    def _configure_background_runtime(self) -> None:
        settings_path = self.settings.fileName() if hasattr(self, "settings") else None
        db_path = str(getattr(self, "current_db_path", "") or "").strip() or None
        if hasattr(self, "background_service_factory"):
            self.background_service_factory.configure(
                db_path=db_path,
                settings_path=settings_path,
            )
        self._background_write_lock = (
            DatabaseWriteCoordinator.for_path(db_path) if db_path else None
        )

    def _on_background_task_state_changed(self) -> None:
        if not hasattr(self, "findChildren"):
            return
        status_bars = self.findChildren(QStatusBar, options=Qt.FindDirectChildrenOnly)
        status_bar = status_bars[0] if status_bars else None
        if status_bar is None:
            return
        if self.background_tasks.has_running_tasks():
            titles = self.background_tasks.active_task_titles()
            preview = ", ".join(titles[:3])
            if len(titles) > 3:
                preview += ", ..."
            status_bar.showMessage(f"Background tasks running: {preview}")
        else:
            status_bar.clearMessage()

    def _prepare_for_background_db_task(self) -> None:
        if getattr(self, "conn", None) is None:
            return
        try:
            self.conn.commit()
        except Exception:
            pass
        try:
            safe_wal_checkpoint(self.conn, mode="PASSIVE", logger=self.logger)
        except Exception:
            pass

    def _show_background_task_error(
        self,
        title: str,
        failure: TaskFailure,
        *,
        user_message: str,
    ) -> None:
        self.logger.error("%s: %s", title, failure.message)
        if failure.traceback_text:
            self.logger.error("%s traceback:\n%s", title, failure.traceback_text)
        QMessageBox.critical(self, title, f"{user_message}\n{failure.message}")

    @staticmethod
    def _scaled_progress_callback(progress_callback, *, start: int, end: int):
        span = max(0, int(end) - int(start))

        def _report(value=None, maximum=None, message=None):
            if progress_callback is None:
                return
            numeric_value = None
            numeric_maximum = None
            try:
                if value is not None and maximum not in (None, 0):
                    ratio = min(max(float(value) / float(maximum), 0.0), 1.0)
                    numeric_value = int(round(int(start) + (ratio * span)))
                    numeric_maximum = 100
                elif value is not None:
                    numeric_value = min(max(int(value), int(start)), int(end))
                    numeric_maximum = 100
            except Exception:
                numeric_value = None
                numeric_maximum = None
            progress_callback(
                value=numeric_value,
                maximum=numeric_maximum,
                message=str(message or ""),
            )

        return _report

    @staticmethod
    def _advance_task_ui_progress(
        ui_progress,
        *,
        value: int,
        message: str,
        maximum: int = 100,
    ) -> None:
        ui_progress.report_progress(value=int(value), maximum=int(maximum), message=message)
        app = QApplication.instance()
        if app is not None:
            app.processEvents()

    def _scaled_ui_progress_callback(self, ui_progress, *, start: int, end: int):
        span = max(0, int(end) - int(start))

        def _report(value=None, maximum=None, message=None):
            numeric_value = int(start)
            try:
                if value is not None and maximum not in (None, 0):
                    ratio = min(max(float(value) / float(maximum), 0.0), 1.0)
                    numeric_value = int(round(int(start) + (ratio * span)))
                elif value is not None:
                    numeric_value = min(max(int(value), int(start)), int(end))
            except Exception:
                numeric_value = int(start)
            self._advance_task_ui_progress(
                ui_progress,
                value=numeric_value,
                maximum=100,
                message=str(message or ""),
            )

        return _report

    def _submit_background_task(
        self,
        *,
        title: str,
        description: str,
        task_fn,
        kind: str = "read",
        unique_key: str | None = None,
        requires_profile: bool = True,
        show_dialog: bool = True,
        cancellable: bool = False,
        owner: QWidget | None = None,
        worker_completion_progress: tuple[int, str] | None = None,
        on_success_before_cleanup=None,
        on_success=None,
        on_success_after_cleanup=None,
        on_error=None,
        on_cancelled=None,
        on_finished=None,
        on_progress=None,
        on_status=None,
    ):
        if requires_profile and not str(getattr(self, "current_db_path", "") or "").strip():
            QMessageBox.warning(self, title, "Open a profile first.")
            return None
        if kind in {"read", "write", "exclusive"}:
            self._prepare_for_background_db_task()

        write_lock = self._background_write_lock if kind in {"write", "exclusive"} else None

        def _wrapped_task(ctx):
            ctx.set_status(description)
            if write_lock is not None:
                with write_lock.acquire():
                    ctx.raise_if_cancelled()
                    result = task_fn(ctx)
            else:
                ctx.raise_if_cancelled()
                result = task_fn(ctx)
            if worker_completion_progress is not None:
                progress_value, progress_message = worker_completion_progress
                ctx.report_progress(
                    value=int(progress_value),
                    maximum=100,
                    message=str(progress_message or ""),
                )
            return result

        return self.background_tasks.submit(
            title=title,
            description=description,
            task_fn=_wrapped_task,
            kind=kind,
            unique_key=unique_key,
            owner=owner or self,
            show_dialog=show_dialog,
            cancellable=cancellable,
            on_success_before_cleanup=on_success_before_cleanup,
            on_success=on_success,
            on_success_after_cleanup=on_success_after_cleanup,
            on_error=on_error,
            on_cancelled=on_cancelled,
            on_finished=on_finished,
            on_progress=on_progress,
            on_status=on_status,
        )

    def _submit_background_bundle_task(
        self,
        *,
        title: str,
        description: str,
        task_fn,
        kind: str = "read",
        unique_key: str | None = None,
        requires_profile: bool = True,
        show_dialog: bool = True,
        cancellable: bool = False,
        owner: QWidget | None = None,
        worker_completion_progress: tuple[int, str] | None = None,
        on_success_before_cleanup=None,
        on_success=None,
        on_success_after_cleanup=None,
        on_error=None,
        on_cancelled=None,
        on_finished=None,
        on_progress=None,
        on_status=None,
    ):
        def _bundle_task(ctx):
            with self.background_service_factory.open_bundle() as bundle:
                result = task_fn(bundle, ctx)
            if worker_completion_progress is not None:
                progress_value, progress_message = worker_completion_progress
                ctx.report_progress(
                    value=int(progress_value),
                    maximum=100,
                    message=str(progress_message or ""),
                )
            return result

        return self._submit_background_task(
            title=title,
            description=description,
            task_fn=_bundle_task,
            kind=kind,
            unique_key=unique_key,
            requires_profile=requires_profile,
            show_dialog=show_dialog,
            cancellable=cancellable,
            owner=owner,
            on_success_before_cleanup=on_success_before_cleanup,
            on_success=on_success,
            on_success_after_cleanup=on_success_after_cleanup,
            on_error=on_error,
            on_cancelled=on_cancelled,
            on_finished=on_finished,
            on_progress=on_progress,
            on_status=on_status,
        )

    # -------------------------------------------------------------------------
    # DB: open/init helpers + MIGRATIONS
    # -------------------------------------------------------------------------
    @staticmethod
    def _background_schema_audit_callback(conn):
        def _audit(action: str, entity: str, ref_id, details) -> None:
            try:
                conn.execute(
                    "INSERT INTO AuditLog (user, action, entity, ref_id, details) VALUES (?, ?, ?, ?, ?)",
                    (
                        None,
                        action,
                        entity,
                        str(ref_id) if ref_id is not None else None,
                        details,
                    ),
                )
            except Exception:
                pass

        return _audit

    def _prepare_database_session(self, path: str, *, progress_callback=None) -> str:
        target_path = str(Path(path))
        if callable(progress_callback):
            progress_callback(1, 4, "Opening profile database session...")
        session = self.database_session.open(target_path)
        prepared_path = target_path
        try:
            schema_service = DatabaseSchemaService(
                session.conn,
                logger=self.logger,
                audit_callback=self._background_schema_audit_callback(session.conn),
                audit_commit=session.conn.commit,
                data_root=self.data_root,
            )
            if callable(progress_callback):
                progress_callback(2, 4, "Initializing required database tables...")
            schema_service.init_db()
            if callable(progress_callback):
                progress_callback(3, 4, "Applying schema migrations and checks...")
            schema_service.migrate_schema()
        finally:
            self.database_session.close(session.conn)
        if callable(progress_callback):
            progress_callback(4, 4, "Profile database prepared.")
        return prepared_path

    def _prepare_database_for_open_blocking(
        self,
        path: str,
        *,
        title: str,
        description: str,
    ) -> bool:
        target_path = str(Path(path))
        self._report_startup_phase(StartupPhase.PREPARING_DATABASE)
        try:
            prepared_path = self._prepare_database_session(
                target_path,
                progress_callback=self._startup_progress_callback(StartupPhase.PREPARING_DATABASE),
            )
        except Exception as exc:
            self.logger.warning(
                "Database preparation failed for %s: %s",
                target_path,
                exc,
            )
            self.logger.debug(
                "Database preparation traceback for %s",
                target_path,
                exc_info=True,
            )
            return False
        return str(prepared_path or "").strip() == target_path

    def open_database(
        self,
        path: str,
        *,
        schema_prepared: bool = False,
        progress_callback=None,
    ):
        """Open (or create) the SQLite DB at path; initialize schema if needed."""
        total_steps = 6 if schema_prepared else 8
        completed_steps = 0

        def _advance(message: str) -> None:
            nonlocal completed_steps
            completed_steps += 1
            if callable(progress_callback):
                progress_callback(completed_steps, total_steps, message)

        if self.conn is not None or self.cursor is not None:
            self._close_database_connection()
        session = self.database_session.open(path)
        self.conn = session.conn
        self.cursor = session.cursor
        self.current_db_path = path
        _advance("Opened profile database connection.")
        self._configure_background_runtime()
        _advance("Configured background runtime services.")
        self._report_startup_phase(StartupPhase.LOADING_SERVICES)
        self._init_services()
        _advance("Loaded profile service layer.")

        self._migrate_artist_code_from_qsettings_if_needed()
        _advance("Restored migrated profile settings.")

        current_code = self.load_artist_code()

        self._log_event(
            "profile.open",
            "Opened profile database",
            path=path,
            artist_code=current_code,
        )

        self.database_session.remember_last_path(self.settings, path)
        self.logger.info("Settings synced to disk")

        # Create base tables/indices if missing
        if not schema_prepared:
            self._report_startup_phase(StartupPhase.PREPARING_DATABASE)
            self.init_db()
            _advance("Ensured required database tables exist.")

            # Run schema migrations and then refresh caches that depend on schema
            try:
                self.migrate_schema()
                if self.code_registry_service is not None:
                    self.code_registry_service.ensure_default_categories()
            except Exception as e:
                self.logger.exception(f"Schema migration failed: {e}")
                self._run_startup_message_box(
                    title="Migration Error",
                    icon=QMessageBox.Critical,
                    text=f"Database migration failed:\n{e}",
                )
                # keep going; DB might still be usable
            if self.history_manager is not None:
                self.history_manager._ensure_history_invariants()
            _advance("Completed schema migrations and history checks.")

        self._migrate_legacy_owner_party_if_needed()
        self.blob_icon_settings = self._load_blob_icon_settings()
        self.active_custom_fields = self.load_active_custom_fields()
        self._refresh_catalog_workspace_docks()
        _advance("Loaded profile metadata and refreshed workspace shells.")

        # now it's safe to write AuditLog
        self._audit("PROFILE", "Database", ref_id=path, details="open_database()")
        self._audit_commit()
        self._refresh_history_actions()
        self._last_auto_snapshot_marker = self._current_auto_snapshot_marker()
        self._refresh_auto_snapshot_schedule()
        _advance("Profile database ready for catalog loading.")

    def init_db(self):
        self.schema_service.init_db()

    def _get_db_version(self) -> int:
        return self.schema_service.get_db_version()

    def migrate_schema(self):
        self.schema_service.migrate_schema()

    # --- Audit helpers ---
    def _audit(
        self,
        action: str,
        entity: str,
        ref_id: str | int | None = None,
        details: str | None = None,
        user: str | None = None,
    ):
        """Append an entry to AuditLog and write to file logger."""
        try:
            self.cursor.execute(
                "INSERT INTO AuditLog (user, action, entity, ref_id, details) VALUES (?, ?, ?, ?, ?)",
                (user, action, entity, str(ref_id) if ref_id is not None else None, details),
            )
            self._log_trace(
                "audit",
                message=f"{action} {entity}",
                action=action,
                entity=entity,
                ref_id=ref_id,
                details=details,
            )
        except Exception as e:
            self.logger.exception(f"Failed to write AuditLog: {e}")

    def _audit_commit(self):
        try:
            self.conn.commit()
        except Exception as e:
            self.logger.exception(f"Audit commit error: {e}")

    def _refresh_history_actions(self):
        if not hasattr(self, "undo_action"):
            return

        undo_source, undo_entry = self._get_best_history_candidate("undo")
        redo_source, redo_entry = self._get_best_history_candidate("redo")
        undo_label = undo_entry.label if undo_entry is not None else None
        redo_label = redo_entry.label if redo_entry is not None else None

        self.undo_action.setText(f"Undo {undo_label}" if undo_label else "Undo")
        self.undo_action.setEnabled(bool(undo_label))

        self.redo_action.setText(f"Redo {redo_label}" if redo_label else "Redo")
        self.redo_action.setEnabled(bool(redo_label))

        if self.history_dialog is not None and self.history_dialog.isVisible():
            self.history_dialog.refresh_data()
        self._schedule_history_storage_budget_enforcement(trigger_label="history update")

    def _schedule_history_storage_budget_enforcement(self, *, trigger_label: str) -> None:
        self._history_budget_enforcement_trigger_label = str(trigger_label or "history update")
        if self._history_budget_enforcement_scheduled or self._history_budget_enforcement_running:
            return
        self._history_budget_enforcement_scheduled = True

        def _run() -> None:
            self._history_budget_enforcement_scheduled = False
            if self._history_budget_enforcement_running:
                return
            self._history_budget_enforcement_running = True
            try:
                self._enforce_history_storage_budget(
                    trigger_label=self._history_budget_enforcement_trigger_label,
                    interactive=False,
                )
            finally:
                self._history_budget_enforcement_running = False

        QTimer.singleShot(0, _run)

    @contextmanager
    def _suspend_table_layout_history(self):
        header = self.table.horizontalHeader() if hasattr(self, "table") else None
        previous_suspend_state = self._suspend_layout_history
        self._suspend_layout_history = True
        if header is not None:
            self._unbind_header_state_signals()
        try:
            yield
        finally:

            def _resume_layout_history():
                self._suspend_layout_history = previous_suspend_state
                try:
                    self._bind_header_state_signals()
                except Exception as exc:
                    self.logger.warning("Failed to rebind header history signals: %s", exc)

            QTimer.singleShot(0, _resume_layout_history)

    def _refresh_after_history_change(self):
        with self._suspend_table_layout_history():
            self.identity = self._load_identity()
            self.theme_settings = self._load_theme_settings()
            self.blob_icon_settings = self._load_blob_icon_settings()
            self._apply_identity()
            self._apply_theme()
            self.active_custom_fields = self.load_active_custom_fields()
            self._rebuild_table_headers()
            try:
                self._load_header_state()
            except Exception:
                pass
            self._apply_saved_hint_positions()
            try:
                self._apply_saved_view_preferences()
            except Exception:
                pass
            self.populate_all_comboboxes()
            self._update_add_data_generated_fields()
            self.refresh_table_preserve_view()
            self._refresh_catalog_workspace_docks()
            self._refresh_auto_snapshot_schedule()
            self._last_auto_snapshot_marker = self._current_auto_snapshot_marker()
            self._refresh_history_actions()

    def _apply_saved_hint_positions(self):
        for attr_name, settings_key in (
            ("col_hint_label", "display/col_hint_pos"),
            ("row_hint_label", "display/row_hint_pos"),
        ):
            label = getattr(self, attr_name, None)
            if label is None:
                continue
            pos = self.settings.value(settings_key, type=QPoint)
            if pos:
                label.move(pos)

    def _on_header_layout_changed(self, *_args):
        # Compatibility shim for older callers that still expect a single
        # layout-change hook after the split between reorder and resize events.
        if getattr(self, "_suspend_layout_history", False):
            return
        self._save_header_state()

    def _on_header_sections_reordered(self, *_args):
        if getattr(self, "_suspend_layout_history", False):
            return
        prefix = self._table_settings_prefix()
        self._save_header_state(
            action_label="Reorder Columns",
            history_entity_id=f"{prefix}/column_order",
        )

    def _should_record_header_resize_history(self) -> bool:
        if getattr(self, "_suspend_layout_history", False):
            return False
        col_width_action = getattr(self, "col_width_action", None)
        if col_width_action is not None and not col_width_action.isChecked():
            return False
        try:
            return QApplication.mouseButtons() != Qt.NoButton
        except Exception:
            return False

    def _on_header_sections_resized(self, *_args):
        if not self._should_record_header_resize_history():
            return
        prefix = self._table_settings_prefix()
        self._save_header_state(
            action_label="Adjust Column Widths",
            history_entity_id=f"{prefix}/column_widths",
        )

    def _unbind_header_state_signals(self):
        if not getattr(self, "_header_layout_signals_bound", False) or not hasattr(self, "table"):
            return
        header = self.table.horizontalHeader()
        moved_wrapper = getattr(self, "_header_section_moved_wrapper", None)
        resized_wrapper = getattr(self, "_header_section_resized_wrapper", None)
        try:
            header.sectionMoved.disconnect(moved_wrapper or self._on_header_sections_reordered)
        except (RuntimeError, TypeError):
            pass
        try:
            header.sectionResized.disconnect(resized_wrapper or self._on_header_sections_resized)
        except (RuntimeError, TypeError):
            pass
        self._header_section_moved_wrapper = None
        self._header_section_resized_wrapper = None
        self._header_layout_signals_bound = False

    def _bind_header_state_signals(self):
        if not hasattr(self, "table"):
            return
        header = self.table.horizontalHeader()
        self._unbind_header_state_signals()
        self._header_section_moved_wrapper = self._connect_args_signal(
            header.sectionMoved,
            header,
            self._on_header_sections_reordered,
        )
        self._header_section_resized_wrapper = self._connect_args_signal(
            header.sectionResized,
            header,
            self._on_header_sections_resized,
        )
        self._header_layout_signals_bound = True

    @staticmethod
    def _set_action_checked_silently(action: QAction, enabled: bool):
        action.blockSignals(True)
        try:
            action.setChecked(bool(enabled))
        finally:
            action.blockSignals(False)

    def _apply_columns_movable_state(self, enabled: bool):
        self.table.horizontalHeader().setSectionsMovable(bool(enabled))

    def _apply_col_width_mode(self, enabled: bool):
        hh = self.table.horizontalHeader()
        if enabled:
            for i in range(self._catalog_view_column_count()):
                hh.setSectionResizeMode(i, QHeaderView.Interactive)
            hh.setStretchLastSection(False)
            if self._col_hint_signal_bound:
                hh.sectionResized.disconnect(self._update_col_hint)
                self._col_hint_signal_bound = False
            hh.sectionResized.connect(self._update_col_hint)
            self._col_hint_signal_bound = True
            self._ensure_col_hint_label()
            self.col_hint_label.show()
            self._apply_table_view_settings()
        else:
            for i in range(self._catalog_view_column_count()):
                hh.setSectionResizeMode(i, QHeaderView.ResizeToContents)
            hh.setStretchLastSection(True)
            if not self.col_width_action.isChecked():
                self.table.resizeColumnsToContents()
            if self._col_hint_signal_bound:
                hh.sectionResized.disconnect(self._update_col_hint)
                self._col_hint_signal_bound = False
            if self.col_hint_label:
                self.col_hint_label.hide()
            self._apply_table_view_settings()
        self._reset_hint_label()

    def _apply_row_height_mode(self, enabled: bool):
        vh = self.table.verticalHeader()
        if enabled:
            vh.setSectionResizeMode(QHeaderView.Interactive)
            if self._row_hint_signal_bound:
                vh.sectionResized.disconnect(self._update_row_hint)
                self._row_hint_signal_bound = False
            vh.sectionResized.connect(self._update_row_hint)
            self._row_hint_signal_bound = True
            self._ensure_row_hint_label()
            self.row_hint_label.show()
        else:
            vh.setSectionResizeMode(QHeaderView.Fixed)
            for i in range(self._catalog_view_row_count()):
                self.table.setRowHeight(i, 24)
            if self._row_hint_signal_bound:
                vh.sectionResized.disconnect(self._update_row_hint)
                self._row_hint_signal_bound = False
            if self.row_hint_label:
                self.row_hint_label.hide()
        self._apply_table_view_settings()
        self._reset_hint_label()

    @staticmethod
    def _dock_state_setting_key() -> str:
        return "display/main_window_dock_state"

    @staticmethod
    def _window_geometry_setting_key() -> str:
        return "display/main_window_geometry"

    @staticmethod
    def _window_state_setting_key() -> str:
        return "display/main_window_window_state"

    @staticmethod
    def _window_normal_geometry_setting_key() -> str:
        return "display/main_window_normal_geometry"

    @staticmethod
    def _saved_main_window_layouts_setting_key() -> str:
        return "display/saved_main_window_layouts_json"

    @staticmethod
    def _workspace_panels_setting_key() -> str:
        return "display/main_window_workspace_panels_json"

    @staticmethod
    def _serialize_qbytearray_setting(value: QByteArray | None) -> str:
        if not isinstance(value, QByteArray) or value.isEmpty():
            return ""
        try:
            return bytes(value.toBase64()).decode("ascii")
        except Exception:
            return ""

    @staticmethod
    def _deserialize_qbytearray_setting(value) -> QByteArray:
        clean = str(value or "").strip()
        if not clean:
            return QByteArray()
        try:
            return QByteArray.fromBase64(clean.encode("ascii"))
        except Exception:
            return QByteArray()

    @staticmethod
    def _serialize_rect_setting(value: QRect | None) -> dict[str, int] | None:
        if not isinstance(value, QRect) or not value.isValid():
            return None
        return {
            "x": int(value.x()),
            "y": int(value.y()),
            "width": int(value.width()),
            "height": int(value.height()),
        }

    @staticmethod
    def _deserialize_rect_setting(value) -> QRect | None:
        if not isinstance(value, dict):
            return None
        try:
            rect = QRect(
                int(value.get("x", 0)),
                int(value.get("y", 0)),
                int(value.get("width", 0)),
                int(value.get("height", 0)),
            )
        except Exception:
            return None
        return rect if rect.isValid() else None

    def _schedule_main_dock_state_save(self) -> None:
        if (
            getattr(self, "_suspend_dock_state_sync", False)
            or getattr(self, "_is_restoring_workspace_layout", False)
            or getattr(self, "_is_closing", False)
            or not getattr(self, "_workspace_layout_restore_complete", False)
        ):
            return
        timer = getattr(self, "_dock_state_save_timer", None)
        if timer is None:
            timer = QTimer(self)
            timer.setSingleShot(True)
            self._connect_noarg_signal(timer.timeout, timer, self._save_main_dock_state)
            self._dock_state_save_timer = timer
        timer.start(75)

    def _schedule_main_window_geometry_save(self) -> None:
        if (
            getattr(self, "_is_restoring_workspace_layout", False)
            or getattr(self, "_is_closing", False)
            or not getattr(self, "_workspace_layout_restore_complete", False)
        ):
            return
        timer = getattr(self, "_window_geometry_save_timer", None)
        if timer is None:
            timer = QTimer(self)
            timer.setSingleShot(True)
            self._connect_noarg_signal(timer.timeout, timer, self._save_main_window_geometry)
            self._window_geometry_save_timer = timer
        timer.start(75)

    def _stop_queued_main_window_layout_persistence(self) -> None:
        for timer_name in ("_dock_state_save_timer", "_window_geometry_save_timer"):
            timer = getattr(self, timer_name, None)
            if isinstance(timer, QTimer):
                timer.stop()

    def _save_main_dock_state(self, *, sync: bool = True) -> None:
        if getattr(self, "_suspend_dock_state_sync", False):
            return
        try:
            snapshot = self._capture_current_workspace_panel_layout_snapshot()
            workspace_debug_log(
                "layout",
                "app.save_main_dock_state",
                sync=bool(sync),
                workspace_panels=summarize_panel_layout_snapshot(snapshot),
            )
            self.settings.setValue(self._dock_state_setting_key(), self.saveState(1))
            self._write_workspace_panel_layouts(
                snapshot,
                sync=False,
            )
            if sync:
                self.settings.sync()
        except Exception as e:
            self.logger.warning("Failed to save dock state: %s", e)

    def _apply_main_dock_state_snapshot(self, state: QByteArray | None) -> bool:
        if not isinstance(state, QByteArray) or state.isEmpty():
            return False
        previous_suspend_state = self._suspend_dock_state_sync
        self._suspend_dock_state_sync = True
        restored = False
        try:
            restored = bool(self.restoreState(state, 1))
            if not restored:
                self.logger.warning("Qt rejected the saved dock state; keeping the default layout")
        except Exception as e:
            self.logger.warning("Failed to restore dock state: %s", e)
        finally:
            self._suspend_dock_state_sync = previous_suspend_state
        return restored

    def _restore_main_dock_state(self) -> bool:
        try:
            state = self.settings.value(self._dock_state_setting_key(), None, QByteArray)
        except Exception:
            state = None
        return self._apply_main_dock_state_snapshot(state)

    def _save_main_window_geometry(self, *, sync: bool = True) -> None:
        try:
            self.settings.setValue(self._window_geometry_setting_key(), self.saveGeometry())
            self.settings.setValue(
                self._window_state_setting_key(),
                self._current_main_window_state_marker(),
            )
            normal_geometry = self.normalGeometry()
            if isinstance(normal_geometry, QRect) and normal_geometry.isValid():
                self.settings.setValue(
                    self._window_normal_geometry_setting_key(),
                    normal_geometry,
                )
            if sync:
                self.settings.sync()
        except Exception as e:
            self.logger.warning("Failed to save main window geometry: %s", e)

    def _apply_main_window_geometry_snapshot(
        self,
        *,
        geometry: QByteArray | None,
        normal_geometry: QRect | None,
        window_state_marker: str,
    ) -> bool:
        has_geometry = isinstance(geometry, QByteArray) and not geometry.isEmpty()
        marker = str(window_state_marker or "").strip().lower()
        if not has_geometry and marker not in {"normal", "maximized", "fullscreen"}:
            return False

        restored = False
        if has_geometry:
            try:
                restored = bool(self.restoreGeometry(geometry))
            except Exception as e:
                self.logger.warning("Failed to restore main window geometry: %s", e)

        if marker == "fullscreen":
            self.showFullScreen()
            return True
        if marker == "maximized":
            self.showMaximized()
            return True
        if marker == "normal":
            self.showNormal()
            if isinstance(normal_geometry, QRect) and normal_geometry.isValid():
                self.setGeometry(normal_geometry)
            return True
        return restored

    def _restore_main_window_geometry(self) -> bool:
        try:
            geometry = self.settings.value(self._window_geometry_setting_key(), None, QByteArray)
        except Exception:
            geometry = None
        try:
            normal_geometry = self.settings.value(
                self._window_normal_geometry_setting_key(),
                None,
                QRect,
            )
        except Exception:
            normal_geometry = None
        try:
            window_state_marker = self.settings.value(self._window_state_setting_key(), "", str)
        except Exception:
            window_state_marker = ""
        return self._apply_main_window_geometry_snapshot(
            geometry=geometry,
            normal_geometry=normal_geometry,
            window_state_marker=window_state_marker,
        )

    def _current_main_window_state_marker(self) -> str:
        window_state = self.windowState()
        if window_state & Qt.WindowFullScreen:
            return "fullscreen"
        if window_state & Qt.WindowMaximized:
            return "maximized"
        return "normal"

    def _load_saved_main_window_layouts(self) -> dict[str, dict[str, object]]:
        raw_value = self.settings.value(self._saved_main_window_layouts_setting_key(), "{}")
        parsed = raw_value
        if isinstance(raw_value, str):
            try:
                parsed = json.loads(raw_value)
            except Exception:
                return {}
        if not isinstance(parsed, dict):
            return {}
        normalized: dict[str, dict[str, object]] = {}
        for name, snapshot in parsed.items():
            clean_name = str(name or "").strip()
            if not clean_name or not isinstance(snapshot, dict):
                continue
            normalized[clean_name] = dict(snapshot)
        return dict(sorted(normalized.items(), key=lambda item: item[0].casefold()))

    def _write_saved_main_window_layouts(
        self,
        layouts: dict[str, dict[str, object]],
        *,
        sync: bool = True,
    ) -> None:
        payload = dict(sorted(layouts.items(), key=lambda item: item[0].casefold()))
        self.settings.setValue(
            self._saved_main_window_layouts_setting_key(),
            json.dumps(payload, ensure_ascii=True, sort_keys=True),
        )
        if sync:
            self.settings.sync()

    def _load_workspace_panel_layouts(self) -> dict[str, dict[str, object]]:
        raw_value = self.settings.value(self._workspace_panels_setting_key(), "{}")
        parsed = raw_value
        if isinstance(raw_value, str):
            try:
                parsed = json.loads(raw_value)
            except Exception:
                return {}
        if not isinstance(parsed, dict):
            return {}
        normalized: dict[str, dict[str, object]] = {}
        for key, payload in parsed.items():
            clean_key = str(key or "").strip()
            if clean_key and isinstance(payload, dict):
                normalized[clean_key] = dict(payload)
        return normalized

    def _write_workspace_panel_layouts(
        self,
        layouts: dict[str, dict[str, object]],
        *,
        sync: bool = True,
    ) -> None:
        payload = dict(sorted(layouts.items(), key=lambda item: item[0].casefold()))
        self.settings.setValue(
            self._workspace_panels_setting_key(),
            json.dumps(payload, ensure_ascii=True, sort_keys=True),
        )
        if sync:
            self.settings.sync()

    def _capture_current_workspace_panel_layout_snapshot(self) -> dict[str, dict[str, object]]:
        registry = getattr(self, "_catalog_workspace_docks", {})
        snapshot: dict[str, dict[str, object]] = {}
        for key, dock in list(registry.items()):
            if not isinstance(dock, QDockWidget):
                continue
            capture = getattr(dock, "capture_panel_layout_state", None)
            if not callable(capture):
                continue
            try:
                state = capture()
            except Exception:
                state = None
            if isinstance(state, dict):
                snapshot[str(key)] = dict(state)
        workspace_debug_log(
            "layout",
            "app.capture_workspace_panel_layout_snapshot",
            snapshot=summarize_panel_layout_snapshot(snapshot),
        )
        return snapshot

    def _contract_template_workspace_debug_summary(self) -> dict[str, object]:
        registry = getattr(self, "_catalog_workspace_docks", {})
        dock = getattr(self, "contract_template_workspace_dock", None)
        if not isinstance(dock, QDockWidget):
            candidate = registry.get("contract_template_workspace")
            if isinstance(candidate, QDockWidget):
                dock = candidate
        return summarize_catalog_workspace_dock(dock)

    def _log_contract_template_restore_checkpoint(self, event: str, **payload) -> None:
        workspace_debug_log(
            "layout",
            event,
            contract_template_workspace=self._contract_template_workspace_debug_summary(),
            payload=payload,
        )

    def _schedule_contract_template_restore_debug_snapshots(
        self,
        *,
        event_prefix: str,
        layout_name: str,
    ) -> None:
        if not workspace_debug_enabled("layout"):
            return
        for delay_ms in (0, 25, 100, 250, 1000):
            QTimer.singleShot(
                delay_ms,
                lambda _delay_ms=delay_ms: self._log_contract_template_restore_checkpoint(
                    f"{event_prefix}.checkpoint",
                    name=str(layout_name or ""),
                    delay_ms=int(_delay_ms),
                    restore_complete=bool(
                        getattr(self, "_workspace_layout_restore_complete", False)
                    ),
                    restoring=bool(getattr(self, "_is_restoring_workspace_layout", False)),
                ),
            )

    def _apply_workspace_panel_layout_snapshot(
        self,
        snapshot: dict[str, object] | None,
    ) -> None:
        payload = dict(snapshot or {})
        workspace_debug_log(
            "layout",
            "app.apply_workspace_panel_layout_snapshot.begin",
            snapshot=summarize_panel_layout_snapshot(payload),
        )
        registry = getattr(self, "_catalog_workspace_docks", {})
        for key, dock in list(registry.items()):
            if not isinstance(dock, QDockWidget):
                continue
            restore = getattr(dock, "restore_panel_layout_state", None)
            if not callable(restore):
                continue
            panel_payload = payload.get(str(key))
            if str(key) == "contract_template_workspace":
                self._log_contract_template_restore_checkpoint(
                    "app.apply_workspace_panel_layout_snapshot.contract_templates.before_restore",
                    requested_panel_state=summarize_panel_layout_state(
                        panel_payload if isinstance(panel_payload, dict) else {}
                    ),
                )
            restore(panel_payload if isinstance(panel_payload, dict) else None)
            if str(key) == "contract_template_workspace":
                self._log_contract_template_restore_checkpoint(
                    "app.apply_workspace_panel_layout_snapshot.contract_templates.after_restore_request",
                    requested_panel_state=summarize_panel_layout_state(
                        panel_payload if isinstance(panel_payload, dict) else {}
                    ),
                )
        workspace_debug_log(
            "layout",
            "app.apply_workspace_panel_layout_snapshot.end",
            snapshot=summarize_panel_layout_snapshot(payload),
        )

    def _saved_main_window_layout_names(self) -> list[str]:
        return list(self._load_saved_main_window_layouts().keys())

    def _find_saved_main_window_layout_name(self, name: str) -> str | None:
        clean_name = str(name or "").strip()
        if not clean_name:
            return None
        for existing_name in self._saved_main_window_layout_names():
            if existing_name.casefold() == clean_name.casefold():
                return existing_name
        return None

    def _default_saved_main_window_layout_name(self) -> str:
        existing_names = {name.casefold() for name in self._saved_main_window_layout_names()}
        index = 1
        while True:
            candidate = f"Layout {index}"
            if candidate.casefold() not in existing_names:
                return candidate
            index += 1

    def _capture_current_main_window_layout_snapshot(self) -> dict[str, object]:
        profiles_toolbar = getattr(self, "toolbar", None)
        action_ribbon_toolbar = getattr(self, "action_ribbon_toolbar", None)
        add_data_dock = getattr(self, "add_data_dock", None)
        catalog_table_dock = getattr(self, "catalog_table_dock", None)
        action_ribbon_snapshot = self._capture_current_action_ribbon_layout_snapshot()
        snapshot = {
            "schema_version": 4,
            "geometry_b64": self._serialize_qbytearray_setting(self.saveGeometry()),
            "window_state": self._current_main_window_state_marker(),
            "normal_geometry": self._serialize_rect_setting(self.normalGeometry()),
            "dock_state_b64": self._serialize_qbytearray_setting(self.saveState(1)),
            **self._catalog_zoom_layout_state(),
            "add_data_panel": bool(
                isinstance(add_data_dock, QDockWidget) and add_data_dock.isVisible()
            ),
            "catalog_table_panel": bool(
                isinstance(catalog_table_dock, QDockWidget) and catalog_table_dock.isVisible()
            ),
            "profiles_toolbar_visible": bool(
                isinstance(profiles_toolbar, QToolBar) and profiles_toolbar.isVisible()
            ),
            "action_ribbon_visible": bool(
                isinstance(action_ribbon_toolbar, QToolBar) and action_ribbon_toolbar.isVisible()
            ),
            "action_ribbon": action_ribbon_snapshot,
            "workspace_panels": self._capture_current_workspace_panel_layout_snapshot(),
        }
        workspace_debug_log(
            "layout",
            "app.capture_named_main_window_layout_snapshot",
            name=str(getattr(self, "_active_saved_main_window_layout_name", "") or ""),
            workspace_panels=summarize_panel_layout_snapshot(snapshot.get("workspace_panels")),
            contract_template_workspace=self._contract_template_workspace_debug_summary(),
        )
        return snapshot

    def _save_named_main_window_layout(self, name: str) -> str | None:
        clean_name = str(name or "").strip()
        if not clean_name:
            return None
        layouts = self._load_saved_main_window_layouts()
        existing_name = self._find_saved_main_window_layout_name(clean_name)
        if existing_name is not None and existing_name != clean_name:
            layouts.pop(existing_name, None)
        layouts[clean_name] = self._capture_current_main_window_layout_snapshot()
        self._write_saved_main_window_layouts(layouts)
        workspace_debug_log(
            "layout",
            "app.save_named_main_window_layout",
            name=clean_name,
            workspace_panels=summarize_panel_layout_snapshot(
                dict(layouts.get(clean_name, {})).get("workspace_panels")
                if isinstance(dict(layouts.get(clean_name, {})), dict)
                else {}
            ),
            contract_template_workspace=self._contract_template_workspace_debug_summary(),
        )
        self._active_saved_main_window_layout_name = clean_name
        self._refresh_saved_layout_controls()
        return clean_name

    def _build_named_main_window_layout_switch_request(
        self,
        name: str,
    ) -> dict[str, object] | None:
        layouts = self._load_saved_main_window_layouts()
        clean_name = str(name or "").strip()
        if not clean_name:
            return None
        known_action_ids = list(getattr(self, "_action_ribbon_specs_by_id", {}).keys())
        current_action_ids = self._normalize_action_ribbon_ids(
            getattr(self, "_action_ribbon_action_ids", [])
        )
        if not current_action_ids:
            current_action_ids = list(getattr(self, "_action_ribbon_default_ids", []))
        return {
            "requested_name": clean_name,
            "layouts": layouts,
            "known_action_ids": known_action_ids,
            "default_action_ids": list(getattr(self, "_action_ribbon_default_ids", [])),
            "current_action_ids": current_action_ids,
            "current_visible": self._current_action_ribbon_visibility(),
        }

    @staticmethod
    def _prepare_named_main_window_layout_switch_request(
        request: dict[str, object],
    ) -> dict[str, object] | None:
        layouts = request.get("layouts")
        if not isinstance(layouts, dict):
            return None
        requested_name = str(request.get("requested_name") or "").strip()
        if not requested_name:
            return None
        resolved_name = None
        for existing_name in layouts.keys():
            clean_existing_name = str(existing_name or "").strip()
            if clean_existing_name.casefold() == requested_name.casefold():
                resolved_name = clean_existing_name
                break
        if resolved_name is None:
            return None
        snapshot = layouts.get(resolved_name)
        if not isinstance(snapshot, dict):
            return None
        known_action_ids = request.get("known_action_ids")
        current_action_ids = request.get("current_action_ids")
        default_action_ids = request.get("default_action_ids")
        current_visible = bool(request.get("current_visible", True))
        ribbon_action_ids, ribbon_visible = (
            App._resolve_saved_layout_action_ribbon_snapshot_payload(
                snapshot,
                current_action_ids=current_action_ids,
                current_visible=current_visible,
                default_action_ids=default_action_ids,
                known_action_ids=known_action_ids,
            )
        )
        return {
            "name": resolved_name,
            "geometry": App._deserialize_qbytearray_setting(snapshot.get("geometry_b64")),
            "normal_geometry": App._deserialize_rect_setting(snapshot.get("normal_geometry")),
            "window_state_marker": str(snapshot.get("window_state") or ""),
            "dock_state": App._deserialize_qbytearray_setting(snapshot.get("dock_state_b64")),
            "workspace_panels": (
                dict(snapshot.get("workspace_panels"))
                if isinstance(snapshot.get("workspace_panels"), dict)
                else {}
            ),
            "add_data_panel": bool(snapshot.get("add_data_panel", False)),
            "catalog_table_panel": bool(snapshot.get("catalog_table_panel", True)),
            "profiles_toolbar_visible": bool(snapshot.get("profiles_toolbar_visible", True)),
            "ribbon_action_ids": ribbon_action_ids,
            "ribbon_visible": bool(ribbon_visible),
            CATALOG_ZOOM_LAYOUT_KEY: snapshot.get(CATALOG_ZOOM_LAYOUT_KEY),
        }

    @contextmanager
    def _suspend_saved_layout_transition_updates(self):
        widgets: list[QWidget] = []
        seen: set[int] = set()
        direct_children_only = Qt.FindChildOption.FindDirectChildrenOnly
        candidates = [
            self.centralWidget(),
            *self.findChildren(QDockWidget, options=direct_children_only),
            *self.findChildren(QToolBar, options=direct_children_only),
        ]
        for candidate in candidates:
            if not isinstance(candidate, QWidget):
                continue
            if isinstance(candidate, CatalogWorkspaceDock):
                continue
            widget_id = id(candidate)
            if widget_id in seen:
                continue
            seen.add(widget_id)
            widgets.append(candidate)

        previous_update_states: list[tuple[QWidget, bool]] = []
        for widget in widgets:
            try:
                previous_update_states.append((widget, widget.updatesEnabled()))
                widget.setUpdatesEnabled(False)
            except Exception:
                continue
        try:
            yield
        finally:
            for widget, previous_state in previous_update_states:
                try:
                    widget.setUpdatesEnabled(previous_state)
                    widget.updateGeometry()
                    widget.update()
                except Exception:
                    continue
            try:
                self.updateGeometry()
                self.update()
            except Exception:
                pass

    def _apply_prepared_named_main_window_layout(
        self,
        prepared: dict[str, object],
        *,
        ui_progress=None,
    ) -> bool:
        resolved_name = str(prepared.get("name") or "").strip()
        if not resolved_name:
            return False

        progress_total = 10

        def _advance(value: int, message: str) -> None:
            if ui_progress is None:
                return
            self._advance_task_ui_progress(
                ui_progress,
                value=value,
                maximum=progress_total,
                message=message,
            )

        ribbon_action_ids = self._normalize_action_ribbon_ids(prepared.get("ribbon_action_ids"))
        if not ribbon_action_ids:
            ribbon_action_ids = list(getattr(self, "_action_ribbon_default_ids", []))

        self._ensure_persistent_workspace_dock_shells()
        self._log_contract_template_restore_checkpoint(
            "app.apply_named_main_window_layout.after_ensure_shells",
            name=resolved_name,
            prepared_workspace_panels=summarize_panel_layout_snapshot(
                prepared.get("workspace_panels")
                if isinstance(prepared.get("workspace_panels"), dict)
                else {}
            ),
        )
        _advance(3, f'Preparing saved layout "{resolved_name}" for restore...')
        previous_suspend_state = self._suspend_dock_state_sync
        previous_restore_state = self._is_restoring_workspace_layout
        self._suspend_dock_state_sync = True
        self._is_restoring_workspace_layout = True
        restored_dock_state = False
        workspace_debug_log(
            "layout",
            "app.apply_named_main_window_layout.begin",
            name=resolved_name,
            workspace_panels=summarize_panel_layout_snapshot(
                prepared.get("workspace_panels")
                if isinstance(prepared.get("workspace_panels"), dict)
                else {}
            ),
            contract_template_workspace=self._contract_template_workspace_debug_summary(),
        )
        try:
            with self._suspend_saved_layout_transition_updates():
                self._apply_main_window_geometry_snapshot(
                    geometry=prepared.get("geometry"),
                    normal_geometry=prepared.get("normal_geometry"),
                    window_state_marker=str(prepared.get("window_state_marker") or ""),
                )
                self._log_contract_template_restore_checkpoint(
                    "app.apply_named_main_window_layout.after_geometry",
                    name=resolved_name,
                )
                _advance(4, f'Applied saved geometry for layout "{resolved_name}".')
                restored_dock_state = self._apply_main_dock_state_snapshot(
                    prepared.get("dock_state")
                )
                self._log_contract_template_restore_checkpoint(
                    "app.apply_named_main_window_layout.after_main_dock_state",
                    name=resolved_name,
                    restored_dock_state=bool(restored_dock_state),
                )
                if not restored_dock_state:
                    self._apply_add_data_panel_state(bool(prepared.get("add_data_panel", False)))
                    self._apply_catalog_table_panel_state(
                        bool(prepared.get("catalog_table_panel", True))
                    )
                _advance(
                    5,
                    (
                        f'Restored saved dock layout for "{resolved_name}".'
                        if restored_dock_state
                        else f'Applied fallback panel visibility for "{resolved_name}".'
                    ),
                )
                self._apply_profiles_toolbar_visibility(
                    bool(prepared.get("profiles_toolbar_visible", True))
                )
                self._apply_action_ribbon_configuration(
                    ribbon_action_ids,
                    bool(prepared.get("ribbon_visible", True)),
                )
                if prepared.get(CATALOG_ZOOM_LAYOUT_KEY) is not None:
                    self._restore_catalog_zoom_layout_state(
                        {CATALOG_ZOOM_LAYOUT_KEY: prepared.get(CATALOG_ZOOM_LAYOUT_KEY)},
                        immediate=True,
                    )
                self._refresh_workspace_dock_default_placement_flags()
                _advance(7, f'Applied toolbar and Action Ribbon state for "{resolved_name}".')

            self._log_contract_template_restore_checkpoint(
                "app.apply_named_main_window_layout.after_transition_updates_resumed",
                name=resolved_name,
            )
            self._apply_workspace_panel_layout_snapshot(
                prepared.get("workspace_panels")
                if isinstance(prepared.get("workspace_panels"), dict)
                else {}
            )
            self._log_contract_template_restore_checkpoint(
                "app.apply_named_main_window_layout.after_workspace_panel_snapshot",
                name=resolved_name,
            )
            _advance(6, f'Applied nested workspace panel state for "{resolved_name}".')
            self._refresh_workspace_dock_default_placement_flags()
            self._materialize_visible_workspace_dock_panels(
                progress_callback=lambda value, maximum, message: (
                    ui_progress.report_progress(value=8, maximum=progress_total, message=message)
                    if ui_progress is not None
                    else None
                )
            )
            self._log_contract_template_restore_checkpoint(
                "app.apply_named_main_window_layout.after_materialize_visible_panels",
                name=resolved_name,
            )
            _advance(8, f'Restored visible workspace panels for "{resolved_name}".')
        finally:
            self._is_restoring_workspace_layout = previous_restore_state
            self._suspend_dock_state_sync = previous_suspend_state

        self._active_saved_main_window_layout_name = resolved_name
        self._store_workspace_panel_visibility_preferences(sync=False)
        self._store_action_ribbon_preferences(
            ribbon_action_ids,
            bool(prepared.get("ribbon_visible", True)),
            sync=False,
        )
        self._refresh_saved_layout_controls()
        _advance(
            9, f'Waiting for visible workspace repaint and stabilization for "{resolved_name}".'
        )
        self._stabilize_visible_layout_after_restore(
            progress_callback=(
                lambda value, maximum, message: (
                    ui_progress.report_progress(
                        value=value,
                        maximum=maximum,
                        message=message,
                    )
                    if ui_progress is not None
                    else None
                )
            ),
            value=9,
            maximum=progress_total,
        )
        self._log_contract_template_restore_checkpoint(
            "app.apply_named_main_window_layout.after_stabilize_visible_layout",
            name=resolved_name,
        )
        self._validate_visible_workspace_dock_panels_after_restore()
        workspace_debug_log(
            "layout",
            "app.apply_named_main_window_layout.end",
            name=resolved_name,
            restored_dock_state=bool(restored_dock_state),
            contract_template_workspace=self._contract_template_workspace_debug_summary(),
        )
        self._schedule_contract_template_restore_debug_snapshots(
            event_prefix="app.apply_named_main_window_layout",
            layout_name=resolved_name,
        )
        self._stop_queued_main_window_layout_persistence()
        self._schedule_main_window_geometry_save()
        self._schedule_main_dock_state_save()
        self._apply_top_chrome_boundary()
        self.settings.sync()
        _advance(10, f'Saved layout "{resolved_name}" is ready.')
        return True

    def _apply_named_main_window_layout(self, name: str) -> bool:
        request = self._build_named_main_window_layout_switch_request(name)
        if request is None:
            return False
        prepared = self._prepare_named_main_window_layout_switch_request(request)
        if prepared is None:
            return False
        return self._apply_prepared_named_main_window_layout(prepared)

    def _start_named_main_window_layout_switch(self, name: str):
        request = self._build_named_main_window_layout_switch_request(name)
        if request is None:
            self._refresh_saved_layout_controls()
            return None

        progress_total = 10
        requested_name = str(request.get("requested_name") or "").strip()
        apply_result: dict[str, bool] = {"applied": False}

        def _task(ctx):
            ctx.set_status(f'Resolving saved layout "{requested_name}"...')
            prepared = self._prepare_named_main_window_layout_switch_request(request)
            if prepared is None:
                raise RuntimeError(f'Saved layout "{requested_name}" is no longer available.')
            ctx.report_progress(
                value=1,
                maximum=progress_total,
                message=f'Resolved saved layout "{prepared["name"]}" payload.',
            )
            ctx.raise_if_cancelled()
            ctx.report_progress(
                value=2,
                maximum=progress_total,
                message=f'Prepared saved layout "{prepared["name"]}" state.',
            )
            return prepared

        def _before_cleanup(prepared, ui_progress) -> None:
            apply_result["applied"] = self._apply_prepared_named_main_window_layout(
                prepared,
                ui_progress=ui_progress,
            )

        def _after_cleanup(prepared) -> None:
            resolved_name = str(prepared.get("name") or requested_name)
            if apply_result["applied"]:
                self.statusBar().showMessage(f'Switched to layout "{resolved_name}".', 3000)
            else:
                self._refresh_saved_layout_controls()

        def _handle_error(failure: TaskFailure) -> None:
            self._refresh_saved_layout_controls()
            self._show_background_task_error(
                "Switch Layout",
                failure,
                user_message="The saved layout could not be applied.",
            )

        return self._submit_background_task(
            title="Switch Layout",
            description=f'Applying saved layout "{requested_name}"...',
            task_fn=_task,
            kind="read",
            unique_key="saved-layout-switch",
            requires_profile=False,
            show_dialog=True,
            on_success_before_cleanup=_before_cleanup,
            on_success_after_cleanup=_after_cleanup,
            on_error=_handle_error,
        )

    def _delete_named_main_window_layout(self, name: str) -> bool:
        layouts = self._load_saved_main_window_layouts()
        resolved_name = self._find_saved_main_window_layout_name(name)
        if resolved_name is None or resolved_name not in layouts:
            return False
        layouts.pop(resolved_name, None)
        self._write_saved_main_window_layouts(layouts)
        if getattr(self, "_active_saved_main_window_layout_name", None) == resolved_name:
            self._active_saved_main_window_layout_name = ""
        self._refresh_saved_layout_controls()
        return True

    def _refresh_saved_layout_controls(self) -> None:
        names = self._saved_main_window_layout_names()
        delete_enabled = bool(names)

        delete_action = getattr(self, "delete_layout_action", None)
        if isinstance(delete_action, QAction):
            delete_action.setEnabled(delete_enabled)

        selector = getattr(self, "saved_layout_selector", None)
        if isinstance(selector, QComboBox):
            previous_state = selector.blockSignals(True)
            try:
                selector.clear()
                if names:
                    selector.addItem("Saved Layouts", "")
                    for layout_name in names:
                        selector.addItem(layout_name, layout_name)
                    active_name = str(
                        getattr(self, "_active_saved_main_window_layout_name", "") or ""
                    ).strip()
                    selector.setEnabled(True)
                    active_index = selector.findData(active_name) if active_name else -1
                    selector.setCurrentIndex(active_index if active_index > 0 else 0)
                else:
                    selector.addItem("No Saved Layouts", "")
                    selector.setCurrentIndex(0)
                    selector.setEnabled(False)
            finally:
                selector.blockSignals(previous_state)

        delete_button = getattr(self, "saved_layout_delete_button", None)
        if isinstance(delete_button, QPushButton):
            delete_button.setEnabled(delete_enabled)

    def _populate_saved_layouts_menu(self) -> None:
        menu = getattr(self, "saved_layouts_menu", None)
        if not isinstance(menu, QMenu):
            return
        menu.clear()
        names = self._saved_main_window_layout_names()
        if not names:
            empty_action = menu.addAction("No Saved Layouts")
            empty_action.setEnabled(False)
            return

        layout_list = QListWidget(menu)
        layout_list.setObjectName("savedLayoutsMenuList")
        layout_list.setSelectionMode(QAbstractItemView.SingleSelection)
        layout_list.setVerticalScrollMode(QAbstractItemView.ScrollPerPixel)
        layout_list.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        layout_list.setSizePolicy(QSizePolicy.Preferred, QSizePolicy.Preferred)
        for layout_name in names:
            QListWidgetItem(layout_name, layout_list)
        active_name = str(getattr(self, "_active_saved_main_window_layout_name", "") or "").strip()
        if active_name:
            matching_items = layout_list.findItems(active_name, Qt.MatchExactly)
            if matching_items:
                layout_list.setCurrentItem(matching_items[0])
        row_height = layout_list.sizeHintForRow(0)
        if row_height <= 0:
            row_height = max(layout_list.fontMetrics().height() + 8, 24)
        visible_rows = min(len(names), 8)
        frame_height = layout_list.frameWidth() * 2
        layout_list.setFixedHeight((row_height * visible_rows) + frame_height + 2)
        widest_name = max(layout_list.fontMetrics().horizontalAdvance(name) for name in names)
        layout_list.setMinimumWidth(min(max(widest_name + 56, 220), 360))

        def _apply_selected_layout(item: QListWidgetItem | None) -> None:
            if item is None:
                return
            menu.close()
            QTimer.singleShot(
                0,
                lambda layout_name=str(
                    item.text() or ""
                ).strip(): self._start_named_main_window_layout_switch(layout_name),
            )

        layout_list.itemClicked.connect(_apply_selected_layout)
        layout_list.itemActivated.connect(_apply_selected_layout)

        widget_action = QWidgetAction(menu)
        widget_action.setDefaultWidget(layout_list)
        menu.addAction(widget_action)

    def add_named_main_window_layout(self) -> None:
        names = self._saved_main_window_layout_names()
        active_name = self._find_saved_main_window_layout_name(
            str(getattr(self, "_active_saved_main_window_layout_name", "") or "")
        )
        suggested_name = active_name or self._default_saved_main_window_layout_name()
        while True:
            name, ok = _get_name_from_editable_choice_dialog(
                self,
                title="Save Layout",
                label="Layout name:",
                choices=names,
                suggested_name=suggested_name,
                placeholder="Enter a new layout name",
            )
            if not ok:
                return
            clean_name = str(name or "").strip()
            if clean_name:
                break
            QMessageBox.warning(self, "Save Layout", "Enter a layout name before saving.")
            suggested_name = str(name or "")

        existing_name = self._find_saved_main_window_layout_name(clean_name)
        if existing_name is not None:
            answer = QMessageBox.question(
                self,
                "Overwrite Layout",
                f'A saved layout named "{existing_name}" already exists.\n\nOverwrite it?',
                QMessageBox.Yes | QMessageBox.No,
                QMessageBox.No,
            )
            if answer != QMessageBox.Yes:
                return

        saved_name = self._save_named_main_window_layout(clean_name)
        if saved_name is not None:
            self.statusBar().showMessage(f'Saved layout "{saved_name}".', 3000)

    def delete_named_main_window_layout_interactive(
        self, preferred_name: str | None = None
    ) -> None:
        names = self._saved_main_window_layout_names()
        if not names:
            QMessageBox.information(self, "Delete Layout", "No saved layouts are available yet.")
            return

        resolved_name = self._find_saved_main_window_layout_name(preferred_name or "")
        default_index = names.index(resolved_name) if resolved_name in names else 0
        selected_name, ok = QInputDialog.getItem(
            self,
            "Delete Layout",
            "Choose the saved layout to delete:",
            names,
            default_index,
            False,
        )
        if not ok or not selected_name:
            return

        answer = QMessageBox.question(
            self,
            "Delete Layout",
            f'Delete the saved layout "{selected_name}"?',
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No,
        )
        if answer != QMessageBox.Yes:
            return

        if self._delete_named_main_window_layout(selected_name):
            self.statusBar().showMessage(f'Deleted layout "{selected_name}".', 3000)

    def _on_saved_layout_selected(self, index: int) -> None:
        selector = getattr(self, "saved_layout_selector", None)
        if not isinstance(selector, QComboBox):
            return
        selected_name = str(selector.itemData(index) or "").strip()
        if not selected_name:
            return
        QTimer.singleShot(
            0,
            lambda layout_name=selected_name: self._start_named_main_window_layout_switch(
                layout_name
            ),
        )

    def _store_workspace_panel_visibility_preferences(self, *, sync: bool = True) -> None:
        try:
            add_data_enabled = bool(
                isinstance(getattr(self, "add_data_dock", None), QDockWidget)
                and self.add_data_dock.isVisible()
            )
            catalog_table_enabled = bool(
                isinstance(getattr(self, "catalog_table_dock", None), QDockWidget)
                and self.catalog_table_dock.isVisible()
            )
            self.settings.setValue("display/add_data_panel", add_data_enabled)
            self.settings.setValue("display/catalog_table_panel", catalog_table_enabled)
            self._set_action_checked_silently(self.add_data_action, add_data_enabled)
            self._set_action_checked_silently(
                self.catalog_table_action,
                catalog_table_enabled,
            )
            if sync:
                self.settings.sync()
        except Exception as e:
            self.logger.warning("Failed to store workspace panel visibility: %s", e)

    def _sync_dock_visibility(self, action: QAction, setting_key: str, visible: bool) -> None:
        self._set_action_checked_silently(action, visible)
        if (
            getattr(self, "_suspend_dock_state_sync", False)
            or getattr(self, "_is_restoring_workspace_layout", False)
            or getattr(self, "_is_closing", False)
            or not getattr(self, "_workspace_layout_restore_complete", False)
        ):
            return
        try:
            self.settings.setValue(setting_key, bool(visible))
            self._schedule_main_dock_state_save()
            self.settings.sync()
        except Exception as e:
            self.logger.warning("Failed to sync dock visibility for %s: %s", setting_key, e)

    def _apply_add_data_panel_state(self, enabled: bool):
        enabled = bool(enabled)
        dock = getattr(self, "add_data_dock", None)
        action = getattr(self, "add_data_action", None)
        if action is not None:
            self._set_action_checked_silently(action, enabled)
        if isinstance(dock, QDockWidget):
            dock.setVisible(enabled)
            if enabled:
                dock.raise_()
                self._ensure_add_track_panel_initialized()

    def _apply_catalog_table_panel_state(self, enabled: bool):
        enabled = bool(enabled)
        dock = getattr(self, "catalog_table_dock", None)
        action = getattr(self, "catalog_table_action", None)
        if action is not None:
            self._set_action_checked_silently(action, enabled)
        if isinstance(dock, QDockWidget):
            dock.setVisible(enabled)
            if enabled:
                dock.raise_()

    def _create_release_browser_panel(self, parent: QWidget) -> ReleaseBrowserPanel:
        panel = ReleaseBrowserPanel(
            release_service_provider=lambda: self.release_service,
            track_title_resolver=self._get_track_title,
            selected_track_ids_provider=lambda: list(
                self._catalog_table_controller().selected_track_ids()
            ),
            track_choice_provider=self._catalog_track_choices,
            parent=parent,
        )
        panel.filter_requested.connect(
            lambda track_ids: self._replace_catalog_track_filter(track_ids, source_label="release")
        )
        panel.open_track_requested.connect(self.open_selected_editor)
        panel.edit_release_requested.connect(self.open_release_editor)
        panel.duplicate_release_requested.connect(self.duplicate_release)
        panel.add_selected_tracks_requested.connect(
            lambda release_id, track_ids: self.add_selected_tracks_to_specific_release(
                release_id, track_ids
            )
        )
        panel.create_release_requested.connect(self.create_release_from_selection)
        return panel

    def _create_work_manager_panel(self, parent: QWidget) -> WorkBrowserPanel:
        panel = WorkBrowserPanel(
            work_service_provider=lambda: self.work_service,
            track_title_resolver=self._get_track_title,
            selected_track_ids_provider=lambda: list(
                self._catalog_table_controller().selected_track_ids()
            ),
            track_choice_provider=self._catalog_track_choices,
            parent=parent,
        )
        panel.filter_requested.connect(
            lambda track_ids: self._replace_catalog_track_filter(track_ids, source_label="work")
        )
        panel.create_requested.connect(self.create_work)
        panel.create_child_track_requested.connect(self._begin_work_child_track_creation)
        panel.create_album_for_work_requested.connect(self.open_add_album_dialog_for_work)
        panel.update_requested.connect(self.update_work)
        panel.duplicate_requested.connect(self.duplicate_work)
        panel.link_tracks_requested.connect(self.link_tracks_to_work)
        panel.delete_requested.connect(self.delete_work)
        return panel

    def _create_global_search_panel(self, parent: QWidget) -> GlobalSearchPanel:
        panel = GlobalSearchPanel(
            search_service_provider=lambda: self.global_search_service,
            relationship_service_provider=lambda: self.relationship_explorer_service,
            parent=parent,
        )
        panel.open_entity_requested.connect(self._open_entity_from_relationship_search)
        return panel

    def _create_diagnostics_catalog_cleanup_panel(
        self, parent: QWidget
    ) -> DiagnosticsCatalogCleanupPanel | None:
        if self.catalog_service is None:
            return None
        return DiagnosticsCatalogCleanupPanel(self, parent=parent)

