    def _action_ribbon_setting_keys(self) -> list[str]:
        return [
            "display/action_ribbon_visible",
            "display/action_ribbon_actions_json",
        ]

    def _current_action_ribbon_visibility(self) -> bool:
        toolbar = getattr(self, "action_ribbon_toolbar", None)
        return bool(isinstance(toolbar, QToolBar) and toolbar.isVisible())

    @staticmethod
    def _normalize_action_ribbon_ids_for_known_ids(action_ids, known_action_ids) -> list[str]:
        known_ids = {
            str(action_id or "").strip()
            for action_id in known_action_ids or []
            if str(action_id or "").strip()
        }
        normalized: list[str] = []
        seen: set[str] = set()
        for action_id in action_ids or []:
            clean_id = str(action_id or "").strip()
            if not clean_id or clean_id in seen:
                continue
            if known_ids and clean_id not in known_ids:
                continue
            seen.add(clean_id)
            normalized.append(clean_id)
        return normalized

    def _normalize_action_ribbon_ids(self, action_ids) -> list[str]:
        known_action_ids = list(getattr(self, "_action_ribbon_specs_by_id", {}).keys())
        return self._normalize_action_ribbon_ids_for_known_ids(action_ids, known_action_ids)

    def _load_saved_action_ribbon_action_ids(self) -> list[str]:
        setting_key = "display/action_ribbon_actions_json"
        if not self.settings.contains(setting_key):
            return list(getattr(self, "_action_ribbon_default_ids", []))

        raw_value = self.settings.value(setting_key, "[]")
        parsed_ids = raw_value
        if isinstance(raw_value, str):
            try:
                parsed_ids = json.loads(raw_value)
            except Exception:
                return list(getattr(self, "_action_ribbon_default_ids", []))
        elif not isinstance(raw_value, list):
            parsed_ids = []
        normalized_ids = self._normalize_action_ribbon_ids(parsed_ids)
        if not normalized_ids and parsed_ids:
            return list(getattr(self, "_action_ribbon_default_ids", []))
        return normalized_ids

    def _capture_current_action_ribbon_layout_snapshot(self) -> dict[str, object]:
        action_ids = self._normalize_action_ribbon_ids(
            getattr(self, "_action_ribbon_action_ids", [])
        )
        if not action_ids:
            action_ids = list(getattr(self, "_action_ribbon_default_ids", []))
        return {
            "schema_version": 1,
            "action_ids": action_ids,
            "visible": self._current_action_ribbon_visibility(),
        }

    def _resolve_saved_layout_action_ribbon_snapshot(
        self,
        snapshot: dict[str, object],
    ) -> tuple[list[str], bool]:
        current_action_ids = self._normalize_action_ribbon_ids(
            getattr(self, "_action_ribbon_action_ids", [])
        )
        return self._resolve_saved_layout_action_ribbon_snapshot_payload(
            snapshot,
            current_action_ids=current_action_ids,
            current_visible=self._current_action_ribbon_visibility(),
            default_action_ids=list(getattr(self, "_action_ribbon_default_ids", [])),
            known_action_ids=list(getattr(self, "_action_ribbon_specs_by_id", {}).keys()),
        )

    @staticmethod
    def _resolve_saved_layout_action_ribbon_snapshot_payload(
        snapshot: dict[str, object],
        *,
        current_action_ids,
        current_visible: bool,
        default_action_ids,
        known_action_ids,
    ) -> tuple[list[str], bool]:
        normalized_current_action_ids = App._normalize_action_ribbon_ids_for_known_ids(
            current_action_ids,
            known_action_ids,
        )
        if not normalized_current_action_ids:
            normalized_current_action_ids = App._normalize_action_ribbon_ids_for_known_ids(
                default_action_ids,
                known_action_ids,
            )

        ribbon_snapshot = snapshot.get("action_ribbon")
        if isinstance(ribbon_snapshot, dict):
            action_ids = App._normalize_action_ribbon_ids_for_known_ids(
                ribbon_snapshot.get("action_ids"),
                known_action_ids,
            )
            if not action_ids:
                action_ids = list(normalized_current_action_ids)
            visible_value = ribbon_snapshot.get("visible")
            if visible_value is None:
                visible_value = snapshot.get("action_ribbon_visible", current_visible)
            return action_ids, bool(visible_value)

        legacy_visible = snapshot.get("action_ribbon_visible")
        if legacy_visible is None:
            legacy_visible = current_visible
        return list(normalized_current_action_ids), bool(legacy_visible)

    def _store_action_ribbon_preferences(
        self,
        action_ids,
        visible: bool,
        *,
        sync: bool = True,
    ) -> None:
        normalized_ids = self._normalize_action_ribbon_ids(action_ids)
        if not normalized_ids:
            normalized_ids = list(getattr(self, "_action_ribbon_default_ids", []))
        try:
            self.settings.setValue(
                "display/action_ribbon_actions_json",
                json.dumps(normalized_ids),
            )
            self.settings.setValue("display/action_ribbon_visible", bool(visible))
            if sync:
                self.settings.sync()
        except Exception as e:
            self.logger.warning("Failed to store action ribbon preferences: %s", e)

    def _action_ribbon_button_tooltip(self, spec: dict) -> str:
        parts = [str(spec.get("label") or "").strip()]
        description = str(spec.get("description") or "").strip()
        shortcut_text = str(spec.get("shortcut") or "").strip()
        if description:
            parts.append(description)
        if shortcut_text:
            parts.append(f"Shortcut: {shortcut_text}")
        return "\n".join(part for part in parts if part)

    def _build_saved_layout_ribbon_widget(self, parent: QWidget) -> QWidget:
        container = QWidget(parent)
        container.setObjectName("savedLayoutRibbonControls")
        container.setProperty("role", "actionRibbonCluster")
        layout = QHBoxLayout(container)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(6)

        selector = FocusWheelComboBox(container)
        selector.setObjectName("savedLayoutSelector")
        selector.setMinimumContentsLength(14)
        selector.setSizeAdjustPolicy(QComboBox.AdjustToContents)
        selector.setInsertPolicy(QComboBox.NoInsert)
        selector.setProperty("role", "actionRibbonSelector")
        self._connect_args_signal(selector.activated, selector, self._on_saved_layout_selected)
        layout.addWidget(selector)

        save_button = QPushButton("Save Layout", container)
        save_button.setObjectName("savedLayoutAddButton")
        save_button.setProperty("role", "actionRibbonButton")
        self._connect_noarg_signal(save_button.clicked, save_button, self.add_named_main_window_layout)
        layout.addWidget(save_button)

        delete_button = QPushButton("Delete Layout", container)
        delete_button.setObjectName("savedLayoutDeleteButton")
        delete_button.setProperty("role", "actionRibbonButton")
        delete_button.clicked.connect(
            lambda: self.delete_named_main_window_layout_interactive(selector.currentData())
        )
        layout.addWidget(delete_button)

        self.saved_layout_selector = selector
        self.saved_layout_add_button = save_button
        self.saved_layout_delete_button = delete_button
        self._refresh_saved_layout_controls()
        return container

    def _rebuild_action_ribbon_toolbar(self):
        toolbar = getattr(self, "action_ribbon_toolbar", None)
        if toolbar is None:
            return

        toolbar.clear()
        action_ids = self._normalize_action_ribbon_ids(
            getattr(self, "_action_ribbon_action_ids", [])
        )
        self._action_ribbon_action_ids = action_ids

        for action_id in action_ids:
            spec = self._action_ribbon_specs_by_id.get(action_id)
            if spec is None:
                continue
            toolbar.addAction(spec["action"])
            widget = toolbar.widgetForAction(spec["action"])
            if widget is not None:
                widget.setProperty("role", "actionRibbonButton")
                widget.setToolTip(self._action_ribbon_button_tooltip(spec))

        spacer = QWidget(toolbar)
        spacer.setObjectName("actionRibbonSpacer")
        spacer.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
        toolbar.addWidget(spacer)

        toolbar.addWidget(self._build_saved_layout_ribbon_widget(toolbar))

        toolbar.addAction(self.customize_action_ribbon_action)
        customize_widget = toolbar.widgetForAction(self.customize_action_ribbon_action)
        if customize_widget is not None:
            customize_widget.setProperty("role", "actionRibbonButton")
            customize_widget.setToolTip(
                "Choose which quick actions appear in the top action ribbon."
            )

    def _apply_action_ribbon_configuration(self, action_ids: list[str], visible: bool):
        self._action_ribbon_action_ids = self._normalize_action_ribbon_ids(action_ids)
        self._rebuild_action_ribbon_toolbar()
        if hasattr(self, "action_ribbon_visibility_action"):
            self._set_action_checked_silently(self.action_ribbon_visibility_action, bool(visible))
        if hasattr(self, "action_ribbon_toolbar") and self.action_ribbon_toolbar is not None:
            self.action_ribbon_toolbar.setVisible(bool(visible))

    def _apply_profiles_toolbar_visibility(self, visible: bool) -> None:
        toolbar = getattr(self, "toolbar", None)
        if toolbar is not None:
            toolbar.setVisible(bool(visible))
            toolbar.updateGeometry()
        if hasattr(self, "profiles_toolbar_visibility_action"):
            self._set_action_checked_silently(
                self.profiles_toolbar_visibility_action,
                bool(visible),
            )
        self._queue_top_chrome_boundary_refresh()

    def _open_action_ribbon_context_menu(self, pos):
        toolbar = getattr(self, "action_ribbon_toolbar", None)
        if toolbar is None:
            return
        menu = QMenu(toolbar)
        menu.addAction(self.customize_action_ribbon_action)
        menu.addSeparator()
        menu.addAction(self.action_ribbon_visibility_action)
        menu.exec(toolbar.mapToGlobal(pos))

    def _apply_saved_view_preferences(self, *, apply_workspace_panel_visibility: bool = True):
        previous_suspend_state = self._suspend_layout_history
        self._suspend_layout_history = True
        try:
            columns_movable = self._catalog_header_state_manager().load_columns_movable_state(
                default=False
            )
            col_width_enabled = self.settings.value("display/interactive_col_width", False, bool)
            row_height_enabled = self.settings.value("display/interactive_row_height", False, bool)
            add_data_enabled = self.settings.value("display/add_data_panel", False, bool)
            catalog_table_enabled = self.settings.value("display/catalog_table_panel", True, bool)
            profiles_toolbar_visible = self.settings.value(
                "display/profiles_toolbar_visible",
                True,
                bool,
            )
            action_ribbon_visible = self.settings.value("display/action_ribbon_visible", True, bool)
            action_ribbon_ids = self._load_saved_action_ribbon_action_ids()

            if not apply_workspace_panel_visibility:
                add_data_dock = getattr(self, "add_data_dock", None)
                catalog_table_dock = getattr(self, "catalog_table_dock", None)
                if isinstance(add_data_dock, QDockWidget):
                    add_data_enabled = bool(add_data_dock.isVisible())
                if isinstance(catalog_table_dock, QDockWidget):
                    catalog_table_enabled = bool(catalog_table_dock.isVisible())

            self._set_action_checked_silently(self.act_reorder_columns, columns_movable)
            self._set_action_checked_silently(self.col_width_action, col_width_enabled)
            self._set_action_checked_silently(self.row_height_action, row_height_enabled)
            self._set_action_checked_silently(self.add_data_action, add_data_enabled)
            self._set_action_checked_silently(self.catalog_table_action, catalog_table_enabled)
            self._set_action_checked_silently(
                self.profiles_toolbar_visibility_action,
                profiles_toolbar_visible,
            )
            self._set_action_checked_silently(
                self.action_ribbon_visibility_action, action_ribbon_visible
            )

            self._apply_columns_movable_state(columns_movable)
            self._apply_col_width_mode(col_width_enabled)
            self._apply_row_height_mode(row_height_enabled)
            if apply_workspace_panel_visibility:
                self._apply_add_data_panel_state(add_data_enabled)
                self._apply_catalog_table_panel_state(catalog_table_enabled)
            self._apply_profiles_toolbar_visibility(profiles_toolbar_visible)
            self._apply_action_ribbon_configuration(action_ribbon_ids, action_ribbon_visible)
        finally:
            self._suspend_layout_history = previous_suspend_state

    def _record_setting_bundle_from_entries(
        self,
        *,
        action_label: str,
        before_entries: list[dict],
        after_entries: list[dict],
        entity_id: str | None = None,
    ):
        if self.history_manager is None or before_entries == after_entries:
            return
        self.history_manager.record_setting_bundle_change(
            label=action_label,
            before_entries=before_entries,
            after_entries=after_entries,
            entity_id=entity_id,
        )
        self._refresh_history_actions()

    def _run_setting_bundle_history_action(
        self,
        *,
        action_label: str,
        setting_keys: list[str],
        mutation,
        entity_id: str | None = None,
    ):
        if self.history_manager is None:
            return mutation()
        before_entries = self.history_manager.capture_setting_states(setting_keys)
        try:
            result = mutation()
        except Exception:
            try:
                self.history_manager.apply_setting_entries(before_entries)
            except Exception as restore_error:
                self.logger.exception(
                    f"Settings rollback failed for {action_label}: {restore_error}"
                )
            raise
        after_entries = self.history_manager.capture_setting_states(setting_keys)
        self._record_setting_bundle_from_entries(
            action_label=action_label,
            before_entries=before_entries,
            after_entries=after_entries,
            entity_id=entity_id,
        )
        return result

    def _run_file_history_action(
        self,
        *,
        action_label,
        action_type: str,
        target_path: str | Path,
        mutation,
        companion_suffixes: tuple[str, ...] = (),
        entity_type: str | None = "File",
        entity_id: str | None = None,
        payload=None,
    ):
        if self.history_manager is None:
            return mutation()
        before_state = self.history_manager.capture_file_state(
            target_path,
            companion_suffixes=companion_suffixes,
        )
        try:
            result = mutation()
            after_state = self.history_manager.capture_file_state(
                target_path,
                companion_suffixes=companion_suffixes,
            )
            if before_state != after_state:
                final_label = action_label(result) if callable(action_label) else action_label
                final_payload = payload(result) if callable(payload) else (payload or {})
                self.history_manager.record_file_write_action(
                    label=final_label,
                    action_type=action_type,
                    target_path=target_path,
                    before_state=before_state,
                    after_state=after_state,
                    entity_type=entity_type,
                    entity_id=entity_id,
                    payload=final_payload,
                )
                self._refresh_history_actions()
            return result
        except Exception:
            try:
                self.history_manager.restore_file_state(target_path, before_state)
            except Exception as restore_error:
                self.logger.exception(f"File rollback failed for {action_type}: {restore_error}")
            raise

    def _table_setting_keys(self, *, include_columns_movable: bool = False) -> list[str]:
        prefix = self._table_settings_prefix()
        keys = [
            f"{prefix}/header_state",
            f"{prefix}/header_labels",
            f"{prefix}/header_labels_json",
            f"{prefix}/header_column_keys_json",
            f"{prefix}/hidden_columns_json",
            f"{prefix}/hidden_column_keys_json",
        ]
        if include_columns_movable:
            keys.append(f"{prefix}/columns_movable")
        return keys

    def _activate_profile(self, path: str, *, save_current_header: bool = True):
        if save_current_header:
            try:
                self._save_header_state(record_history=False)
            except Exception:
                pass

        self.open_database(path)
        self._reset_catalog_zoom_for_profile_change()

        with self._suspend_table_layout_history():
            try:
                self.active_custom_fields = self.load_active_custom_fields()
                self._rebuild_table_headers()
                self._load_header_state()
            except Exception:
                pass

            self._reload_profiles_list(select_path=path)
            self.refresh_table_preserve_view()
            self.populate_all_comboboxes()
            self._update_add_data_generated_fields()
            self._refresh_history_actions()
            self._schedule_owner_party_bootstrap()

    def _prepare_profile_database_background(
        self,
        path: str,
        *,
        title: str,
        description: str,
        show_dialog: bool = True,
        on_success,
        on_error=None,
        on_finished=None,
        progress_callback=None,
    ) -> str | None:
        target_path = str(Path(path))

        def _worker(ctx):
            ctx.set_status(description)
            return self._prepare_database_session(
                target_path,
                progress_callback=lambda value, maximum, message: ctx.report_progress(
                    value=value,
                    maximum=maximum,
                    message=message,
                ),
            )

        def _handle_error(failure: TaskFailure) -> None:
            if on_error is not None:
                on_error(failure)
                return
            self._show_background_task_error(
                title,
                failure,
                user_message="Could not prepare the selected profile:",
            )

        return self._submit_background_task(
            title=title,
            description=description,
            task_fn=_worker,
            kind="exclusive",
            unique_key=f"profile.prepare.{target_path}",
            requires_profile=False,
            show_dialog=show_dialog,
            cancellable=False,
            owner=self,
            on_success=on_success,
            on_finished=on_finished,
            on_error=_handle_error,
            on_progress=(
                (lambda update: progress_callback(update.value, update.maximum, update.message))
                if callable(progress_callback)
                else None
            ),
        )

    def _activate_profile_in_background(
        self,
        path: str,
        *,
        save_current_header: bool = True,
        title: str = "Open Profile",
        description: str = "Preparing the selected profile database...",
        on_activated=None,
    ) -> str | None:
        if save_current_header:
            try:
                self._save_header_state(record_history=False)
            except Exception:
                pass

        loading_feedback = self._create_runtime_loading_feedback()
        loading_progress_tracker = (
            StartupProgressTracker.for_profile_loading(loading_feedback)
            if loading_feedback is not None
            else None
        )
        if loading_feedback is not None:
            if loading_progress_tracker is not None:
                loading_progress_tracker.set_phase(StartupPhase.OPENING_PROFILE_DB, description)
                loading_progress_tracker.complete_phase(
                    StartupPhase.OPENING_PROFILE_DB,
                    "Selected profile database for activation.",
                )
            else:
                self._set_loading_feedback_phase(
                    loading_feedback,
                    StartupPhase.OPENING_PROFILE_DB,
                    description,
                )

        prepared = {"path": None}

        def _success(prepared_path: str):
            prepared["path"] = str(prepared_path)

        def _error(failure: TaskFailure) -> None:
            try:
                self._show_background_task_error(
                    title,
                    failure,
                    user_message="Could not prepare the selected profile:",
                )
            finally:
                self._finish_loading_feedback(loading_feedback)

        def _finished():
            prepared_path = str(prepared.get("path") or "").strip()
            if not prepared_path:
                self._finish_loading_feedback(loading_feedback)
                return
            if loading_progress_tracker is not None:
                loading_progress_tracker.set_phase(
                    StartupPhase.LOADING_SERVICES,
                    "Opening selected profile database...",
                )
            else:
                self._set_loading_feedback_phase(
                    loading_feedback,
                    StartupPhase.LOADING_SERVICES,
                    "Opening selected profile database...",
                )
            if loading_feedback is not None:
                self._drain_qt_events()
            self.open_database(
                prepared_path,
                schema_prepared=True,
                progress_callback=self._loading_feedback_progress_callback(
                    loading_feedback,
                    loading_progress_tracker,
                    StartupPhase.LOADING_SERVICES,
                ),
            )
            self._reset_catalog_zoom_for_profile_change()
            with self._suspend_table_layout_history():
                interface_progress = self._loading_feedback_progress_callback(
                    loading_feedback,
                    loading_progress_tracker,
                    StartupPhase.FINALIZING_INTERFACE,
                )
                try:
                    self.active_custom_fields = self.load_active_custom_fields()
                    interface_progress(
                        1, 3, "Loaded active custom fields for the selected profile."
                    )
                    self._rebuild_table_headers()
                    interface_progress(2, 3, "Rebuilt catalog headers for the selected profile.")
                    self._load_header_state()
                except Exception:
                    pass
                interface_progress(3, 3, "Restored header state and profile selection.")
                self._reload_profiles_list(select_path=prepared_path)
                if loading_progress_tracker is not None:
                    loading_progress_tracker.set_phase(
                        StartupPhase.LOADING_CATALOG,
                        "Loading catalog rows and workspace data...",
                    )
                else:
                    self._set_loading_feedback_phase(
                        loading_feedback,
                        StartupPhase.LOADING_CATALOG,
                        "Loading catalog rows and workspace data...",
                    )
                if loading_feedback is not None:
                    self._drain_qt_events()
                task_id = self._refresh_catalog_ui_in_background(
                    select_path=prepared_path,
                    unique_key=f"catalog.ui.profile.{prepared_path}",
                    show_dialog=loading_feedback is None,
                    on_finished=lambda: (
                        on_activated(prepared_path) if on_activated is not None else None,
                        self._schedule_owner_party_bootstrap(),
                    ),
                    on_complete=lambda: (
                        (
                            loading_progress_tracker.finish()
                            if loading_progress_tracker is not None
                            else None
                        ),
                        self._finish_loading_feedback(loading_feedback),
                    ),
                    progress_callback=self._loading_feedback_progress_callback(
                        loading_feedback,
                        loading_progress_tracker,
                        StartupPhase.LOADING_CATALOG,
                    ),
                )
                if task_id is None:
                    if loading_progress_tracker is not None:
                        loading_progress_tracker.finish()
                    self._finish_loading_feedback(loading_feedback)

        task_id = self._prepare_profile_database_background(
            path,
            title=title,
            description=description,
            show_dialog=loading_feedback is None,
            on_success=_success,
            on_error=_error,
            on_finished=_finished,
            progress_callback=self._loading_feedback_progress_callback(
                loading_feedback,
                loading_progress_tracker,
                StartupPhase.PREPARING_DATABASE,
            ),
        )
        return task_id

    @staticmethod
    def _history_time_key(entry):
        if entry is None or not entry.created_at:
            return datetime.min
        try:
            return datetime.fromisoformat(entry.created_at)
        except ValueError:
            return datetime.min

    def _get_best_history_candidate(self, direction: str):
        candidates = []

        if direction == "undo":
            if self.history_manager is not None and self.history_manager.can_undo():
                candidates.append(("profile", self.history_manager.get_current_visible_entry()))
            if self.session_history_manager.can_undo():
                candidates.append(("session", self.session_history_manager.get_current_entry()))
        else:
            if self.history_manager is not None:
                redo_entry = self.history_manager.get_default_redo_entry()
                if redo_entry is not None:
                    candidates.append(("profile", redo_entry))
            redo_entry = self.session_history_manager.get_default_redo_entry()
            if redo_entry is not None:
                candidates.append(("session", redo_entry))

        if not candidates:
            return None, None
        return max(candidates, key=lambda item: (self._history_time_key(item[1]), item[1].entry_id))

    def _session_history_open_profile(self, path: str):
        self._activate_profile_in_background(path)

    def _session_history_reload_profiles(self, select_path: str | None = None):
        chosen_path = select_path or getattr(self, "current_db_path", None)
        self._reload_profiles_list(select_path=chosen_path)
        if self.conn is not None:
            self.refresh_table_preserve_view()
            self.populate_all_comboboxes()
        self._refresh_history_actions()

    def _session_history_delete_profile(self, path: str):
        profile_path = str(Path(path))
        if getattr(self, "current_db_path", None) == profile_path and self.conn is not None:
            self._close_database_connection()
        self.profile_workflows.profile_store.delete_profile(profile_path)

    def _run_snapshot_history_action(
        self,
        *,
        action_label: str,
        action_type: str,
        mutation,
        entity_type: str | None = None,
        entity_id: str | int | None = None,
        payload: dict | None = None,
        before_kind: str | None = None,
        before_label: str | None = None,
        after_kind: str | None = None,
        after_label: str | None = None,
    ):
        result = run_snapshot_history_action(
            history_manager=self.history_manager,
            action_label=action_label,
            action_type=action_type,
            mutation=mutation,
            entity_type=entity_type,
            entity_id=entity_id,
            payload=payload,
            before_kind=before_kind,
            before_label=before_label,
            after_kind=after_kind,
            after_label=after_label,
            logger=self.logger,
        )
        self._refresh_history_actions()
        return result

    def open_history_dialog(self):
        self.history_dialog = HistoryDialog(self, parent=self)
        self.history_dialog.exec()

    def history_undo(self):
        source, _ = self._get_best_history_candidate("undo")
        if source is None:
            return
        try:
            if source == "session":
                entry = self.session_history_manager.undo(self)
                if entry is not None:
                    self._refresh_history_actions()
                    if self.history_dialog is not None and self.history_dialog.isVisible():
                        self.history_dialog.refresh_data()
            else:
                entry = self.history_manager.undo()
                if entry is not None:
                    self._refresh_after_history_change()
        except Exception as e:
            self.logger.exception(f"Undo failed: {e}")
            QMessageBox.critical(self, "Undo Error", f"Could not undo the last action:\n{e}")

    def history_redo(self):
        source, _ = self._get_best_history_candidate("redo")
        if source is None:
            return
        try:
            if source == "session":
                entry = self.session_history_manager.redo(self)
                if entry is not None:
                    self._refresh_history_actions()
                    if self.history_dialog is not None and self.history_dialog.isVisible():
                        self.history_dialog.refresh_data()
            else:
                entry = self.history_manager.redo()
                if entry is not None:
                    self._refresh_after_history_change()
        except Exception as e:
            self.logger.exception(f"Redo failed: {e}")
            QMessageBox.critical(self, "Redo Error", f"Could not redo the action:\n{e}")

    def create_manual_snapshot(self):
        if self.history_manager is None:
            return
        label, ok = QInputDialog.getText(self, "Create Snapshot", "Snapshot label (optional):")
        if not ok:
            return
        snapshot_label = label.strip() or None
        estimated_bytes = self._estimate_history_snapshot_capture_bytes()
        if not self._prepare_history_storage_for_projected_growth(
            trigger_label="manual snapshot",
            additional_bytes=estimated_bytes,
            interactive=True,
        ):
            return

        def _worker(bundle, ctx):
            ctx.set_status("Capturing a full profile snapshot...")
            snapshot = bundle.history_manager.create_manual_snapshot(snapshot_label)
            return {"snapshot_id": snapshot.snapshot_id, "label": snapshot.label}

        def _success(result):
            self.logger.info("Created snapshot %s: %s", result["snapshot_id"], result["label"])
            QMessageBox.information(self, "Snapshot Created", f"Snapshot saved:\n{result['label']}")
            self._refresh_history_actions()
            if self.history_dialog is not None and self.history_dialog.isVisible():
                self.history_dialog.refresh_data()
            self._enforce_history_storage_budget(
                trigger_label="manual snapshot",
                interactive=True,
            )

        self._submit_background_bundle_task(
            title="Create Snapshot",
            description="Creating a manual snapshot of the current profile...",
            task_fn=_worker,
            kind="read",
            unique_key="snapshot.create",
            on_success=_success,
            on_error=lambda failure: self._show_background_task_error(
                "Snapshot Error",
                failure,
                user_message="Could not create the snapshot:",
            ),
        )

    def delete_snapshot_from_history(self, snapshot_id: int):
        if self.history_manager is None:
            return
        self.history_manager.delete_snapshot_as_action(snapshot_id)
        self._refresh_history_actions()
        if self.history_dialog is not None and self.history_dialog.isVisible():
            self.history_dialog.refresh_data()

    def delete_backup_from_history(self, backup_id: int):
        if self.history_manager is None:
            return
        self.history_manager.delete_backup(backup_id)
        self._refresh_history_actions()
        if self.history_dialog is not None and self.history_dialog.isVisible():
            self.history_dialog.refresh_data()

    def restore_snapshot_from_history(self, snapshot_id: int):
        if self.history_manager is None:
            return
        if (
            QMessageBox.question(
                self,
                "Restore Snapshot",
                "Restore this snapshot into the current profile?\n\nThe current state can be undone afterward.",
                QMessageBox.Yes | QMessageBox.No,
            )
            != QMessageBox.Yes
        ):
            return
        estimated_bytes = self._estimate_history_snapshot_capture_bytes()
        if not self._prepare_history_storage_for_projected_growth(
            trigger_label="snapshot restore",
            additional_bytes=estimated_bytes,
            interactive=True,
        ):
            return
        self._submit_background_bundle_task(
            title="Restore Snapshot",
            description="Restoring the selected snapshot...",
            task_fn=lambda bundle, ctx: bundle.history_manager.restore_snapshot_as_action(
                snapshot_id
            ),
            kind="write",
            unique_key="snapshot.restore",
            on_success=lambda _result: (
                self._refresh_after_history_change(),
                self._enforce_history_storage_budget(
                    trigger_label="snapshot restore",
                    interactive=True,
                ),
            ),
            on_error=lambda failure: self._show_background_task_error(
                "Restore Snapshot",
                failure,
                user_message="Could not restore the snapshot:",
            ),
        )

    def _collect_catalog_cleanup_targets(
        self,
        *,
        artist_name: str,
        additional_artists: list[str],
        album_title: str | None,
    ) -> tuple[list[str], list[str]]:
        artist_names = {
            (artist_name or "").strip(),
            *[(name or "").strip() for name in additional_artists],
        }
        new_artists = sorted(
            {
                name
                for name in artist_names
                if name and not self.track_service.artist_exists(name, cursor=self.cursor)
            }
        )
        clean_album = (album_title or "").strip()
        new_albums = []
        if clean_album and not self.track_service.album_exists(clean_album, cursor=self.cursor):
            new_albums.append(clean_album)
        return new_artists, new_albums

    # --- NEW: Variant helpers (repurposed as Artist Code AA) ---
    def load_isrc_prefix(self):
        return self.settings_reads.load_isrc_prefix()

    def load_active_custom_fields(self):
        return self.custom_field_definitions.list_active_fields()

    def _isrc_generation_state(self) -> tuple[str, str]:
        prefix = (self.load_isrc_prefix() or "").upper().strip()
        if not prefix:
            return (
                "disabled",
                "No ISRC prefix is configured. Tracks can still be saved, but ISRC auto-generation stays disabled until you add one in Settings.",
            )
        if not re.fullmatch(r"[A-Z]{2}[A-Z0-9]{3}", prefix):
            return (
                "error",
                "The saved ISRC prefix is invalid. Fix it in Settings to re-enable auto-generation.",
            )

        artist_code = self.load_artist_code()
        if not re.fullmatch(r"\d{2}", artist_code or ""):
            return (
                "error",
                "The saved ISRC artist code is invalid. Fix it in Settings to re-enable auto-generation.",
            )

        return ("ready", "")

    def _next_generated_isrc(
        self,
        *,
        release_date: QDate | None = None,
        use_release_year: bool = False,
        reserved_compacts: set[str] | None = None,
    ) -> str:
        if self.conn is None or self.cursor is None:
            return ""
        state, _message = self._isrc_generation_state()
        if state != "ready":
            return ""

        prefix = (self.load_isrc_prefix() or "").upper().strip()
        artist_code = self.load_artist_code()
        year = datetime.now().year % 100
        if use_release_year and isinstance(release_date, QDate) and release_date.isValid():
            year = release_date.year() % 100
        yy = f"{year:02d}"

        claimed_compacts = {
            str(code or "").strip().upper()
            for code in (reserved_compacts or set())
            if str(code or "").strip()
        }
        for seq in range(1, 1000):
            sss = f"{seq:03d}"
            candidate_compact = f"{prefix}{yy}{artist_code}{sss}"
            if candidate_compact in claimed_compacts:
                continue
            candidate = f"{prefix[0:2]}-{prefix[2:5]}-{yy}-{artist_code}{sss}"
            try:
                if not self.is_isrc_taken_normalized(candidate):
                    return candidate
            except Exception:
                return candidate
        return ""

    # =============================================================================
    # UI helpers
    # =============================================================================
    @staticmethod
    def _create_add_data_group(
        title: str, description: str | None = None
    ) -> tuple[QGroupBox, QVBoxLayout]:
        group = QGroupBox(title)
        layout = QVBoxLayout(group)
        layout.setContentsMargins(14, 16, 14, 14)
        layout.setSpacing(10)
        if description:
            description_label = QLabel(description, group)
            description_label.setWordWrap(True)
            description_label.setProperty("role", "sectionDescription")
            layout.addWidget(description_label)
        return group, layout

    @staticmethod
    def _create_add_data_status_field(placeholder: str) -> QLineEdit:
        field = QLineEdit()
        field.setReadOnly(True)
        field.setMinimumWidth(240)
        field.setPlaceholderText(placeholder)
        field.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
        return field

    @staticmethod
    def _create_add_data_row(
        label_widget: QLabel,
        field_widget: QWidget,
        *,
        top_aligned: bool = False,
        label_width: int = 132,
    ) -> QWidget:
        row = QWidget()
        layout = QHBoxLayout(row)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(12)
        label_widget.setMinimumWidth(label_width)
        label_widget.setAlignment(Qt.AlignRight | (Qt.AlignTop if top_aligned else Qt.AlignVCenter))
        if field_widget.sizePolicy().horizontalPolicy() == QSizePolicy.Preferred:
            field_widget.setSizePolicy(
                QSizePolicy.Expanding, field_widget.sizePolicy().verticalPolicy()
            )
        layout.addWidget(label_widget, 0, Qt.AlignTop if top_aligned else Qt.AlignVCenter)
        layout.addWidget(field_widget, 1, Qt.AlignTop if top_aligned else Qt.AlignVCenter)
        return row

    def _preview_generated_isrc(self) -> str:
        release_date = None
        if hasattr(self, "release_date_field"):
            try:
                release_date = self.release_date_field.selectedDate()
            except Exception:
                release_date = None
        return self._next_generated_isrc(
            release_date=release_date,
            use_release_year=bool(
                hasattr(self, "prev_release_toggle") and self.prev_release_toggle.isChecked()
            ),
        )

    def _update_add_data_generated_fields(self) -> None:
        if hasattr(self, "record_id_field"):
            self.record_id_field.clear()
        if hasattr(self, "entry_date_preview_field"):
            self.entry_date_preview_field.clear()
        if not hasattr(self, "generated_isrc_field"):
            return

        state, message = self._isrc_generation_state()
        preview = self._preview_generated_isrc()
        self.generated_isrc_field.setText(preview)
        if hasattr(self, "prev_release_toggle"):
            self.prev_release_toggle.setEnabled(state == "ready")

        if preview:
            self.generated_isrc_field.setPlaceholderText(
                "Generated automatically using the current ISRC settings."
            )
            self.generated_isrc_field.setToolTip(
                "Next available ISRC based on the current release date and ISRC settings."
            )
        elif state == "ready":
            self.generated_isrc_field.setPlaceholderText(
                "No free ISRC sequence is currently available."
            )
            self.generated_isrc_field.setToolTip(
                "ISRC auto-generation is enabled, but no free sequence is currently available for the active year and artist code."
            )
        elif state == "disabled":
            self.generated_isrc_field.setPlaceholderText(
                "Auto-generation disabled until an ISRC prefix is set."
            )
            self.generated_isrc_field.setToolTip(message)
        else:
            self.generated_isrc_field.setPlaceholderText(
                "Fix ISRC settings to re-enable auto-generation."
            )
            self.generated_isrc_field.setToolTip(message)

    def _initialize_catalog_table_model_view(self) -> None:
        table_model = CatalogTableModel(parent=self)
        filter_proxy = CatalogFilterProxyModel(parent=self)
        filter_proxy.setSourceModel(table_model)
        self._catalog_table_model = table_model
        self._catalog_filter_proxy_model = filter_proxy
        self.table.setModel(filter_proxy)
        self.table.setSortingEnabled(True)
        self.table.sortByColumn(0, Qt.AscendingOrder)
        self._connect_catalog_selection_model()

    def _connect_catalog_selection_model(self) -> None:
        selection_model = self.table.selectionModel() if hasattr(self, "table") else None
        if selection_model is None:
            return
        if getattr(self, "_catalog_selection_model_connection", None) is selection_model:
            return
        try:
            selection_model.selectionChanged.connect(
                lambda *_args: self._on_catalog_selection_changed()
            )
        except Exception:
            pass
        self._catalog_selection_model_connection = selection_model

    def _catalog_zoom_controller(self) -> CatalogZoomController:
        controller = getattr(self, "_catalog_zoom_controller_instance", None)
        if not isinstance(controller, CatalogZoomController):
            controller = CatalogZoomController(self)
            self._connect_args_signal(
                controller.zoom_percent_changed,
                controller,
                self._sync_catalog_zoom_controls,
            )
            self._catalog_zoom_controller_instance = controller
        controller.bind_view(
            getattr(self, "table", None),
            apply_callback=self._apply_catalog_zoom_to_view,
        )
        return controller

    def _initialize_catalog_zoom_controls(self) -> None:
        slider = getattr(self, "catalog_zoom_slider", None)
        if slider is None:
            return
        slider.setRange(CATALOG_ZOOM_MIN_PERCENT, CATALOG_ZOOM_MAX_PERCENT)
        slider.setSingleStep(CATALOG_ZOOM_STEP_PERCENT)
        slider.setPageStep(CATALOG_ZOOM_STEP_PERCENT)
        controller = self._catalog_zoom_controller()
        if not getattr(self, "_catalog_zoom_slider_connected", False):
            self._connect_args_signal(
                slider.valueChanged,
                slider,
                self._on_catalog_zoom_slider_value_changed,
            )
            self._connect_noarg_signal(slider.sliderReleased, slider, self._flush_catalog_zoom)
            self._catalog_zoom_slider_connected = True
        self._sync_catalog_zoom_controls(controller.zoom_percent())
        controller.set_zoom_percent(controller.zoom_percent(), immediate=True)

    def _on_catalog_zoom_slider_value_changed(self, zoom_percent: int) -> None:
        controller = self._catalog_zoom_controller()
        controller.set_zoom_percent(int(zoom_percent), immediate=False)

    def _flush_catalog_zoom(self) -> None:
        controller = getattr(self, "_catalog_zoom_controller_instance", None)
        if isinstance(controller, CatalogZoomController):
            controller.flush_pending_apply()

    def _sync_catalog_zoom_controls(self, zoom_percent: int) -> None:
        normalized_zoom = CatalogZoomController.clamp_zoom_percent(zoom_percent)
        slider = getattr(self, "catalog_zoom_slider", None)
        if slider is not None:
            previous_state = slider.blockSignals(True)
            try:
                if slider.value() != normalized_zoom:
                    slider.setValue(normalized_zoom)
            finally:
                slider.blockSignals(previous_state)
        label = getattr(self, "catalog_zoom_value_label", None)
        if label is not None:
            label.setText(f"{normalized_zoom}%")
        decrease_button = getattr(self, "catalog_zoom_decrease_button", None)
        if decrease_button is not None:
            decrease_button.setEnabled(normalized_zoom > CATALOG_ZOOM_MIN_PERCENT)
        increase_button = getattr(self, "catalog_zoom_increase_button", None)
        if increase_button is not None:
            increase_button.setEnabled(normalized_zoom < CATALOG_ZOOM_MAX_PERCENT)

    @staticmethod
    def _scaled_catalog_zoom_font(base_font: QFont, zoom_percent: int) -> QFont:
        scale = max(0.01, float(zoom_percent) / 100.0)
        font = QFont(base_font)
        if font.pointSizeF() > 0:
            font.setPointSizeF(max(1.0, font.pointSizeF() * scale))
        elif font.pixelSize() > 0:
            font.setPixelSize(max(1, int(round(font.pixelSize() * scale))))
        return font

    def _catalog_zoom_base_metrics(self, view) -> dict[str, object]:
        metrics = getattr(self, "_catalog_zoom_metrics", None)
        if isinstance(metrics, dict):
            return metrics
        horizontal_header = view.horizontalHeader()
        vertical_header = view.verticalHeader()
        icon_size = view.iconSize()
        icon_extent = max(int(icon_size.width()), int(icon_size.height()), 18)
        header_height = max(
            int(horizontal_header.height()),
            int(horizontal_header.sizeHint().height()),
            24,
        )
        metrics = {
            "table_font": QFont(view.font()),
            "horizontal_header_font": QFont(horizontal_header.font()),
            "vertical_header_font": QFont(vertical_header.font()),
            "row_height": max(int(vertical_header.defaultSectionSize()), 24),
            "minimum_row_height": max(int(vertical_header.minimumSectionSize()), 18),
            "header_height": header_height,
            "icon_extent": icon_extent,
        }
        self._catalog_zoom_metrics = metrics
        return metrics

    def _apply_catalog_zoom_to_view(self, view, zoom_percent: int) -> None:
        if view is None:
            return
        normalized_zoom = CatalogZoomController.clamp_zoom_percent(zoom_percent)
        metrics = self._catalog_zoom_base_metrics(view)
        scale = float(normalized_zoom) / 100.0
        horizontal_header = view.horizontalHeader()
        vertical_header = view.verticalHeader()

        view.setFont(self._scaled_catalog_zoom_font(metrics["table_font"], normalized_zoom))
        horizontal_header.setFont(
            self._scaled_catalog_zoom_font(
                metrics["horizontal_header_font"],
                normalized_zoom,
            )
        )
        vertical_header.setFont(
            self._scaled_catalog_zoom_font(
                metrics["vertical_header_font"],
                normalized_zoom,
            )
        )

        row_height = max(18, int(round(int(metrics["row_height"]) * scale)))
        minimum_row_height = max(18, int(round(int(metrics["minimum_row_height"]) * scale)))
        header_height = max(24, int(round(int(metrics["header_height"]) * scale)))
        icon_extent = max(12, int(round(int(metrics["icon_extent"]) * scale)))

        vertical_header.setMinimumSectionSize(minimum_row_height)
        vertical_header.setDefaultSectionSize(row_height)
        horizontal_header.setMinimumHeight(header_height)
        view.setIconSize(QSize(icon_extent, icon_extent))
        view.updateGeometry()
        viewport = view.viewport()
        if viewport is not None:
            viewport.update()

    @staticmethod
    def _catalog_zoom_steps_from_wheel_event(event) -> int:
        pixel_delta = event.pixelDelta()
        angle_delta = event.angleDelta()
        if not pixel_delta.isNull():
            dominant = (
                pixel_delta.y() if abs(pixel_delta.y()) >= abs(pixel_delta.x()) else pixel_delta.x()
            )
            return int(round(dominant / 40.0))
        if not angle_delta.isNull():
            dominant = (
                angle_delta.y() if abs(angle_delta.y()) >= abs(angle_delta.x()) else angle_delta.x()
            )
            return int(round(dominant / 120.0))
        return 0

    def _handle_catalog_zoom_wheel_event(self, event) -> bool:
        modifiers = event.modifiers() if hasattr(event, "modifiers") else Qt.NoModifier
        if not modifiers & (Qt.ControlModifier | Qt.MetaModifier):
            return False
        steps = self._catalog_zoom_steps_from_wheel_event(event)
        if not steps:
            return False
        self._catalog_zoom_controller().step_zoom(steps, immediate=False)
        event.accept()
        return True

    def _handle_catalog_zoom_native_gesture_event(self, event) -> bool:
        gesture_type = event.gestureType() if hasattr(event, "gestureType") else None
        if gesture_type == Qt.ZoomNativeGesture:
            value = float(event.value() if hasattr(event, "value") else 0.0)
            if abs(value) < 0.0001:
                return False
            self._catalog_zoom_controller().apply_pinch_scale(1.0 + value, immediate=True)
            event.accept()
            return True
        if gesture_type == Qt.SmartZoomNativeGesture:
            self._catalog_zoom_controller().reset_zoom(immediate=True)
            event.accept()
            return True
        return False

    def _handle_catalog_zoom_pinch_gesture_event(self, event) -> bool:
        if not hasattr(event, "gesture"):
            return False
        pinch = event.gesture(Qt.PinchGesture)
        if pinch is None:
            return False
        if not pinch.changeFlags() & QPinchGesture.ScaleFactorChanged:
            return False
        last_factor = float(pinch.lastScaleFactor() or 1.0)
        scale_factor = float(pinch.scaleFactor() or 1.0)
        factor = scale_factor if abs(last_factor) < 0.0001 else scale_factor / last_factor
        if abs(factor - 1.0) < 0.001:
            return False
        self._catalog_zoom_controller().apply_pinch_scale(factor, immediate=True)
        event.accept()
        return True

    def _handle_catalog_zoom_event(self, source, event) -> bool:
        table = getattr(self, "table", None)
        if table is None:
            return False
        viewport = table.viewport()
        if source not in (table, viewport):
            return False
        event_type = event.type()
        if event_type == QEvent.Wheel:
            return self._handle_catalog_zoom_wheel_event(event)
        if event_type == QEvent.NativeGesture:
            return self._handle_catalog_zoom_native_gesture_event(event)
        if event_type == QEvent.Gesture:
            if (
                getattr(self, "_catalog_zoom_gesture_platform", platform.system().lower())
                == "darwin"
            ):
                return False
            return self._handle_catalog_zoom_pinch_gesture_event(event)
        return False

    def _catalog_zoom_layout_state(self) -> dict[str, int]:
        return self._catalog_zoom_controller().layout_state()

    def _restore_catalog_zoom_layout_state(
        self,
        payload: dict[str, object] | None,
        *,
        immediate: bool = True,
    ) -> int:
        controller = self._catalog_zoom_controller()
        restored = controller.restore_layout_state(payload, immediate=immediate)
        self._sync_catalog_zoom_controls(restored)
        return restored

    def _reset_catalog_zoom_for_profile_change(self) -> int:
        controller = self._catalog_zoom_controller()
        restored = controller.on_profile_changed(immediate=True)
        self._sync_catalog_zoom_controls(restored)
        return restored

    def _catalog_source_model(self) -> CatalogTableModel | None:
        model = getattr(self, "_catalog_table_model", None)
        return model if isinstance(model, CatalogTableModel) else None

    def _catalog_proxy_model(self) -> CatalogFilterProxyModel | None:
        proxy = getattr(self, "_catalog_filter_proxy_model", None)
        return proxy if isinstance(proxy, CatalogFilterProxyModel) else None

    def _catalog_view_row_count(self) -> int:
        model = self.table.model() if hasattr(self, "table") else None
        return int(model.rowCount()) if model is not None else 0

    def _catalog_view_column_count(self) -> int:
        model = self.table.model() if hasattr(self, "table") else None
        return int(model.columnCount()) if model is not None else 0

    def _catalog_header_text_for_column(self, column: int) -> str:
        model = self.table.model() if hasattr(self, "table") else None
        if model is None:
            return ""
        if column < 0 or column >= model.columnCount():
            return ""
        return str(model.headerData(int(column), Qt.Horizontal, Qt.DisplayRole) or "")

    def _catalog_table_column_specs_for_fields(
        self,
        active_custom_fields: list[dict[str, object]] | None = None,
    ) -> tuple[CatalogColumnSpec, ...]:
        fields = (
            list(active_custom_fields)
            if active_custom_fields is not None
            else list(getattr(self, "active_custom_fields", []) or [])
        )
        default_hidden_names = {str(name).strip() for name in DEFAULT_HIDDEN_CUSTOM_COLUMN_NAMES}
        column_specs: list[CatalogColumnSpec] = []
        for logical_index, header_text in enumerate(self.BASE_HEADERS):
            standard_spec = standard_field_spec_for_label(header_text)
            column_key = (
                f"base:{standard_spec.key}"
                if standard_spec is not None
                else self._fallback_header_column_key(
                    header_text,
                    prefix="base",
                    logical_index=logical_index,
                )
            )
            column_specs.append(CatalogColumnSpec(key=column_key, header_text=header_text))

        for field_index, field in enumerate(fields):
            header_text = str(field.get("name") or "").strip() or f"Custom {field_index + 1}"
            try:
                field_id = int(field.get("id"))
            except (TypeError, ValueError):
                field_id = None
            logical_index = len(self.BASE_HEADERS) + field_index
            column_key = (
                f"custom:{field_id}"
                if field_id is not None and field_id > 0
                else self._fallback_header_column_key(
                    header_text,
                    prefix="custom",
                    logical_index=logical_index,
                )
            )
            column_specs.append(
                CatalogColumnSpec(
                    key=column_key,
                    header_text=header_text,
                    hidden_by_default=header_text in default_hidden_names,
                )
            )
        return tuple(column_specs)

    def _rebuild_table_headers(self):
        source_model = self._catalog_source_model()
        if source_model is not None:
            source_model.set_snapshot(
                CatalogSnapshot(
                    column_specs=self._catalog_table_column_specs_for_fields(),
                    rows=(),
                )
            )
        self._apply_saved_column_visibility()
        self._rebuild_search_column_choices()
        self._refresh_column_visibility_menu()

    @staticmethod
    def _catalog_combo_values_from_connection(
        conn: sqlite3.Connection,
        *,
        progress_callback=None,
    ) -> dict[str, list[str]]:
        artist_values: list[str] = []
        seen_artist_values: set[str] = set()

        def _values(query: str) -> list[str]:
            try:
                return [
                    str(row[0] or "").strip()
                    for row in conn.execute(query).fetchall()
                    if str(row[0] or "").strip()
                ]
            except sqlite3.OperationalError:
                return []

        try:
            party_service = PartyService(conn)
            for record in party_service.list_artist_parties():
                primary = artist_primary_label(record)
                for candidate in (primary, *list(getattr(record, "artist_aliases", ()) or ())):
                    clean_value = str(candidate or "").strip()
                    if not clean_value or clean_value in seen_artist_values:
                        continue
                    seen_artist_values.add(clean_value)
                    artist_values.append(clean_value)
        except Exception:
            artist_values = []

        combo_values = {"artists": sorted(artist_values, key=str.casefold)}
        if callable(progress_callback):
            progress_callback(1, 5, "Loaded Artist lookup values.")
        combo_values["albums"] = [
            r[0]
            for r in conn.execute(
                "SELECT DISTINCT title FROM Albums WHERE title IS NOT NULL AND title != '' ORDER BY title"
            ).fetchall()
        ]
        if callable(progress_callback):
            progress_callback(2, 5, "Loaded Album lookup values.")
        combo_values["upcs"] = _values(
            """
            SELECT value
            FROM (
                SELECT upc AS value
                FROM Tracks
                WHERE upc IS NOT NULL AND upc != ''
                UNION
                SELECT upc AS value
                FROM Releases
                WHERE upc IS NOT NULL AND upc != ''
            )
            ORDER BY value
            """
        )
        if callable(progress_callback):
            progress_callback(3, 5, "Loaded UPC lookup values.")
        combo_values["genres"] = [
            r[0]
            for r in conn.execute(
                "SELECT DISTINCT genre FROM Tracks WHERE genre IS NOT NULL AND genre != '' ORDER BY genre"
            ).fetchall()
        ]
        if callable(progress_callback):
            progress_callback(4, 5, "Loaded Genre lookup values.")
        combo_values["catalog_numbers"] = _values(
            """
            SELECT value
            FROM (
                SELECT catalog_number AS value
                FROM Tracks
                WHERE catalog_number IS NOT NULL AND catalog_number != ''
                UNION
                SELECT catalog_number AS value
                FROM Releases
                WHERE catalog_number IS NOT NULL AND catalog_number != ''
            )
            ORDER BY value
            """
        )
        if callable(progress_callback):
            progress_callback(5, 5, "Loaded catalog number lookup values.")
        return combo_values

    def _apply_catalog_combo_values(self, combo_values: dict[str, list[str]]) -> None:
        self._populate_combobox(self.artist_field, combo_values.get("artists", []))
        self._populate_combobox(
            self.additional_artist_field, combo_values.get("artists", []), allow_empty=True
        )
        self._populate_combobox(
            self.album_title_field, combo_values.get("albums", []), allow_empty=True
        )
        self._populate_combobox(self.upc_field, combo_values.get("upcs", []), allow_empty=True)
        self._populate_combobox(self.genre_field, combo_values.get("genres", []), allow_empty=True)
        if hasattr(self.catalog_number_field, "refresh"):
            self.catalog_number_field.refresh()
        else:
            self._populate_combobox(
                self.catalog_number_field,
                combo_values.get("catalog_numbers", []),
                allow_empty=True,
            )

    def populate_all_comboboxes(self):
        if self.conn is None:
            return
        self._apply_catalog_combo_values(self._catalog_combo_values_from_connection(self.conn))
        self._refresh_add_track_artist_party_choices()

    def _artist_lookup_values(self) -> list[str]:
        if self.conn is None:
            return []
        return list(self._catalog_combo_values_from_connection(self.conn).get("artists", []))

    @staticmethod
    def _populate_combobox(combo: QComboBox, items, allow_empty=False):
        combo.clear()
        if allow_empty:
            combo.addItem("")
        combo.addItems(items)
        comp = QCompleter(items)
        comp.setCaseSensitivity(Qt.CaseInsensitive)
        combo.setCompleter(comp)

    @staticmethod
    def _artist_party_primary_label(record: PartyRecord) -> str:
        return artist_primary_label(record)

    @classmethod
    def _artist_party_choice_label(cls, record: PartyRecord) -> str:
        return artist_choice_label(record)

    def _artist_party_records(self) -> list[PartyRecord]:
        if self.party_service is None:
            return []
        try:
            return list(self.party_service.list_artist_parties() or [])
        except Exception:
            return []

    def _configure_artist_party_combo(
        self,
        combo: QComboBox,
        *,
        allow_empty: bool = False,
        selected_party_id: int | None = None,
        current_text: str | None = None,
    ) -> None:
        clean_text_value = str(current_text or "").strip()
        labels: list[str] = []
        previous_state = combo.blockSignals(True)
        try:
            combo.clear()
            combo.setEditable(True)
            combo.setInsertPolicy(QComboBox.NoInsert)
            if allow_empty:
                combo.addItem("", None)
            for record in self._artist_party_records():
                label = self._artist_party_choice_label(record)
                combo.addItem(label, int(record.id))
                combo.setItemData(
                    combo.count() - 1,
                    self._artist_party_primary_label(record),
                    Qt.UserRole + 1,
                )
                labels.append(label)
                labels.extend(
                    alias
                    for alias in getattr(record, "artist_aliases", ()) or ()
                    if str(alias or "").strip()
                )
            if selected_party_id is not None and combo.findData(int(selected_party_id)) < 0:
                fallback_label = clean_text_value or f"Party #{int(selected_party_id)}"
                combo.addItem(fallback_label, int(selected_party_id))
                combo.setItemData(combo.count() - 1, fallback_label, Qt.UserRole + 1)
                labels.append(fallback_label)
            completer = QCompleter(sorted({label for label in labels if label}), combo)
            completer.setCaseSensitivity(Qt.CaseInsensitive)
            combo.setCompleter(completer)
            if selected_party_id is not None:
                index = combo.findData(int(selected_party_id))
                combo.setCurrentIndex(index if index >= 0 else 0)
            elif clean_text_value:
                combo.setCurrentIndex(-1)
                combo.setEditText(clean_text_value)
            elif allow_empty:
                combo.setCurrentIndex(0)
        finally:
            combo.blockSignals(previous_state)

    def _resolve_artist_party_choice(self, combo: QComboBox) -> tuple[str, int | None]:
        clean = str(combo.currentText() or "").strip()
        if not clean:
            return "", None
        current_index = combo.currentIndex()
        if current_index >= 0:
            data = combo.itemData(current_index)
            label = str(combo.itemText(current_index) or "").strip()
            if data not in (None, "") and clean.casefold() == label.casefold():
                primary_label = str(combo.itemData(current_index, Qt.UserRole + 1) or label).strip()
                return primary_label or label, int(data)
        for index in range(combo.count()):
            label = str(combo.itemText(index) or "").strip()
            if clean.casefold() != label.casefold():
                continue
            data = combo.itemData(index)
            if data not in (None, ""):
                primary_label = str(combo.itemData(index, Qt.UserRole + 1) or label).strip()
                return primary_label or label, int(data)
        return clean, None

    def _resolve_party_backed_artist_name(
        self,
        raw_name: str,
        *,
        selected_party_id: int | None = None,
        cursor: sqlite3.Cursor | None = None,
    ) -> tuple[str, int | None]:
        clean_name = str(raw_name or "").strip()
        if not clean_name:
            return "", None
        if self.party_service is None:
            return clean_name, None
        party_id = int(selected_party_id) if selected_party_id not in (None, "") else None
        if party_id is None:
            existing_id = self.party_service.find_artist_party_id_by_name(
                clean_name,
                cursor=cursor,
            )
            if existing_id is not None:
                party_id = int(existing_id)
            else:
                party_id = int(
                    self.party_service.ensure_artist_party_by_name(
                        clean_name,
                        cursor=cursor,
                    )
                )
        record = self.party_service.fetch_party(int(party_id))
        if record is None:
            return clean_name, int(party_id)
        return self._artist_party_primary_label(record), int(record.id)

    def _resolve_party_backed_additional_artist_names(
        self,
        names: list[str],
        *,
        cursor: sqlite3.Cursor | None = None,
    ) -> list[str]:
        resolved: list[str] = []
        seen: set[str] = set()
        for raw_name in names:
            clean_name, _party_id = self._resolve_party_backed_artist_name(
                raw_name,
                cursor=cursor,
            )
            normalized = clean_name.casefold()
            if not clean_name or normalized in seen:
                continue
            seen.add(normalized)
            resolved.append(clean_name)
        return resolved

    def _refresh_add_track_artist_party_choices(self) -> None:
        for combo, allow_empty in (
            (getattr(self, "artist_field", None), False),
            (getattr(self, "additional_artist_field", None), True),
        ):
            if not isinstance(combo, QComboBox):
                continue
            current_text, selected_party_id = self._resolve_artist_party_choice(combo)
            self._configure_artist_party_combo(
                combo,
                allow_empty=allow_empty,
                selected_party_id=selected_party_id,
                current_text=current_text,
            )

    def _work_payload_from_track_seed(
        self,
        *,
        track_title: str,
        iswc: str | None,
        registration_number: str | None,
    ) -> WorkPayload:
        return WorkPayload(
            title=str(track_title or "").strip(),
            iswc=str(iswc or "").strip() or None,
            registration_number=str(registration_number or "").strip() or None,
            profile_name=self._current_profile_name(),
        )

    @staticmethod
    def _work_track_relationship_choices() -> list[str]:
        ordered = [
            "original",
            "version",
            "alternate_master",
            "remix",
            "edit",
            "live",
            "instrumental",
            "derivative",
            "other",
        ]
        return [value for value in ordered if value in TRACK_RELATIONSHIP_TYPES]

    @staticmethod
    def _work_track_relationship_label(value: str) -> str:
        return str(value or "original").strip().replace("_", " ").title()

    def _normalize_work_track_relationship(self, value: str | None) -> str:
        clean = str(value or "").strip().lower().replace(" ", "_")
        return clean if clean in TRACK_RELATIONSHIP_TYPES else "original"

    @staticmethod
    def _work_track_governance_modes() -> tuple[tuple[str, str], ...]:
        return (
            ("create_new_work", "Create New Work from This Track"),
            ("link_existing_work", "Link to Existing Work"),
        )

    def _refresh_add_track_lookup_sources_preserving_text(self) -> None:
        self._refresh_add_track_artist_party_choices()
        if self.conn is None:
            return

        def _set_items_preserving_text(combo: QComboBox, values) -> None:
            clean_values: list[str] = []
            seen: set[str] = set()
            for value in values:
                clean_value = str(value or "").strip()
                if not clean_value or clean_value in seen:
                    continue
                seen.add(clean_value)
                clean_values.append(clean_value)
            current_text = str(combo.currentText() or "").strip()
            previous_state = combo.blockSignals(True)
            try:
                combo.clear()
                combo.setEditable(True)
                combo.setInsertPolicy(QComboBox.NoInsert)
                combo.addItem("")
                combo.addItems(clean_values)
                if current_text and combo.findText(current_text, Qt.MatchFixedString) < 0:
                    combo.addItem(current_text)
                combo.setCurrentText(current_text)
                completer = QCompleter(clean_values, combo)
                completer.setCaseSensitivity(Qt.CaseInsensitive)
                combo.setCompleter(completer)
            finally:
                combo.blockSignals(previous_state)

        album_combo = getattr(self, "album_title_field", None)
        upc_combo = getattr(self, "upc_field", None)
        genre_combo = getattr(self, "genre_field", None)
        catalog_field = getattr(self, "catalog_number_field", None)

        combo_values = self._catalog_combo_values_from_connection(self.conn)

        if isinstance(album_combo, QComboBox):
            _set_items_preserving_text(album_combo, combo_values.get("albums", []))
        if isinstance(upc_combo, QComboBox):
            _set_items_preserving_text(upc_combo, combo_values.get("upcs", []))
        if isinstance(genre_combo, QComboBox):
            _set_items_preserving_text(genre_combo, combo_values.get("genres", []))
        if catalog_field is not None and hasattr(catalog_field, "refresh"):
            current_catalog_number = (
                str(catalog_field.currentText() or "").strip()
                if hasattr(catalog_field, "currentText")
                else ""
            )
            catalog_field.refresh()
            catalog_field.setCurrentText(current_catalog_number)

    def _ensure_add_track_panel_initialized(self) -> None:
        if not hasattr(self, "add_data_work_mode_combo"):
            return
        self._current_work_track_context()
        self._refresh_work_track_creation_context_ui()

        lookup_combos = (
            getattr(self, "album_title_field", None),
            getattr(self, "upc_field", None),
            getattr(self, "genre_field", None),
        )
        catalog_combo = getattr(getattr(self, "catalog_number_field", None), "combo", None)
        if any(
            isinstance(combo, QComboBox) and combo.count() == 0 for combo in lookup_combos
        ) or (isinstance(catalog_combo, QComboBox) and catalog_combo.count() == 0):
            self._refresh_add_track_lookup_sources_preserving_text()

    def _on_add_track_dock_visibility_changed(self, visible: bool) -> None:
        self._sync_dock_visibility(self.add_data_action, "display/add_data_panel", visible)
        if bool(visible):
            self._ensure_add_track_panel_initialized()

    def _default_work_track_context(self) -> dict[str, object]:
        return {
            "mode": "create_new_work",
            "work_id": None,
            "relationship_type": "original",
            "parent_track_id": None,
            "locked_work": False,
            "return_to_work_manager": False,
        }

    def _set_pending_work_track_context(self, **overrides: object) -> dict[str, object]:
        context = self._default_work_track_context()
        context.update(overrides)
        self._pending_work_track_context = context
        return self._current_work_track_context()

    def _current_work_track_context(self) -> dict[str, object]:
        context = getattr(self, "_pending_work_track_context", None)
        if not isinstance(context, dict):
            context = self._default_work_track_context()
        mode = str(context.get("mode") or "create_new_work").strip().lower()
        if mode not in {"create_new_work", "link_existing_work"}:
            mode = "create_new_work"
        try:
            work_id = int(context.get("work_id"))
        except (TypeError, ValueError):
            work_id = None
        parent_track_id = context.get("parent_track_id")
        try:
            normalized_parent_track_id = (
                int(parent_track_id) if parent_track_id not in (None, "") else None
            )
        except (TypeError, ValueError):
            normalized_parent_track_id = None
        locked_work = bool(context.get("locked_work"))
        return_to_work_manager = bool(context.get("return_to_work_manager"))
        if locked_work and work_id is not None:
            mode = "link_existing_work"
        normalized = {
            "mode": mode,
            "work_id": work_id if mode == "link_existing_work" else None,
            "relationship_type": (
                self._normalize_work_track_relationship(
                    str(context.get("relationship_type") or "original")
                )
                if mode == "link_existing_work"
                else "original"
            ),
            "parent_track_id": normalized_parent_track_id if mode == "link_existing_work" else None,
            "locked_work": locked_work,
            "return_to_work_manager": return_to_work_manager,
        }
        self._pending_work_track_context = normalized
        return normalized

    def _available_work_records(self) -> list:
        if self.work_service is None:
            return []
        try:
            return list(self.work_service.list_works())
        except Exception:
            return []

    @staticmethod
    def _work_choice_label(record) -> str:
        title = str(getattr(record, "title", "") or "").strip()
        work_id = int(getattr(record, "id", 0) or 0)
        iswc = str(getattr(record, "iswc", "") or "").strip()
        base = title or (f"Work #{work_id}" if work_id > 0 else "Untitled Work")
        return f"{base} ({iswc})" if iswc else base

    def _focus_work_in_manager(self, work_id: int | None) -> None:
        if not work_id:
            return
        panel = getattr(self, "work_browser_dialog", None)
        if panel is None:
            return
        focus_work = getattr(panel, "focus_work", None)
        if callable(focus_work):
            focus_work(int(work_id))

    def _reset_add_track_heading(self) -> None:
        self.add_data_title.setText("Add Track")
        self.add_data_subtitle.setText(
            "Add single-track musical entries here. Every new track must either link to an existing Work or create a new Work from the track before it can be saved."
        )
        self.save_button.setText("Create Work + Save Track")

    def _refresh_work_track_creation_context_ui(self) -> None:
        context_group = getattr(self, "add_data_work_context_group", None)
        mode_combo = getattr(self, "add_data_work_mode_combo", None)
        work_combo = getattr(self, "add_data_work_work_combo", None)
        relationship_combo = getattr(self, "add_data_work_relationship_combo", None)
        parent_combo = getattr(self, "add_data_work_parent_combo", None)
        if (
            context_group is None
            or mode_combo is None
            or work_combo is None
            or relationship_combo is None
            or parent_combo is None
        ):
            return

        context = self._current_work_track_context()
        detail = None
        if context.get("work_id") is not None and self.work_service is not None:
            detail = self.work_service.fetch_work_detail(int(context["work_id"]))

        self._reset_add_track_heading()
        context_group.setVisible(True)

        previous_mode_state = mode_combo.blockSignals(True)
        try:
            mode_combo.clear()
            for value, label in self._work_track_governance_modes():
                mode_combo.addItem(label, value)
            selected_mode_index = mode_combo.findData(str(context.get("mode") or "create_new_work"))
            mode_combo.setCurrentIndex(selected_mode_index if selected_mode_index >= 0 else 0)
        finally:
            mode_combo.blockSignals(previous_mode_state)

        previous_work_state = work_combo.blockSignals(True)
        try:
            work_combo.clear()
            work_combo.addItem("Choose the governing Work…", None)
            for record in self._available_work_records():
                try:
                    work_id = int(getattr(record, "id", 0) or 0)
                except (TypeError, ValueError):
                    continue
                if work_id <= 0:
                    continue
                work_combo.addItem(self._work_choice_label(record), work_id)
            selected_work_id = context.get("work_id")
            if selected_work_id is not None and work_combo.findData(int(selected_work_id)) < 0:
                work_combo.addItem(f"Missing Work #{int(selected_work_id)}", int(selected_work_id))
            selected_work_index = (
                work_combo.findData(int(selected_work_id)) if selected_work_id is not None else 0
            )
            work_combo.setCurrentIndex(selected_work_index if selected_work_index >= 0 else 0)
            work_combo.setEnabled(
                str(context.get("mode")) == "link_existing_work"
                and not bool(context.get("locked_work"))
            )
        finally:
            work_combo.blockSignals(previous_work_state)

        relationship_type = self._normalize_work_track_relationship(
            str(context.get("relationship_type") or "original")
        )
        track_choices: list[tuple[int, str]] = []
        if detail is not None:
            for track_id in detail.track_ids:
                title = str(self._get_track_title(int(track_id)) or "").strip()
                track_choices.append((int(track_id), title or f"Track #{int(track_id)}"))
        valid_parent_track_ids = {track_id for track_id, _title in track_choices}
        parent_track_id = context.get("parent_track_id")
        if parent_track_id not in valid_parent_track_ids:
            parent_track_id = None
        self._pending_work_track_context = {
            "mode": str(context.get("mode") or "create_new_work"),
            "work_id": int(context["work_id"]) if context.get("work_id") is not None else None,
            "relationship_type": relationship_type,
            "parent_track_id": parent_track_id,
            "locked_work": bool(context.get("locked_work")),
            "return_to_work_manager": bool(context.get("return_to_work_manager")),
        }

        if str(context.get("mode")) == "create_new_work":
            self.add_data_work_context_summary.setText(
                "Saving this track will create a new parent Work from the track title, ISWC, and registration number, then link the track immediately as the first governed original."
            )
            self.add_data_work_context_hint.setText(
                "Main artist names resolve through Party records on save. Creating the Work from this panel avoids entering the same shared metadata twice."
            )
            self.save_button.setText("Create Work + Save Track")
        elif detail is None:
            self.add_data_work_context_summary.setText(
                "Choose the existing Work that should govern this track before saving."
            )
            self.add_data_work_context_hint.setText(
                "Use child relationship and optional parent track when this entry is a version, remix, alternate master, or other derivative under an existing Work."
            )
            self.save_button.setText("Save Governed Track")
        else:
            work_title = str(detail.work.title or "").strip() or f"Work #{int(detail.work.id)}"
            relationship_label = self._work_track_relationship_label(relationship_type)
            self.add_data_work_context_summary.setText(
                f"This track will link to Work #{int(detail.work.id)}: {work_title} as {relationship_label}."
            )
            if track_choices:
                self.add_data_work_context_hint.setText(
                    f"{len(track_choices)} linked track{'s' if len(track_choices) != 1 else ''} already sit under this work. "
                    "Choose a parent track when this new recording derives from one of them."
                )
            else:
                self.add_data_work_context_hint.setText(
                    "This Work does not have any linked tracks yet. Saving now will create the first governed track under it."
                )
            self.save_button.setText("Save Governed Track")

        previous_relationship_state = relationship_combo.blockSignals(True)
        try:
            relationship_combo.clear()
            for value in self._work_track_relationship_choices():
                relationship_combo.addItem(self._work_track_relationship_label(value), value)
            selected_relationship_index = relationship_combo.findData(relationship_type)
            relationship_combo.setCurrentIndex(
                selected_relationship_index if selected_relationship_index >= 0 else 0
            )
            relationship_combo.setEnabled(
                str(context.get("mode")) == "link_existing_work"
                and detail is not None
                and relationship_combo.count() > 0
            )
        finally:
            relationship_combo.blockSignals(previous_relationship_state)

        previous_parent_state = parent_combo.blockSignals(True)
        try:
            parent_combo.clear()
            parent_combo.addItem("No direct parent track", None)
            for track_id, title in track_choices:
                parent_combo.addItem(title, int(track_id))
            selected_parent_index = (
                parent_combo.findData(int(parent_track_id)) if parent_track_id is not None else 0
            )
            parent_combo.setCurrentIndex(selected_parent_index if selected_parent_index >= 0 else 0)
            parent_combo.setEnabled(
                str(context.get("mode")) == "link_existing_work" and bool(track_choices)
            )
        finally:
            parent_combo.blockSignals(previous_parent_state)
        self.add_data_clear_work_context_button.setVisible(
            bool(context.get("return_to_work_manager"))
        )

    def _on_add_track_governance_mode_changed(self, _index: int) -> None:
        context = self._current_work_track_context()
        mode = str(self.add_data_work_mode_combo.currentData() or "create_new_work")
        context["mode"] = mode
        if mode == "create_new_work":
            context["work_id"] = None
            context["relationship_type"] = "original"
            context["parent_track_id"] = None
            context["locked_work"] = False
        self._pending_work_track_context = context
        self._refresh_work_track_creation_context_ui()

    def _on_add_track_work_changed(self, _index: int) -> None:
        context = self._current_work_track_context()
        work_id = self.add_data_work_work_combo.currentData()
        try:
            context["work_id"] = int(work_id) if work_id not in (None, "") else None
        except (TypeError, ValueError):
            context["work_id"] = None
        context["parent_track_id"] = None
        self._pending_work_track_context = context
        self._refresh_work_track_creation_context_ui()

    def _on_add_track_relationship_changed(self, _index: int) -> None:
        context = self._current_work_track_context()
        relationship_type = self._normalize_work_track_relationship(
            self.add_data_work_relationship_combo.currentData()
        )
        context["relationship_type"] = relationship_type
        self._pending_work_track_context = context
        self._refresh_work_track_creation_context_ui()

    def _on_add_track_parent_track_changed(self, _index: int) -> None:
        context = self._current_work_track_context()
        parent_track_id = self.add_data_work_parent_combo.currentData()
        try:
            context["parent_track_id"] = (
                int(parent_track_id) if parent_track_id not in (None, "") else None
            )
        except (TypeError, ValueError):
            context["parent_track_id"] = None
        self._pending_work_track_context = context

    def _clear_work_track_creation_context(self) -> None:
        self._pending_work_track_context = self._default_work_track_context()
        self._refresh_work_track_creation_context_ui()

    def _return_from_work_track_creation_context(self) -> None:
        context = self._current_work_track_context()
        work_id = int(context["work_id"]) if context.get("work_id") is not None else None
        self._clear_work_track_creation_context()
        self.clear_form_fields()
        self._apply_add_data_panel_state(False)
        self.open_work_manager(work_id=work_id)

    def open_add_track_entry(self) -> None:
        if self.track_service is None or self.conn is None:
            QMessageBox.warning(self, "Add Track", "Open a profile first.")
            return
        self._apply_add_data_panel_state(True)
        self._set_pending_work_track_context()
        self.clear_form_fields()
        self._refresh_work_track_creation_context_ui()
        self._show_add_track_details_tab()
        self.track_title_field.setFocus()

    def _begin_work_child_track_creation(
        self, work_id: int, *, seed_from_work: bool = True
    ) -> bool:
        if self.work_service is None:
            QMessageBox.warning(self, "Work Manager", "Open a profile first.")
            return False
        detail = self.work_service.fetch_work_detail(int(work_id))
        if detail is None:
            QMessageBox.warning(self, "Work Manager", "The selected work could not be loaded.")
            return False
        current_context = self._current_work_track_context()
        relationship_type = (
            str(current_context.get("relationship_type") or "original")
            if int(current_context.get("work_id") or 0) == int(work_id)
            else "original"
        )
        parent_track_id = (
            current_context.get("parent_track_id")
            if int(current_context.get("work_id") or 0) == int(work_id)
            else None
        )
        self._pending_work_track_context = {
            "mode": "link_existing_work",
            "work_id": int(work_id),
            "relationship_type": self._normalize_work_track_relationship(relationship_type),
            "parent_track_id": parent_track_id,
            "locked_work": False,
            "return_to_work_manager": True,
        }
        self._apply_add_data_panel_state(True)
        self.clear_form_fields()
        if seed_from_work:
            if str(detail.work.title or "").strip():
                self.track_title_field.setText(str(detail.work.title or "").strip())
                self.track_title_field.selectAll()
            if str(detail.work.iswc or "").strip():
                self.iswc_field.setText(str(detail.work.iswc or "").strip())
        self._refresh_work_track_creation_context_ui()
        self._focus_work_in_manager(int(work_id))
        self.track_title_field.setFocus()
        return True

    def clear_form_fields(self):
        self.artist_field.setCurrentText("")
        self.additional_artist_field.setCurrentText("")
        self.track_title_field.clear()
        self.album_title_field.setCurrentText("")
        if hasattr(self, "track_number_field"):
            self.track_number_field.setValue(1)
        self.audio_file_field.clear()
        self.album_art_field.clear()
        self.release_date_field.setSelectedDate(QDate.currentDate())
        self.iswc_field.clear()
        self.upc_field.setCurrentText("")
        self.catalog_number_field.setCurrentText("")
        self.buma_work_number_field.clear()
        self.genre_field.setCurrentText("")
        self.prev_release_toggle.setChecked(False)
        self._update_add_data_generated_fields()

    # =============================================================================
    # Search / table refresh (with view preservation)
    # =============================================================================
    def _rebuild_search_column_choices(self):
        cur_data = (
            self.search_column_combo.currentData() if self.search_column_combo.count() else -1
        )
        self.search_column_combo.blockSignals(True)
        self.search_column_combo.clear()
        self.search_column_combo.addItem("All columns", -1)

        model = self.table.model()
        column_count = model.columnCount() if model is not None else 0
        for idx in range(column_count):
            if self.table.isColumnHidden(idx):
                continue
            name = str(model.headerData(idx, Qt.Horizontal, Qt.DisplayRole) or "")
            if not name:
                continue
            column_key = str(model.headerData(idx, Qt.Horizontal, ColumnKeyRole) or "")
            self.search_column_combo.addItem(name, column_key or idx)

        restore = self.search_column_combo.findData(cur_data)
        self.search_column_combo.setCurrentIndex(restore if restore != -1 else 0)
        self.search_column_combo.blockSignals(False)

    def _selected_search_column_key(self) -> str | None:
        data = self.search_column_combo.currentData()
        if data in (-1, None, ""):
            return None
        if isinstance(data, str):
            return data
        try:
            logical_index = int(data)
        except (TypeError, ValueError):
            return None
        model = self.table.model()
        if model is None or logical_index < 0 or logical_index >= model.columnCount():
            return None
        return str(model.headerData(logical_index, Qt.Horizontal, ColumnKeyRole) or "") or None

    def _apply_catalog_search_filter(self):
        proxy = self._catalog_proxy_model()
        if proxy is not None:
            proxy.set_search_text(self.search_field.text())
            proxy.set_search_column_key(self._selected_search_column_key())
            proxy.set_explicit_track_ids(getattr(self, "_explicit_row_filter_track_ids", None))
        self._sync_catalog_count_label()
        self._sync_catalog_duration_label()
        self._refresh_workspace_selection_scopes()

    # =============================================================================
    # Header label helpers for robust persistence (rev09)
    # =============================================================================
    def _header_labels(self):
        m = self.table.model()
        return [
            str(m.headerData(c, Qt.Horizontal, Qt.DisplayRole) or "")
            for c in range(m.columnCount())
        ]

    def _labels_with_occurrence(self, labels):
        seen = {}
        out = []
        for lbl in labels:
            n = seen.get(lbl, 0)
            out.append((lbl, n))
            seen[lbl] = n + 1
        return out

    def reset_search(self):
        self._explicit_row_filter_track_ids = None
        self.search_field.blockSignals(True)
        self.search_field.clear()
        self.search_field.blockSignals(False)
        self.search_column_combo.blockSignals(True)
        idx = self.search_column_combo.findData(-1)  # “All columns”
        self.search_column_combo.setCurrentIndex(idx if idx != -1 else 0)
        self.search_column_combo.blockSignals(False)
        self._apply_catalog_search_filter()

    def _set_catalog_filter_text(self, filter_text: str) -> None:
        clean_text = str(filter_text or "")
        self.search_field.setText(clean_text)

    def _set_catalog_filter_from_current_cell(self) -> None:
        table = getattr(self, "table", None)
        if table is None:
            return
        index = table.currentIndex()
        if not index.isValid():
            selection_model = table.selectionModel()
            selected_indexes = (
                selection_model.selectedIndexes() if selection_model is not None else []
            )
            index = selected_indexes[0] if selected_indexes else index
        if not index.isValid():
            return
        self._set_catalog_filter_text(str(index.data(Qt.DisplayRole) or ""))

    def _load_catalog_ui_dataset(
        self,
        *,
        custom_field_definitions: CustomFieldDefinitionService | None = None,
        catalog_reads: CatalogReadService | None = None,
        track_service: TrackService | None = None,
        custom_field_values: CustomFieldValueService | None = None,
        conn: sqlite3.Connection | None = None,
        progress_callback=None,
    ) -> dict[str, object]:
        active_custom_fields = (
            custom_field_definitions.list_active_fields()
            if custom_field_definitions is not None
            else self.load_active_custom_fields()
        )
        if callable(progress_callback):
            progress_callback(
                6,
                100,
                f"Loaded {len(active_custom_fields)} active custom fields.",
            )
        active_catalog_reads = catalog_reads or self.catalog_reads
        active_conn = conn or self.conn
        if active_catalog_reads is None or active_conn is None:
            raise ValueError("Catalog dataset services are not available.")
        rows, cf_map = active_catalog_reads.fetch_rows_with_customs(
            active_custom_fields,
            progress_callback=(
                self._scaled_progress_callback(
                    progress_callback,
                    start=10,
                    end=44,
                )
                if callable(progress_callback)
                else None
            ),
        )
        track_ids = [int(row[0]) for row in rows if row and row[0] is not None]
        blob_badges = active_catalog_reads.fetch_blob_badge_payload(
            track_ids,
            active_custom_fields,
            track_service=track_service or self.track_service,
            custom_field_values=custom_field_values or self.custom_field_values,
            progress_callback=(
                self._scaled_progress_callback(
                    progress_callback,
                    start=46,
                    end=64,
                )
                if callable(progress_callback)
                else None
            ),
        )
        combo_values = self._catalog_combo_values_from_connection(
            active_conn,
            progress_callback=(
                self._scaled_progress_callback(
                    progress_callback,
                    start=68,
                    end=84,
                )
                if callable(progress_callback)
                else None
            ),
        )
        if callable(progress_callback):
            progress_callback(88, 100, f"Prepared catalog dataset with {len(rows)} rows.")
        return {
            "active_custom_fields": active_custom_fields,
            "rows": rows,
            "cf_map": cf_map,
            "blob_badges": blob_badges,
            "combo_values": combo_values,
        }

    def _sort_value_for_catalog_cell(
        self,
        *,
        header_text: str,
        display_text: str,
        raw_value,
        custom_def: dict[str, object] | None = None,
    ):
        text = str(display_text or "")
        try:
            if header_text == "ID":
                return int(raw_value if raw_value not in (None, "") else text)
            if header_text == "Track Length (hh:mm:ss)":
                return int(raw_value or parse_hms_text(text))
            if header_text in ("Entry Date", "Release Date"):
                return int(text.replace("-", "")) if text else 0
            if custom_def and custom_def.get("field_type") == "date":
                return int(text.replace("-", "")) if text else 0
            if custom_def and custom_def.get("field_type") == "checkbox":
                return 1 if text.lower() in ("1", "true", "yes", "y", "checked") else 0
            return float(text) if "." in text else int(text)
        except Exception:
            return text

    def _catalog_cell_value(
        self,
        value,
        *,
        header_text: str,
        display_text: str | None = None,
        custom_def: dict[str, object] | None = None,
        tooltip: str | None = None,
    ) -> CatalogCellValue:
        resolved_display = "" if value is None else str(value)
        if display_text is not None:
            resolved_display = str(display_text)
        return CatalogCellValue(
            display_text=resolved_display,
            sort_value=self._sort_value_for_catalog_cell(
                header_text=header_text,
                display_text=resolved_display,
                raw_value=value,
                custom_def=custom_def,
            ),
            search_text=resolved_display,
            raw_value=value,
            tooltip=tooltip,
        )

    def _media_badge_cell_value(
        self,
        meta: dict[str, object] | None,
        *,
        track_id: int,
        header_text: str,
        media_key: str | None = None,
        field: dict[str, object] | None = None,
    ) -> CatalogCellValue:
        meta = dict(meta or {})
        has_payload = bool(meta.get("has_media") or meta.get("has_blob"))
        display = (
            self._format_blob_badge(meta.get("mime_type"), meta.get("size_bytes", 0))
            if has_payload
            else "—"
        )
        tooltip = ""
        raw_value = ""
        icon = None
        decoration_key = None
        if has_payload and media_key:
            kind = self._blob_icon_kind_for_standard_media(media_key, meta=meta)
            tooltip = self._standard_media_badge_tooltip(media_key, meta, display)
            raw_value = (int(track_id), media_key)
            icon = self._resolve_blob_badge_icon(
                spec=self._blob_icon_spec_for_standard_media(media_key, meta=meta),
                kind=kind,
            )
            decoration_key = kind
        elif has_payload and field is not None:
            field_type = str(field.get("field_type") or "").strip().lower()
            kind = self._blob_icon_kind_for_storage(
                "audio" if field_type == "blob_audio" else "image",
                storage_mode=meta.get("storage_mode"),
            )
            tooltip = (
                f"{describe_blob_icon_spec(field.get('blob_icon_payload'), kind=kind, allow_inherit=True)}\n"
                f"{self._storage_mode_badge_label(meta.get('storage_mode'))}\n"
                f"Stored size: {display}"
            )
            raw_value = (int(track_id), int(field["id"]))
            icon = self._resolve_blob_badge_icon(
                spec=self._blob_icon_spec_for_custom_field_with_meta(field, meta=meta),
                kind=kind,
            )
            decoration_key = kind
        return CatalogCellValue(
            display_text=display,
            sort_value=display,
            search_text=display if has_payload else "",
            raw_value=raw_value,
            tooltip=tooltip or None,
            decoration_key=decoration_key,
            decoration=icon,
        )

    def _catalog_snapshot_from_dataset(
        self,
        rows: list[tuple],
        cf_map: dict[tuple[int, int], str],
        *,
        blob_badges: dict[str, object] | None = None,
        progress_callback=None,
    ) -> CatalogSnapshot:
        column_specs = self._catalog_table_column_specs_for_fields(self.active_custom_fields)
        standard_meta = dict((blob_badges or {}).get("standard_media") or {})
        custom_meta = dict((blob_badges or {}).get("custom_fields") or {})
        base_cols = len(self.BASE_HEADERS)
        snapshot_rows: list[CatalogRowSnapshot] = []
        total_rows = len(rows)
        if total_rows <= 0:
            if callable(progress_callback):
                progress_callback(1, 1, "No catalog rows needed to be applied.")
            return CatalogSnapshot(column_specs=column_specs, rows=())
        batch_size = max(1, min(100, total_rows // 20 or 1))

        for row_idx, row_data in enumerate(rows):
            track_id = int(row_data[0])
            cells_by_key: dict[str, CatalogCellValue] = {}
            for col_idx in range(base_cols):
                column_spec = column_specs[col_idx]
                header = column_spec.header_text
                val_raw = row_data[col_idx]
                if header == "Track Length (hh:mm:ss)":
                    secs = 0
                    try:
                        secs = int(val_raw or 0)
                    except Exception:
                        secs = parse_hms_text(str(val_raw))
                    cells_by_key[column_spec.key] = self._catalog_cell_value(
                        secs,
                        header_text=header,
                        display_text=seconds_to_hms(secs),
                    )
                elif header in self._standard_media_header_map():
                    media_key = self._standard_media_key_for_header(header)
                    cells_by_key[column_spec.key] = self._media_badge_cell_value(
                        standard_meta.get((track_id, media_key)),
                        track_id=track_id,
                        header_text=header,
                        media_key=media_key,
                    )
                else:
                    cells_by_key[column_spec.key] = self._catalog_cell_value(
                        val_raw,
                        header_text=header,
                    )

            for offset, field in enumerate(self.active_custom_fields):
                column_spec = column_specs[base_cols + offset]
                field_type = str(field.get("field_type") or "").strip().lower()
                if field_type in ("blob_image", "blob_audio"):
                    cells_by_key[column_spec.key] = self._media_badge_cell_value(
                        custom_meta.get((track_id, int(field["id"]))),
                        track_id=track_id,
                        header_text=column_spec.header_text,
                        field=field,
                    )
                else:
                    val = cf_map.get((track_id, field["id"]), "")
                    cells_by_key[column_spec.key] = self._catalog_cell_value(
                        val,
                        header_text=column_spec.header_text,
                        custom_def=field,
                    )
            snapshot_rows.append(CatalogRowSnapshot(track_id=track_id, cells_by_key=cells_by_key))
            if callable(progress_callback) and (
                row_idx == total_rows - 1 or ((row_idx + 1) % batch_size) == 0
            ):
                progress_callback(
                    row_idx + 1,
                    total_rows,
                    f"Applied {row_idx + 1} of {total_rows} catalog rows.",
                )
        return CatalogSnapshot(column_specs=column_specs, rows=tuple(snapshot_rows))

    def _apply_catalog_model_dataset(
        self,
        dataset: dict[str, object],
        *,
        progress_callback=None,
    ) -> None:
        self.active_custom_fields = list(dataset.get("active_custom_fields") or [])
        self._rebuild_table_headers()
        if callable(progress_callback):
            progress_callback(76, 100, "Rebuilt catalog table headers.")
        snapshot = self._catalog_snapshot_from_dataset(
            list(dataset.get("rows") or []),
            dict(dataset.get("cf_map") or {}),
            blob_badges=dict(dataset.get("blob_badges") or {}),
            progress_callback=(
                self._scaled_progress_callback(
                    progress_callback,
                    start=78,
                    end=90,
                )
                if callable(progress_callback)
                else None
            ),
        )
        source_model = self._catalog_source_model()
        if source_model is not None:
            source_model.set_snapshot(snapshot)
        self._apply_catalog_search_filter()
        self._apply_catalog_combo_values(dict(dataset.get("combo_values") or {}))
        if callable(progress_callback):
            progress_callback(91, 100, "Applied catalog lookup values.")
        self.table.resizeColumnsToContents()
        if callable(progress_callback):
            progress_callback(93, 100, "Resized catalog table columns.")
        self._sync_catalog_count_label()
        self._sync_catalog_duration_label()
        if callable(progress_callback):
            progress_callback(95, 100, "Updated catalog counts and duration.")
        if callable(progress_callback):
            progress_callback(98, 100, "Applied prepared media badges to catalog model.")

    def _capture_catalog_refresh_request(
        self,
        *,
        focus_id: int | None = None,
        select_path: str | None = None,
    ) -> dict[str, object]:
        return {
            "view_state": self._capture_view_state(),
            "sort_enabled": bool(self.table.isSortingEnabled()),
            "focus_id": int(focus_id) if focus_id is not None else None,
            "select_path": str(select_path) if select_path else None,
        }

    def _load_catalog_ui_dataset_from_bundle(
        self,
        bundle,
        ctx,
        *,
        progress_start: int,
        progress_end: int,
    ) -> dict[str, object]:
        return self._load_catalog_ui_dataset(
            custom_field_definitions=bundle.custom_field_definitions,
            catalog_reads=bundle.catalog_reads,
            track_service=bundle.track_service,
            custom_field_values=bundle.custom_field_values,
            conn=bundle.conn,
            progress_callback=self._scaled_progress_callback(
                ctx.report_progress,
                start=progress_start,
                end=progress_end,
            ),
        )

    def _apply_catalog_refresh_request(
        self,
        dataset: dict[str, object],
        refresh_request: dict[str, object],
        *,
        progress_callback=None,
        refresh_history_actions: bool = True,
        refresh_add_track_controls: bool = True,
    ) -> None:
        state = dict(refresh_request.get("view_state") or {})
        sort_enabled = bool(refresh_request.get("sort_enabled"))
        focus_id = refresh_request.get("focus_id")
        select_path = refresh_request.get("select_path")
        current_sort_enabled = bool(self.table.isSortingEnabled())

        with self._suspend_table_layout_history():
            with self._suspend_catalog_view_updates():
                if current_sort_enabled:
                    self.table.setSortingEnabled(False)

                self._apply_catalog_model_dataset(
                    dataset,
                    progress_callback=(
                        self._scaled_progress_callback(
                            progress_callback,
                            start=0,
                            end=74,
                        )
                        if callable(progress_callback)
                        else None
                    ),
                )

                if callable(progress_callback):
                    progress_callback(76, 100, "Restoring saved catalog headers and view state...")
                try:
                    self._load_header_state()
                except Exception as exc:
                    self.logger.warning("Failed to load header state: %s", exc)

                self._restore_view_state(state)
                if focus_id is not None:
                    self._select_row_by_id(int(focus_id))
                if select_path:
                    self._reload_profiles_list(select_path=str(select_path))
                if sort_enabled:
                    self.table.setSortingEnabled(True)
                    self._sort_catalog_table(
                        state.get("sort_col", 0),
                        state.get("sort_order", Qt.AscendingOrder),
                    )
                elif current_sort_enabled:
                    self.table.setSortingEnabled(True)

                if callable(progress_callback):
                    progress_callback(90, 100, "Refreshing generated fields and history state...")
                self._update_add_data_generated_fields()
                if refresh_history_actions:
                    self._refresh_history_actions()

                if refresh_add_track_controls:
                    if callable(progress_callback):
                        progress_callback(96, 100, "Refreshing add-track governance controls...")
                    self._refresh_add_track_artist_party_choices()
                    self._refresh_work_track_creation_context_ui()
            self._flush_pending_catalog_repaints(
                progress_callback=progress_callback,
                value=98,
                maximum=100,
                message="Painting refreshed catalog icons and widgets...",
            )

    @contextmanager
    def _suspend_catalog_view_updates(self):
        table = getattr(self, "table", None)
        widgets: list[QWidget] = []
        for candidate in (
            table,
            getattr(table, "viewport", lambda: None)(),
            getattr(table, "horizontalHeader", lambda: None)(),
            getattr(getattr(table, "horizontalHeader", lambda: None)(), "viewport", lambda: None)(),
            getattr(table, "verticalHeader", lambda: None)(),
            getattr(getattr(table, "verticalHeader", lambda: None)(), "viewport", lambda: None)(),
        ):
            if isinstance(candidate, QWidget):
                widgets.append(candidate)

        previous_states: list[tuple[QWidget, bool]] = []
        for widget in widgets:
            try:
                previous_states.append((widget, widget.updatesEnabled()))
            except Exception:
                continue
        for widget, _previous_state in previous_states:
            try:
                widget.setUpdatesEnabled(False)
            except Exception:
                continue
        try:
            yield
        finally:
            for widget, previous_state in previous_states:
                try:
                    widget.setUpdatesEnabled(previous_state)
                    widget.updateGeometry()
                    widget.update()
                except Exception:
                    continue

    def _catalog_repaint_targets(self) -> list[QWidget]:
        seen: set[int] = set()
        targets: list[QWidget] = []

        def _add_target(widget) -> None:
            if not isinstance(widget, QWidget):
                return
            widget_id = id(widget)
            if widget_id in seen:
                return
            seen.add(widget_id)
            targets.append(widget)

        _add_target(self)
        _add_target(self.centralWidget())
        _add_target(self.table)
        try:
            _add_target(self.table.viewport())
        except Exception:
            pass
        try:
            header = self.table.horizontalHeader()
            _add_target(header)
            _add_target(header.viewport())
        except Exception:
            pass
        try:
            header = self.table.verticalHeader()
            _add_target(header)
            _add_target(header.viewport())
        except Exception:
            pass
        try:
            _add_target(self.statusBar())
        except Exception:
            pass
        for dock in self.findChildren(QDockWidget):
            _add_target(dock)
            try:
                _add_target(dock.widget())
            except Exception:
                continue
        return targets

    def _flush_pending_catalog_repaints(
        self,
        *,
        progress_callback=None,
        value: int | None = None,
        maximum: int | None = None,
        message: str = "Painting refreshed catalog icons and widgets...",
        passes: int = 3,
    ) -> None:
        if callable(progress_callback):
            progress_callback(value, maximum, message)
        app = QApplication.instance()
        if app is None:
            return
        targets = self._catalog_repaint_targets()
        for _ in range(max(1, int(passes))):
            for widget in targets:
                try:
                    if not widget.isVisible():
                        continue
                except Exception:
                    continue
                try:
                    widget.updateGeometry()
                except Exception:
                    pass
                try:
                    widget.update()
                except Exception:
                    pass
            try:
                app.processEvents()
            except Exception:
                pass
            if QCoreApplication is not None:
                for event_type in (
                    int(QEvent.LayoutRequest),
                    int(QEvent.UpdateRequest),
                    int(QEvent.Paint),
                    int(QEvent.DeferredDelete),
                ):
                    try:
                        QCoreApplication.sendPostedEvents(None, event_type)
                    except Exception:
                        continue
            for widget in targets:
                try:
                    if widget.isVisible():
                        widget.repaint()
                except Exception:
                    continue
            try:
                app.processEvents()
            except Exception:
                pass

    def _refresh_catalog_ui_in_background(
        self,
        *,
        focus_id: int | None = None,
        select_path: str | None = None,
        show_dialog: bool = False,
        on_finished=None,
        on_complete=None,
        unique_key: str = "catalog.ui.refresh",
        retry_count: int = 0,
        progress_callback=None,
    ) -> str | None:
        if self.conn is None:
            if on_complete is not None:
                on_complete()
            return None
        refresh_request = self._capture_catalog_refresh_request(
            focus_id=focus_id,
            select_path=select_path,
        )
        if bool(refresh_request.get("sort_enabled")):
            self.table.setSortingEnabled(False)
        self._clear_catalog_table_model()
        self._sync_catalog_count_label()
        self._sync_catalog_duration_label()
        completion_notified = False

        def _notify_complete() -> None:
            nonlocal completion_notified
            if completion_notified:
                return
            completion_notified = True
            if on_complete is not None:
                on_complete()

        def _worker(bundle, ctx):
            ctx.set_status("Loading catalog rows, media badges, and lookup values...")
            return self._load_catalog_ui_dataset_from_bundle(
                bundle,
                ctx,
                progress_start=0,
                progress_end=74,
            )

        def _before_cleanup(dataset: dict[str, object], ui_progress):
            try:
                self.conn.commit()
            except Exception:
                pass
            self._apply_catalog_refresh_request(
                dataset,
                refresh_request,
                progress_callback=self._scaled_ui_progress_callback(
                    ui_progress,
                    start=76,
                    end=99,
                ),
            )
            self._advance_task_ui_progress(
                ui_progress,
                value=100,
                message="Catalog view fully restored and ready.",
            )
            if on_finished is not None:
                on_finished()

        def _after_cleanup(_dataset: dict[str, object]) -> None:
            _notify_complete()

        def _finished():
            if not bool(refresh_request.get("sort_enabled")):
                self.table.setSortingEnabled(False)

        def _handle_error(failure: TaskFailure) -> None:
            retry_message = str(failure.message or "").lower()
            if retry_count < 3 and "exclusive database task is currently running" in retry_message:
                QTimer.singleShot(
                    100,
                    lambda: self._refresh_catalog_ui_in_background(
                        focus_id=focus_id,
                        select_path=select_path,
                        show_dialog=show_dialog,
                        on_finished=on_finished,
                        on_complete=on_complete,
                        unique_key=unique_key,
                        retry_count=retry_count + 1,
                    ),
                )
                return
            try:
                self._show_background_task_error(
                    "Load Catalog",
                    failure,
                    user_message="Could not load the catalog view:",
                )
            finally:
                _notify_complete()

        task_id = self._submit_background_bundle_task(
            title="Load Catalog",
            description="Loading catalog rows, media badges, and lookup values...",
            task_fn=_worker,
            kind="read",
            unique_key=unique_key,
            show_dialog=show_dialog,
            owner=self,
            on_success_before_cleanup=_before_cleanup,
            on_success_after_cleanup=_after_cleanup,
            on_error=_handle_error,
            on_finished=_finished,
            on_progress=(
                (lambda update: progress_callback(update.value, update.maximum, update.message))
                if callable(progress_callback)
                else None
            ),
        )
        if task_id is None:
            _notify_complete()
        return task_id

    def refresh_table(self):
        # Ensure custom fields and headers are ready
        dataset = self._load_catalog_ui_dataset()

        previous_suspend_state = self._suspend_layout_history
        self._suspend_layout_history = True
        try:
            _prev_sort_enabled = self.table.isSortingEnabled()
            header = self.table.horizontalHeader()
            sort_col = header.sortIndicatorSection()
            sort_order = header.sortIndicatorOrder()
            if _prev_sort_enabled:
                self.table.setSortingEnabled(False)
            self._clear_catalog_table_model()
            self._apply_catalog_model_dataset(dataset)
            self.table.setSortingEnabled(_prev_sort_enabled)
            if _prev_sort_enabled:
                self._sort_catalog_table(sort_col, sort_order)
        finally:
            self._suspend_layout_history = previous_suspend_state

    def _clear_catalog_table_model(self) -> None:
        source_model = self._catalog_source_model()
        if source_model is not None:
            source_model.set_snapshot(
                CatalogSnapshot(column_specs=self._catalog_table_column_specs_for_fields(), rows=())
            )
        proxy = self._catalog_proxy_model()
        if proxy is not None:
            proxy.set_explicit_track_ids(getattr(self, "_explicit_row_filter_track_ids", None))

    def _sort_catalog_table(self, column: int | None, order: Qt.SortOrder) -> None:
        try:
            sort_column = int(column if column is not None else 0)
        except (TypeError, ValueError):
            sort_column = 0
        if 0 <= sort_column < self._catalog_view_column_count():
            self.table.sortByColumn(sort_column, order)

    def _sync_catalog_count_label(self):
        # updates 'showing: N records'
        if not hasattr(self, "count_label") or self.count_label is None:
            return
        visible = self.table.model().rowCount() if self.table.model() is not None else 0
        self.count_label.setText(f"showing: {visible} record{'s' if visible != 1 else ''}")

    def _sync_catalog_duration_label(self):
        if not hasattr(self, "duration_label") or self.duration_label is None:
            return
        col_idx = self._catalog_table_controller().column_for_key("base:track_length_sec")
        if col_idx is None:
            col_idx = -1
        if col_idx == -1:
            self.duration_label.setText("")
            return
        total_sec = 0
        try:
            for r in range(self._catalog_view_row_count()):
                index = self.table.model().index(r, col_idx)
                v = self.table.model().data(index, RawValueRole)
                if isinstance(v, (int, float)):
                    total_sec += int(v)
                else:
                    total_sec += parse_hms_text(str(self.table.model().data(index) or ""))
        except Exception:
            pass
        self.duration_label.setText(f"total: {seconds_to_hms(total_sec)}")

    # --- Preserve view wrapper ---
    def _capture_view_state(self):
        hh = self.table.horizontalHeader()
        state = {
            "filter_text": self.search_field.text(),
            "search_column_data": self.search_column_combo.currentData(),
            "sort_col": hh.sortIndicatorSection(),
            "sort_order": hh.sortIndicatorOrder(),
            "v_scroll": self.table.verticalScrollBar().value(),
            "h_scroll": self.table.horizontalScrollBar().value(),
            "selected_track_ids": list(self._catalog_table_controller().selected_track_ids()),
            "current_track_id": self._catalog_table_controller().current_track_id(),
        }
        return state

    def _restore_view_state(self, state):
        filter_text = str(state.get("filter_text") or "")
        search_field_state = self.search_field.blockSignals(True)
        try:
            self.search_field.setText(filter_text)
        finally:
            self.search_field.blockSignals(search_field_state)

        search_column_data = state.get("search_column_data", -1)
        search_column_state = self.search_column_combo.blockSignals(True)
        try:
            column_index = self.search_column_combo.findData(search_column_data)
            if column_index < 0:
                column_index = self.search_column_combo.findData(-1)
            self.search_column_combo.setCurrentIndex(column_index if column_index >= 0 else 0)
        finally:
            self.search_column_combo.blockSignals(search_column_state)

        sort_col = state.get("sort_col", 0)
        sort_order = state.get("sort_order", Qt.AscendingOrder)
        self._sort_catalog_table(sort_col, sort_order)
        self._apply_catalog_search_filter()
        selected_track_ids = self._normalize_track_ids(state.get("selected_track_ids") or [])
        if selected_track_ids:
            self._select_track_ids_in_table(selected_track_ids)
        current_track_id = state.get("current_track_id")
        if current_track_id is not None:
            self._select_row_by_id(int(current_track_id))
        self.table.verticalScrollBar().setValue(state.get("v_scroll", 0))
        self.table.horizontalScrollBar().setValue(state.get("h_scroll", 0))

    def _select_row_by_id(self, focus_id: int):
        controller = self._catalog_table_controller()
        index = controller.view_index_for_track_id(int(focus_id), column=0)
        if not index.isValid():
            return
        self.table.setCurrentIndex(index)
        selection_model = self.table.selectionModel()
        if selection_model is not None:
            selection_model.select(
                index, QItemSelectionModel.ClearAndSelect | QItemSelectionModel.Rows
            )
        self.table.scrollTo(index, QAbstractItemView.PositionAtCenter)

    def refresh_table_preserve_view(self, focus_id: int | None = None):
        with self._suspend_table_layout_history():
            _prev_sort_enabled = self.table.isSortingEnabled()
            if _prev_sort_enabled:
                self.table.setSortingEnabled(False)

            # Capture current viewport
            state = self._capture_view_state()

            # Refresh schema + headers
            self.active_custom_fields = self.load_active_custom_fields()
            self._rebuild_table_headers()

            # Always rebind first (safe if duplicated)
            try:
                self._bind_header_state_signals()
            except Exception as e:
                self.logger.warning("Failed to rebind sectionMoved: %s", e)

            # Then load header state (visual order + widths)
            try:
                self._load_header_state()
            except Exception as e:
                self.logger.warning("Failed to load header state: %s", e)

            # Refresh data and restore view state
            self.refresh_table()
            self._restore_view_state(state)
            self._sync_catalog_count_label()

            if focus_id is not None:
                self._select_row_by_id(focus_id)

            # Restore sorting after refresh
            if _prev_sort_enabled:
                self.table.setSortingEnabled(True)
                self._sort_catalog_table(
                    state.get("sort_col", 0),
                    state.get("sort_order", Qt.AscendingOrder),
                )

    # =============================================================================
    # Relational helpers
    # =============================================================================

    def get_or_create_artist(self, name: str) -> int:
        return self.track_service.get_or_create_artist(name, cursor=self.cursor)

    def get_or_create_album(self, title: str) -> int | None:
        return self.track_service.get_or_create_album(title, cursor=self.cursor)

    @staticmethod
    def _parse_additional_artists(s: str):
        return TrackService.parse_additional_artists(s)

    @staticmethod
    def _media_file_filter(media_key: str) -> str:
        if media_key == "audio_file":
            return "Audio (*.wav *.aif *.aiff *.mp3 *.flac *.m4a *.aac *.ogg *.opus);;All files (*)"
        return "Images (*.png *.jpg *.jpeg *.webp *.gif *.bmp *.tif *.tiff);;All files (*)"

    @staticmethod
    def _audio_format_label(suffix: str | None) -> str:
        labels = {
            ".aac": "AAC",
            ".aif": "AIFF",
            ".aiff": "AIFF",
            ".flac": "FLAC",
            ".m4a": "M4A",
            ".mp3": "MP3",
            ".mp4": "MP4",
            ".oga": "OGA",
            ".ogg": "OGG",
            ".opus": "Opus",
            ".wav": "WAV",
        }
        clean_suffix = str(suffix or "").strip().lower()
        if clean_suffix in labels:
            return labels[clean_suffix]
        if clean_suffix.startswith(".") and len(clean_suffix) > 1:
            return clean_suffix[1:].upper()
        return "audio"

    @classmethod
    def _lossy_audio_suffix_for_values(
        cls,
        *,
        path_value: str | None = None,
        filename: str | None = None,
        mime_type: str | None = None,
    ) -> str | None:
        for candidate in (filename, path_value):
            clean_candidate = str(candidate or "").strip()
            if not clean_candidate:
                continue
            suffix = Path(clean_candidate).suffix.lower()
            if suffix in PROVENANCE_ONLY_SUFFIXES:
                return suffix
        clean_mime = str(mime_type or "").strip().lower()
        mime_suffixes = {
            "audio/aac": ".aac",
            "audio/mp4": ".m4a",
            "audio/mpeg": ".mp3",
            "audio/ogg": ".ogg",
            "audio/opus": ".opus",
            "video/mp4": ".mp4",
        }
        return mime_suffixes.get(clean_mime)

    @classmethod
    def _lossy_primary_audio_warning_text(
        cls,
        *,
        path_value: str | None = None,
        filename: str | None = None,
        mime_type: str | None = None,
        short: bool = False,
    ) -> str:
        suffix = cls._lossy_audio_suffix_for_values(
            path_value=path_value,
            filename=filename,
            mime_type=mime_type,
        )
        if not suffix:
            return ""
        format_label = cls._audio_format_label(suffix)
        if short:
            return f"Lossy primary audio selected ({format_label})."
        return (
            f"Lossy primary audio selected ({format_label}). Direct watermark and master-audio "
            "workflows use WAV, FLAC, or AIFF, so this attachment will be treated as a lossy "
            "primary source."
        )

    @staticmethod
    def _set_lossy_audio_warning_label(label: QLabel | None, warning_text: str) -> None:
        if label is None:
            return
        label.setText(warning_text)
        label.setVisible(bool(warning_text))

    def _refresh_line_edit_lossy_audio_warning(self, line_edit: QLineEdit) -> None:
        warning_label = getattr(line_edit, "_lossy_audio_warning_label", None)
        warning_text = self._lossy_primary_audio_warning_text(
            path_value=line_edit.text(),
            short=True,
        )
        self._set_lossy_audio_warning_label(warning_label, warning_text)

    def _confirm_lossy_primary_audio_selection(
        self,
        values,
        *,
        title: str,
        action_label: str,
        parent_widget: QWidget | None = None,
    ) -> bool:
        entries: list[str] = []
        for value in values or []:
            clean_value = str(value or "").strip()
            suffix = self._lossy_audio_suffix_for_values(path_value=clean_value)
            if not clean_value or not suffix:
                continue
            name = Path(clean_value).name or clean_value
            entries.append(f"{name} ({self._audio_format_label(suffix)})")
        if not entries:
            return True
        extra_note = "" if len(entries) <= 8 else f"\n…and {len(entries) - 8} more."
        message = (
            f"{action_label} will keep {len(entries)} lossy audio file"
            f"{'s' if len(entries) != 1 else ''} as primary catalog audio.\n\n"
            "Lossy primary audio is shown with the lossy badge, and direct watermark/master "
            "workflows use WAV, FLAC, or AIFF.\n\n"
            "Continue?\n\n- " + "\n- ".join(entries[:8]) + extra_note
        )
        return (
            QMessageBox.question(
                parent_widget or self,
                title,
                message,
                QMessageBox.Yes | QMessageBox.No,
            )
            == QMessageBox.Yes
        )

    def _browse_track_media_file(self, media_key: str, *, parent_widget=None) -> str:
        title = "Choose Audio File" if media_key == "audio_file" else "Choose Album Art"
        path, _ = QFileDialog.getOpenFileName(
            parent_widget or self,
            title,
            "",
            self._media_file_filter(media_key),
        )
        return path or ""

    @staticmethod
    def _set_track_length_widgets(
        hours_widget,
        minutes_widget,
        seconds_widget,
        total_seconds: int,
    ) -> None:
        normalized_seconds = max(0, int(total_seconds or 0))
        hours = min(99, normalized_seconds // 3600)
        minutes = (normalized_seconds % 3600) // 60
        seconds = normalized_seconds % 60
        for widget, value in (
            (hours_widget, hours),
            (minutes_widget, minutes),
            (seconds_widget, seconds),
        ):
            previous_state = widget.blockSignals(True)
            try:
                widget.setValue(int(value))
            finally:
                widget.blockSignals(previous_state)

    def _apply_audio_duration_to_widgets(
        self,
        source_path: str | Path | None,
        *,
        hours_widget,
        minutes_widget,
        seconds_widget,
    ) -> int | None:
        if self.track_service is None:
            return None
        duration_seconds = self.track_service.derive_audio_duration_seconds(source_path)
        if duration_seconds is None:
            return None
        self._set_track_length_widgets(
            hours_widget,
            minutes_widget,
            seconds_widget,
            int(duration_seconds),
        )
        return int(duration_seconds)

    def _choose_media_into_line_edit(
        self,
        media_key: str,
        line_edit: QLineEdit,
        *,
        parent_widget=None,
        hours_widget=None,
        minutes_widget=None,
        seconds_widget=None,
    ) -> None:
        path = self._browse_track_media_file(media_key, parent_widget=parent_widget)
        if path:
            line_edit.setText(path)
            if media_key == "audio_file":
                self._refresh_line_edit_lossy_audio_warning(line_edit)
                if (
                    hours_widget is not None
                    and minutes_widget is not None
                    and seconds_widget is not None
                ):
                    self._apply_audio_duration_to_widgets(
                        path,
                        hours_widget=hours_widget,
                        minutes_widget=minutes_widget,
                        seconds_widget=seconds_widget,
                    )

    def _replace_additional_artists_for_track(self, track_id: int, names):
        self.track_service.replace_additional_artists(track_id, names, cursor=self.cursor)

    # =============================================================================
    # ISRC duplicate check across formats (uses new compact column)
    # =============================================================================
    def is_isrc_taken_normalized(self, candidate: str, exclude_track_id: int | None = None) -> bool:
        return self.track_service.is_isrc_taken_normalized(
            candidate,
            exclude_track_id=exclude_track_id,
            cursor=self.cursor,
        )

    @staticmethod
    def _normalize_track_number_value(value) -> int | None:
        try:
            normalized = int(value)
        except (TypeError, ValueError):
            return None
        return normalized if normalized > 0 else None

    def _warn_duplicate_track_numbers(
        self,
        *,
        album_title: str | None,
        planned_rows: list[tuple[int | None, str | None]],
        exclude_track_ids=None,
        parent_widget: QWidget | None = None,
        title: str = "Duplicate Track Numbers",
        track_service: TrackService | None = None,
        cursor: sqlite3.Cursor | None = None,
    ) -> None:
        active_track_service = track_service or self.track_service
        clean_album_title = str(album_title or "").strip()
        if (
            active_track_service is None
            or is_blank(clean_album_title)
            or clean_album_title.casefold() == "single"
        ):
            return

        normalized_rows: list[tuple[int, str]] = []
        for index, (track_number, track_title) in enumerate(planned_rows, start=1):
            normalized_track_number = self._normalize_track_number_value(track_number)
            if normalized_track_number is None:
                continue
            clean_title = str(track_title or "").strip() or f"Track {index}"
            normalized_rows.append((normalized_track_number, clean_title))
        if not normalized_rows:
            return

        batch_duplicates: dict[int, list[str]] = {}
        for track_number, track_title in normalized_rows:
            batch_duplicates.setdefault(track_number, []).append(track_title)
        batch_duplicates = {
            track_number: titles
            for track_number, titles in batch_duplicates.items()
            if len(titles) > 1
        }

        existing_conflicts: dict[int, list[tuple[int, str]]] = {}
        for track_number, _track_title in normalized_rows:
            if track_number in existing_conflicts:
                continue
            conflicts = active_track_service.list_album_track_number_conflicts(
                clean_album_title,
                track_number,
                exclude_track_ids=exclude_track_ids,
                cursor=cursor,
            )
            if conflicts:
                existing_conflicts[track_number] = conflicts

        if not batch_duplicates and not existing_conflicts:
            return

        lines = [
            f"Album '{clean_album_title}' has duplicate stored track numbers.",
            "Saving is still allowed so you can keep adjusting the order freely.",
        ]
        if batch_duplicates:
            lines.append("")
            lines.append("This save contains duplicates:")
            for track_number, titles in sorted(batch_duplicates.items()):
                lines.append(f"- Track {track_number}: {', '.join(titles)}")
        if existing_conflicts:
            lines.append("")
            lines.append("Existing tracks on this album already use these numbers:")
            for track_number, conflicts in sorted(existing_conflicts.items()):
                labels = [
                    f'#{int(track_id)} "{track_title}"'
                    if str(track_title or "").strip()
                    else f"#{int(track_id)}"
                    for track_id, track_title in conflicts
                ]
                extra = ""
                if len(labels) > 4:
                    extra = f", and {len(labels) - 4} more"
                lines.append(f"- Track {track_number}: {', '.join(labels[:4])}{extra}")

        QMessageBox.warning(parent_widget or self, title, "\n".join(lines))

    # =============================================================================
    # Save / Edit / Delete
    # =============================================================================
    def save(self):
        work_track_context = self._current_work_track_context()
        if is_blank(self.track_title_field.text()) or is_blank(self.artist_field.currentText()):
            QMessageBox.warning(self, "Missing data", "Track Title and Artist are required.")
            return
        if (
            str(work_track_context.get("mode") or "create_new_work") == "link_existing_work"
            and work_track_context.get("work_id") is None
        ):
            QMessageBox.warning(
                self,
                "Missing Work",
                "Choose the existing Work that should govern this track, or switch the governance mode to create a new Work from the track.",
            )
            return
        if not valid_upc_ean(self.upc_field.currentText()):
            QMessageBox.warning(
                self, "Invalid UPC/EAN", "UPC/EAN must be 12 or 13 digits (or leave empty)."
            )
            return
        try:
            # ISWC (optional)
            raw_iswc = (self.iswc_field.text() or "").strip()
            iso_iswc = None
            if raw_iswc:
                iso_iswc = to_iso_iswc(raw_iswc)
                if not iso_iswc or not is_valid_iswc_any(iso_iswc):
                    QMessageBox.warning(
                        self,
                        "Invalid ISWC",
                        "ISWC must be like T-123.456.789-0 or T1234567890 (checksum 0–9 or X), or leave empty.",
                    )
                    return

            generated_iso = ""
            comp = ""
            if self._isrc_generation_state()[0] == "ready":
                generated_iso = self.generate_isrc()
                if not generated_iso:
                    QMessageBox.critical(
                        self,
                        "ISRC Error",
                        "No free ISRC sequence is currently available for the active year and artist code.",
                    )
                    return
                comp = to_compact_isrc(generated_iso)
                if not comp or not is_valid_isrc_compact_or_iso(generated_iso):
                    QMessageBox.critical(
                        self,
                        "ISRC Error",
                        "Generated ISRC is invalid. Check prefix and artist-code settings.",
                    )
                    return

                if self.is_isrc_taken_normalized(generated_iso):
                    QMessageBox.critical(
                        self, "ISRC Error", "A track with this ISRC already exists."
                    )
                    return

            release_date_sql = self.release_date_field.selectedDate().toString("yyyy-MM-dd")

            track_seconds = hms_to_seconds(
                self.track_len_h.value(), self.track_len_m.value(), self.track_len_s.value()
            )
            self._log_trace(
                "track.create.prepare",
                message="Preparing track insert",
                isrc=generated_iso,
                isrc_compact=comp,
                track_title=self.track_title_field.text().strip(),
            )
            selected_artist_name, selected_artist_party_id = self._resolve_artist_party_choice(
                self.artist_field
            )
            resolved_artist_name, _artist_party_id = self._resolve_party_backed_artist_name(
                selected_artist_name or self.artist_field.currentText(),
                selected_party_id=selected_artist_party_id,
                cursor=self.cursor,
            )
            resolved_additional_artists = self._resolve_party_backed_additional_artist_names(
                self._parse_additional_artists(self.additional_artist_field.currentText()),
                cursor=self.cursor,
            )
            self.artist_field.setCurrentText(resolved_artist_name)
            self.additional_artist_field.setCurrentText(", ".join(resolved_additional_artists))
            governance_mode = str(work_track_context.get("mode") or "create_new_work")
            payload = TrackCreatePayload(
                isrc=generated_iso,
                track_title=self.track_title_field.text().strip(),
                artist_name=resolved_artist_name,
                additional_artists=resolved_additional_artists,
                album_title=self.album_title_field.currentText().strip() or None,
                release_date=release_date_sql,
                track_length_sec=track_seconds,
                iswc=(iso_iswc or None),
                upc=(self.upc_field.currentText().strip() or None),
                genre=(self.genre_field.currentText().strip() or None),
                track_number=self.track_number_field.value(),
                catalog_number=(
                    self.catalog_number_field.identifier_value()
                    if hasattr(self.catalog_number_field, "identifier_value")
                    else (self.catalog_number_field.currentText().strip() or None)
                ),
                catalog_number_mode=(
                    self.catalog_number_field.identifier_mode()
                    if hasattr(self.catalog_number_field, "identifier_mode")
                    else None
                ),
                catalog_registry_entry_id=(
                    self.catalog_number_field.catalog_registry_entry_id()
                    if hasattr(self.catalog_number_field, "catalog_registry_entry_id")
                    else None
                ),
                catalog_external_code_identifier_id=(
                    self.catalog_number_field.external_code_identifier_id()
                    if hasattr(self.catalog_number_field, "external_code_identifier_id")
                    else None
                ),
                external_catalog_identifier_id=(
                    self.catalog_number_field.external_catalog_identifier_id()
                    if hasattr(self.catalog_number_field, "external_catalog_identifier_id")
                    else None
                ),
                buma_work_number=(self.buma_work_number_field.text().strip() or None),
                audio_file_source_path=(self.audio_file_field.text().strip() or None),
                album_art_source_path=(self.album_art_field.text().strip() or None),
            )
            if governance_mode == "link_existing_work":
                payload.work_id = int(work_track_context["work_id"])
                payload.parent_track_id = (
                    int(work_track_context["parent_track_id"])
                    if work_track_context.get("parent_track_id") is not None
                    else None
                )
                payload.relationship_type = str(
                    work_track_context.get("relationship_type") or "original"
                )
            else:
                payload.work_id = None
                payload.parent_track_id = None
                payload.relationship_type = "original"
            self._warn_duplicate_track_numbers(
                album_title=payload.album_title,
                planned_rows=[(payload.track_number, payload.track_title)],
                parent_widget=self,
                title="Duplicate Track Number",
                track_service=self.track_service,
                cursor=self.cursor,
            )
            if payload.audio_file_source_path and not self._confirm_lossy_primary_audio_selection(
                [payload.audio_file_source_path],
                title="Save Track Media",
                action_label="Saving this track",
            ):
                return
            media_modes = self._choose_track_media_storage_modes(
                audio_source_path=payload.audio_file_source_path,
                album_art_source_path=payload.album_art_source_path,
                title="Save Track Media",
            )
            if media_modes is None:
                return
            payload.audio_file_storage_mode, payload.album_art_storage_mode = media_modes

            refresh_request = self._capture_catalog_refresh_request()
            action_label = (
                f"Create Work + Track: {payload.track_title}"
                if governance_mode == "create_new_work"
                else f"Create Track: {payload.track_title}"
            )
            action_type = (
                "track.create_governed"
                if governance_mode == "create_new_work"
                else "track.create"
            )
            profile_name = self._current_profile_name()

            def _worker(bundle, ctx):
                ctx.report_progress(
                    value=0,
                    maximum=100,
                    message="Saving track, media, and work governance...",
                )
                governed_service = GovernedImportCoordinator(
                    bundle.conn,
                    track_service=bundle.track_service,
                    party_service=bundle.party_service,
                    work_service=bundle.work_service,
                    profile_name=profile_name,
                )

                def _mutation():
                    cur = bundle.conn.cursor()
                    result = governed_service.create_governed_track(
                        payload,
                        cursor=cur,
                        governance_mode=governance_mode,
                        profile_name=profile_name,
                    )
                    created_track_id = int(result.track_id)
                    ctx.report_progress(
                        value=34,
                        maximum=100,
                        message="Synchronizing release records for the saved track...",
                    )
                    release_ids = self._sync_releases_for_tracks(
                        [created_track_id],
                        cursor=cur,
                        track_service=bundle.track_service,
                        release_service=bundle.release_service,
                        profile_name=profile_name,
                    )
                    return {
                        "work_id": int(result.work_id),
                        "track_id": created_track_id,
                        "release_ids": list(release_ids),
                    }

                result_payload = run_snapshot_history_action(
                    history_manager=bundle.history_manager,
                    action_label=action_label,
                    action_type=action_type,
                    entity_type="Track",
                    entity_id=payload.track_title,
                    payload={
                        "track_title": payload.track_title,
                        "artist_name": payload.artist_name,
                        "album_title": payload.album_title,
                        "created_work_from_track": governance_mode == "create_new_work",
                    },
                    mutation=_mutation,
                    progress_callback=ctx.report_progress,
                    post_mutation_progress=(48, "Capturing track-save history snapshot..."),
                    record_progress=(56, "Recording track-save history..."),
                    logger=self.logger,
                )
                ctx.report_progress(
                    value=60,
                    maximum=100,
                    message="Loading refreshed catalog rows, media badges, and lookup values...",
                )
                result_payload["dataset"] = self._load_catalog_ui_dataset_from_bundle(
                    bundle,
                    ctx,
                    progress_start=62,
                    progress_end=88,
                )
                return result_payload

            def _before_cleanup(result_payload: dict[str, object], ui_progress) -> None:
                try:
                    self.conn.commit()
                except Exception:
                    pass
                refresh_payload = dict(refresh_request)
                refresh_payload["focus_id"] = int(result_payload["track_id"])
                self._apply_catalog_refresh_request(
                    dict(result_payload.get("dataset") or {}),
                    refresh_payload,
                    progress_callback=self._scaled_ui_progress_callback(
                        ui_progress,
                        start=90,
                        end=97,
                    ),
                )
                self._advance_task_ui_progress(
                    ui_progress,
                    value=98,
                    message="Refreshing work manager and draft controls...",
                )
                self.clear_form_fields()
                if governance_mode == "create_new_work":
                    self._set_pending_work_track_context()
                self._refresh_work_track_creation_context_ui()
                self._refresh_work_manager_panel()
                if governance_mode == "create_new_work":
                    self._focus_work_in_manager(int(result_payload["work_id"]))
                self._advance_task_ui_progress(
                    ui_progress,
                    value=100,
                    message="Track saved and catalog UI is ready.",
                )

            def _after_cleanup(result_payload: dict[str, object]) -> None:
                work_id_for_refresh = int(result_payload["work_id"])
                track_id = int(result_payload["track_id"])
                release_ids = list(result_payload.get("release_ids") or [])
                if governance_mode == "create_new_work":
                    self._audit(
                        "CREATE",
                        "Work",
                        ref_id=work_id_for_refresh,
                        details=f"title={payload.track_title}",
                    )
                self._log_event(
                    "track.create",
                    "Track created",
                    track_id=track_id,
                    isrc=generated_iso,
                    track_title=payload.track_title,
                    release_ids=release_ids,
                )
                self._audit("CREATE", "Track", ref_id=track_id, details=f"isrc={generated_iso}")
                self._audit_commit()
                QMessageBox.information(self, "Success", "Track info saved successfully!")

            self._submit_background_bundle_task(
                title="Save Track",
                description="Saving track, media, and work governance...",
                task_fn=_worker,
                kind="write",
                unique_key=f"track.create.{payload.track_title.strip().casefold()}",
                owner=self,
                worker_completion_progress=(89, "Finalizing background track save..."),
                on_success_before_cleanup=_before_cleanup,
                on_success_after_cleanup=_after_cleanup,
                on_error=lambda failure: self._show_background_task_error(
                    "Save Track",
                    failure,
                    user_message="Failed to save record:",
                ),
            )
        except sqlite3.IntegrityError as e:
            self.conn.rollback()
            self.logger.exception(f"Save failed (integrity): {e}")
            QMessageBox.critical(self, "Save Error", f"Database constraint error:\n{e}")
        except Exception as e:
            self.conn.rollback()
            self.logger.exception(f"Save failed: {e}")
            QMessageBox.critical(self, "Save Error", f"Failed to save record:\n{e}")

    def open_add_album_dialog(
        self,
        *,
        work_id: int | None = None,
        lock_work: bool = False,
        relationship_type: str | None = None,
        inherit_work_context: bool = True,
    ):
        current_context = self._current_work_track_context() if inherit_work_context else None
        effective_work_id = (
            int(work_id)
            if work_id is not None
            else (
                int(current_context["work_id"])
                if current_context is not None and current_context.get("work_id") is not None
                else None
            )
        )
        effective_relationship_type = (
            relationship_type
            if relationship_type is not None
            else (
                str(current_context.get("relationship_type") or "original")
                if current_context is not None
                else None
            )
        )
        dlg = AlbumEntryDialog(
            self,
            work_id=effective_work_id,
            lock_work=bool(lock_work and effective_work_id is not None),
            relationship_type=effective_relationship_type,
        )
        dlg.exec()

    def open_add_album_dialog_for_work(self, work_id: int) -> None:
        self.open_add_album_dialog(
            work_id=int(work_id),
            lock_work=True,
            relationship_type="original",
            inherit_work_context=False,
        )

    def open_track_editor(
        self,
        track_id: int,
        *,
        batch_track_ids: list[int] | None = None,
        initial_focus_target: str | None = None,
    ):
        try:
            dlg = EditDialog(
                int(track_id),
                self,
                batch_track_ids=batch_track_ids,
                initial_focus_target=initial_focus_target,
            )
        except ValueError as exc:
            QMessageBox.warning(self, "Edit Track", str(exc))
            return
        dlg.exec()
        self.populate_all_comboboxes()

    def open_selected_editor(
        self,
        track_id: int | None = None,
        *,
        initial_focus_target: str | None = None,
    ):
        if isinstance(track_id, bool):
            track_id = None
        if track_id is None:
            selected_ids = list(self._catalog_table_controller().selected_track_ids())
            if not selected_ids:
                QMessageBox.warning(
                    self,
                    "Edit Track",
                    "Could not determine the selected track. Select one or more catalog rows and try again.",
                )
                return
            track_id = selected_ids[0]
            batch_ids = selected_ids
        else:
            try:
                track_id = int(track_id)
            except (TypeError, ValueError):
                track_id = 0
            if track_id <= 0:
                QMessageBox.warning(
                    self,
                    "Edit Track",
                    "Could not determine the selected track. Select one or more catalog rows and try again.",
                )
                return
            batch_ids = list(self._catalog_table_controller().selected_track_ids())
            if track_id not in batch_ids:
                batch_ids = [track_id]
        self.open_track_editor(
            int(track_id),
            batch_track_ids=batch_ids,
            initial_focus_target=initial_focus_target,
        )

    def _current_catalog_context_track_id(self) -> int | None:
        controller = self._catalog_table_controller()
        track_id = controller.current_track_id()
        if track_id is not None:
            return int(track_id)
        selected_ids = list(controller.selected_track_ids())
        if selected_ids:
            return int(selected_ids[0])
        return None

    def open_album_track_ordering_dialog(self, track_id: int | None = None) -> None:
        if self.track_service is None or self.conn is None:
            QMessageBox.warning(self, "Album Track Ordering", "Open a profile first.")
            return
        if isinstance(track_id, bool):
            track_id = None
        if track_id is None:
            track_id = self._current_catalog_context_track_id()
        try:
            resolved_track_id = int(track_id or 0)
        except (TypeError, ValueError):
            resolved_track_id = 0
        if resolved_track_id <= 0:
            QMessageBox.information(
                self,
                "Album Track Ordering",
                "Select a catalog row that belongs to an album first.",
            )
            return

        try:
            album_snapshots = self.track_service.list_album_group_snapshots(
                resolved_track_id,
                include_media_blobs=False,
            )
        except Exception as exc:
            QMessageBox.warning(self, "Album Track Ordering", str(exc))
            return

        if not album_snapshots:
            QMessageBox.information(
                self,
                "Album Track Ordering",
                "The selected track is not part of a saved album group.",
            )
            return

        album_title = str(album_snapshots[0].album_title or "").strip() or "Unnamed Album"
        dialog = AlbumTrackOrderingDialog(
            self,
            album_title=album_title,
            snapshots=album_snapshots,
            parent=self,
        )
        if dialog.exec() != QDialog.Accepted:
            return

        ordered_track_ids = dialog.ordered_track_ids()
        current_order = [int(snapshot.track_id) for snapshot in album_snapshots]
        order_already_sequential = all(
            self._normalize_track_number_value(snapshot.track_number) == index
            for index, snapshot in enumerate(album_snapshots, start=1)
        )
        if not ordered_track_ids or (
            ordered_track_ids == current_order and order_already_sequential
        ):
            if self.statusBar() is not None:
                self.statusBar().showMessage("Album track order unchanged.", 4000)
            return

        profile_name = self._current_profile_name()
        refresh_request = self._capture_catalog_refresh_request(focus_id=resolved_track_id)

        def _worker(bundle, ctx):
            total_tracks = max(1, len(ordered_track_ids))
            reorder_progress = self._scaled_progress_callback(
                ctx.report_progress,
                start=4,
                end=44,
            )
            ctx.report_progress(
                value=0,
                maximum=100,
                message="Preparing album track ordering update...",
            )

            def _mutation():
                with bundle.conn:
                    cur = bundle.conn.cursor()
                    for index, ordered_track_id in enumerate(ordered_track_ids, start=1):
                        reorder_progress(
                            index - 1,
                            total_tracks,
                            f"Saving reordered track {index} of {total_tracks}...",
                        )
                        snapshot = bundle.track_service.fetch_track_snapshot(
                            int(ordered_track_id),
                            cursor=cur,
                            include_media_blobs=False,
                        )
                        if snapshot is None:
                            raise ValueError(f"Track {int(ordered_track_id)} could not be loaded.")
                        payload = TrackUpdatePayload(
                            track_id=int(snapshot.track_id),
                            isrc=snapshot.isrc,
                            track_title=snapshot.track_title,
                            artist_name=snapshot.artist_name,
                            additional_artists=list(snapshot.additional_artists),
                            album_title=snapshot.album_title,
                            release_date=snapshot.release_date,
                            track_length_sec=int(snapshot.track_length_sec or 0),
                            iswc=snapshot.iswc,
                            upc=snapshot.upc,
                            genre=snapshot.genre,
                            track_number=index,
                            catalog_number=snapshot.catalog_number,
                            catalog_number_mode=snapshot.catalog_number_mode,
                            catalog_registry_entry_id=snapshot.catalog_registry_entry_id,
                            catalog_external_code_identifier_id=(
                                snapshot.catalog_external_code_identifier_id
                            ),
                            external_catalog_identifier_id=snapshot.external_catalog_identifier_id,
                            buma_work_number=snapshot.buma_work_number,
                            composer=snapshot.composer,
                            publisher=snapshot.publisher,
                            comments=snapshot.comments,
                            lyrics=snapshot.lyrics,
                            work_id=snapshot.work_id,
                            parent_track_id=snapshot.parent_track_id,
                            relationship_type=snapshot.relationship_type,
                            audio_file_source_path=None,
                            album_art_source_path=None,
                            clear_audio_file=False,
                            clear_album_art=False,
                        )
                        bundle.track_service.update_track(payload, cursor=cur)
                        reorder_progress(
                            index,
                            total_tracks,
                            f"Saved reordered track {index} of {total_tracks}.",
                        )
                    ctx.report_progress(
                        value=48,
                        maximum=100,
                        message="Synchronizing release records for the reordered album...",
                    )
                    release_ids = self._sync_releases_for_tracks(
                        ordered_track_ids,
                        cursor=cur,
                        track_service=bundle.track_service,
                        release_service=bundle.release_service,
                        profile_name=profile_name,
                    )
                    return {
                        "release_ids": list(release_ids),
                        "track_ids": list(ordered_track_ids),
                    }

            result_payload = run_snapshot_history_action(
                history_manager=bundle.history_manager,
                action_label=f"Album Track Ordering: {album_title}",
                action_type="track.album_order.update",
                entity_type="Album",
                entity_id=album_title,
                payload={
                    "album_title": album_title,
                    "track_ids": list(ordered_track_ids),
                },
                mutation=_mutation,
                progress_callback=ctx.report_progress,
                post_mutation_progress=(56, "Capturing album-order history snapshot..."),
                record_progress=(64, "Recording album-order history..."),
                logger=self.logger,
            )
            ctx.report_progress(
                value=68,
                maximum=100,
                message="Loading refreshed catalog rows, media badges, and lookup values...",
            )
            result_payload["dataset"] = self._load_catalog_ui_dataset_from_bundle(
                bundle,
                ctx,
                progress_start=70,
                progress_end=92,
            )
            return result_payload

        def _before_cleanup(result_payload: dict[str, object], ui_progress) -> None:
            try:
                self.conn.commit()
            except Exception:
                pass
            self._apply_catalog_refresh_request(
                dict(result_payload.get("dataset") or {}),
                refresh_request,
                progress_callback=self._scaled_ui_progress_callback(
                    ui_progress,
                    start=95,
                    end=99,
                ),
            )
            self._advance_task_ui_progress(
                ui_progress,
                value=100,
                message="Album track ordering saved and catalog UI is ready.",
            )

        def _after_cleanup(result_payload: dict[str, object]) -> None:
            release_ids = list(result_payload.get("release_ids") or [])
            self.populate_all_comboboxes()
            self._refresh_catalog_workspace_docks()
            self._log_event(
                "track.album_order.update",
                "Updated album track ordering",
                album_title=album_title,
                track_ids=list(ordered_track_ids),
                release_ids=release_ids,
            )
            if self.statusBar() is not None:
                self.statusBar().showMessage(
                    f'Updated album track ordering for "{album_title}".',
                    5000,
                )

        self._submit_background_bundle_task(
            title="Album Track Ordering",
            description="Saving album track ordering...",
            task_fn=_worker,
            kind="write",
            unique_key=f"track.album_order.update.{album_title.strip().casefold()}",
            owner=self,
            worker_completion_progress=(94, "Finalizing background album order update..."),
            on_success_before_cleanup=_before_cleanup,
            on_success_after_cleanup=_after_cleanup,
            on_error=lambda failure: self._show_background_task_error(
                "Album Track Ordering",
                failure,
                user_message="Could not save the album track order:",
            ),
        )

    def edit_entry(self, item):
        row_idx = item.row()
        column_idx = item.column() if hasattr(item, "column") else 0
        model = self.table.model()
        controller = self._catalog_table_controller()
        index = model.index(int(row_idx), int(column_idx)) if model is not None else None
        track_id = controller.track_id_for_index(index) if index is not None else None
        cell_target = controller.cell_target(
            index,
            base_column_count=len(self.BASE_HEADERS),
            custom_fields=self.active_custom_fields,
        )
        if track_id is None:
            QMessageBox.warning(self, "Edit Track", "Could not determine the selected track.")
            return
        self.open_selected_editor(
            track_id,
            initial_focus_target=self._catalog_editor_focus_target(cell_target),
        )

