    def _start_conversion_export(self, preview, output_path: str | Path) -> None:
        format_name = (
            str(preview.template_profile.format_name or "").strip().lower() or "conversion"
        )
        default_name = Path(str(output_path or "")).name or (
            f"conversion_output{preview.template_profile.output_suffix or f'.{format_name}'}"
        )
        try:
            resolved_path = self._resolve_file_export_target(
                output_path,
                default_filename=default_name,
            )
        except ValueError as exc:
            QMessageBox.warning(self, "Template Conversion", str(exc))
            return
        expected_suffix = str(preview.template_profile.output_suffix or "").strip()
        if expected_suffix and resolved_path.suffix.lower() != expected_suffix.lower():
            resolved_path = resolved_path.with_suffix(expected_suffix)
        if (
            preview.template_profile.template_bytes is None
            and resolved_path.resolve() == preview.template_profile.template_path.resolve()
        ):
            QMessageBox.warning(
                self,
                "Template Conversion",
                "Choose a new output file. Conversion export never overwrites the source template.",
            )
            return

        use_history = (
            self.history_manager is not None
            and str(getattr(self, "current_db_path", "") or "").strip()
            and self.background_service_factory is not None
        )

        def _worker(bundle, ctx):
            export_progress = self._scaled_progress_callback(ctx.report_progress, start=0, end=92)

            def _mutation():
                return bundle.conversion_service.export_preview(
                    preview,
                    resolved_path,
                    progress_callback=export_progress,
                )

            return run_file_history_action(
                history_manager=bundle.history_manager,
                action_label=lambda result: (
                    f"Export Conversion {result.target_format.upper()}: {result.exported_row_count} rows"
                ),
                action_type="file.conversion_export",
                target_path=resolved_path,
                mutation=_mutation,
                entity_type="ConversionExport",
                entity_id=str(resolved_path),
                payload=lambda result: {
                    "path": str(resolved_path),
                    "format": result.target_format,
                    "row_count": result.exported_row_count,
                    "template_path": str(preview.template_profile.template_path),
                    "source_mode": preview.source_profile.source_mode,
                },
                progress_callback=ctx.report_progress,
                post_mutation_progress=(95, "Capturing conversion export history..."),
                record_progress=(97, "Recording conversion export history..."),
                logger=self.logger,
            )

        def _direct_worker(ctx):
            export_progress = self._scaled_progress_callback(ctx.report_progress, start=0, end=96)
            return self.conversion_service.export_preview(
                preview,
                resolved_path,
                progress_callback=export_progress,
            )

        def _success(result) -> None:
            if self.history_manager is not None:
                self._refresh_history_actions()
            self._log_event(
                "conversion.export",
                "Exported template conversion output",
                path=str(resolved_path),
                format=result.target_format,
                exported_rows=result.exported_row_count,
                template_path=str(preview.template_profile.template_path),
                source_mode=preview.source_profile.source_mode,
            )
            if self.conn is not None:
                self._audit(
                    "EXPORT",
                    "ConversionExport",
                    ref_id=str(resolved_path),
                    details=(
                        f"format={result.target_format}; rows={result.exported_row_count}; "
                        f"template={preview.template_profile.template_path.name}"
                    ),
                )
                self._audit_commit()
            message_lines = [
                f"Converted output written to:\n{resolved_path}",
                "",
                f"Format: {result.target_format.upper()}",
                f"Rows written: {result.exported_row_count}",
            ]
            if result.summary_lines:
                message_lines.extend(["", *result.summary_lines])
            QMessageBox.information(self, "Template Conversion", "\n".join(message_lines))

        submit_kwargs = {
            "title": f"Export Conversion {format_name.upper()}",
            "description": "Rendering the converted output from the compiled template preview...",
            "kind": "read",
            "unique_key": f"conversion.export.{format_name}",
            "worker_completion_progress": (100, "Conversion export complete."),
            "on_success_after_cleanup": _success,
            "on_error": lambda failure: self._show_background_task_error(
                "Template Conversion",
                failure,
                user_message="Could not export the converted output:",
            ),
        }
        if use_history:
            self._submit_background_bundle_task(
                task_fn=_worker,
                **submit_kwargs,
            )
        else:
            self._submit_background_task(
                task_fn=_direct_worker,
                requires_profile=False,
                **submit_kwargs,
            )

    def _current_profile_name(self) -> str | None:
        path = str(getattr(self, "current_db_path", "") or "").strip()
        return Path(path).name if path else None

    @staticmethod
    def _normalize_track_ids(track_ids) -> list[int]:
        normalized: list[int] = []
        seen: set[int] = set()
        for value in track_ids or []:
            try:
                track_id = int(value)
            except (TypeError, ValueError):
                continue
            if track_id <= 0 or track_id in seen:
                continue
            seen.add(track_id)
            normalized.append(track_id)
        return normalized

    @staticmethod
    def _first_non_blank(*values):
        for value in values:
            if isinstance(value, str):
                text = value.strip()
                if text:
                    return text
            elif value not in (None, "", [], {}, ()):
                return value
        return None

    def _bulk_audio_attach_scope_track_ids(
        self, track_ids: list[int] | None = None
    ) -> tuple[list[int], str]:
        explicit_ids = self._normalize_track_ids(track_ids)
        if explicit_ids:
            return explicit_ids, "selected tracks"
        selected_ids = self._normalize_track_ids(
            self._catalog_table_controller().selected_track_ids()
        )
        if selected_ids:
            return selected_ids, "current selection"
        visible_ids = list(self._catalog_table_controller().visible_track_ids())
        if visible_ids:
            return visible_ids, "visible catalog rows"
        all_ids = [choice.track_id for choice in self._all_catalog_track_choices()]
        return self._normalize_track_ids(all_ids), "entire catalog"

    def _catalog_track_choices(self) -> list[TrackChoice]:
        controller = self._catalog_table_controller()
        model = controller.active_model()
        if model is None:
            return []
        title_column = controller.column_for_key("base:track_title")
        artist_column = controller.column_for_key("base:artist_name")
        album_column = controller.column_for_key("base:album_title")
        choices: list[TrackChoice] = []
        for row in range(model.rowCount()):
            row_index = model.index(row, 0)
            track_id = controller.track_id_for_index(row_index)
            if track_id is None:
                continue
            title = ""
            if title_column is not None:
                title = str(model.data(model.index(row, title_column), Qt.DisplayRole) or "").strip()
            if not title:
                title = self._get_track_title(track_id)
            artist = (
                str(model.data(model.index(row, artist_column), Qt.DisplayRole) or "").strip()
                if artist_column is not None
                else ""
            )
            album = (
                str(model.data(model.index(row, album_column), Qt.DisplayRole) or "").strip()
                if album_column is not None
                else ""
            )
            subtitle = " / ".join(
                part
                for part in (artist, album)
                if part
            )
            choices.append(TrackChoice(track_id=int(track_id), title=title, subtitle=subtitle))
        return choices

    def _all_catalog_track_choices(
        self, *, conn: sqlite3.Connection | None = None
    ) -> list[TrackChoice]:
        active_conn = conn or self.conn
        if active_conn is None:
            return []
        main_artist_join_sql, main_artist_name_expr = track_main_artist_join_sql(
            active_conn,
            track_alias="t",
            artist_alias="main_artist",
        )
        rows = active_conn.execute(
            f"""
            SELECT
                t.id,
                COALESCE(t.track_title, ''),
                COALESCE({main_artist_name_expr}, ''),
                COALESCE(al.title, '')
            FROM Tracks t
            {main_artist_join_sql}
            LEFT JOIN Albums al ON al.id = t.album_id
            ORDER BY t.track_title COLLATE NOCASE, t.id
            """
        ).fetchall()
        choices: list[TrackChoice] = []
        for track_id, track_title, artist_name, album_title in rows:
            clean_title = str(track_title or "").strip() or f"Track {int(track_id)}"
            subtitle = " / ".join(
                part
                for part in (
                    str(artist_name or "").strip(),
                    str(album_title or "").strip(),
                )
                if part
            )
            choices.append(
                TrackChoice(track_id=int(track_id), title=clean_title, subtitle=subtitle)
            )
        return choices

    def _on_party_authority_changed(self) -> None:
        if self.conn is None:
            return
        artist_combo_states: list[tuple[QComboBox, bool, str, int | None]] = []
        for combo, allow_empty in (
            (getattr(self, "artist_field", None), False),
            (getattr(self, "additional_artist_field", None), True),
        ):
            if not isinstance(combo, QComboBox):
                continue
            current_text, selected_party_id = self._resolve_artist_party_choice(combo)
            artist_combo_states.append((combo, allow_empty, current_text, selected_party_id))
        try:
            self.populate_all_comboboxes()
        except Exception:
            pass
        for combo, allow_empty, current_text, selected_party_id in artist_combo_states:
            try:
                self._configure_artist_party_combo(
                    combo,
                    allow_empty=allow_empty,
                    selected_party_id=selected_party_id,
                    current_text=current_text,
                )
            except Exception:
                pass
        try:
            self.refresh_table_preserve_view()
        except Exception:
            pass
        try:
            self._refresh_work_manager_panel()
        except Exception:
            pass
        try:
            self._refresh_party_manager_panel()
        except Exception:
            pass
        try:
            if self.release_browser_dialog is not None and self.release_browser_dialog.isVisible():
                self.release_browser_dialog.refresh()
        except Exception:
            pass
        try:
            self._refresh_catalog_workspace_docks()
        except Exception:
            pass
        try:
            self._refresh_add_track_artist_party_choices()
        except Exception:
            pass

    @staticmethod
    def _track_choice_tuple(choice: TrackChoice) -> tuple[int, str, str | None]:
        subtitle = str(choice.subtitle or "").strip()
        artist_name = subtitle.split(" / ", 1)[0].strip() if subtitle else None
        label = f"{int(choice.track_id)} - {choice.title}"
        if subtitle:
            label = f"{label} / {subtitle}"
        return int(choice.track_id), label, artist_name or None

    def _catalog_track_choice_tuples(
        self,
        *,
        include_hidden: bool = False,
        conn: sqlite3.Connection | None = None,
    ) -> list[tuple[int, str, str | None]]:
        choices = (
            self._all_catalog_track_choices(conn=conn)
            if include_hidden
            else self._catalog_track_choices()
        )
        return [self._track_choice_tuple(choice) for choice in choices]

    def _media_attach_track_candidates(
        self,
        track_ids,
        *,
        track_service: TrackService | None = None,
    ) -> list[BulkAudioAttachTrackCandidate]:
        active_track_service = track_service or self.track_service
        if active_track_service is None:
            return []
        candidates: list[BulkAudioAttachTrackCandidate] = []
        for track_id in self._normalize_track_ids(track_ids):
            snapshot = active_track_service.fetch_track_snapshot(int(track_id))
            if snapshot is None:
                continue
            candidates.append(
                BulkAudioAttachTrackCandidate(
                    track_id=snapshot.track_id,
                    title=snapshot.track_title,
                    artist=snapshot.artist_name,
                    album=snapshot.album_title,
                    isrc=snapshot.isrc,
                )
            )
        return candidates

    def _album_art_attach_track_ids(
        self,
        track_ids,
        *,
        track_service: TrackService | None = None,
    ) -> list[int]:
        active_track_service = track_service or self.track_service
        if active_track_service is None:
            return []
        allowed: list[int] = []
        for track_id in self._normalize_track_ids(track_ids):
            try:
                state = active_track_service.describe_album_art_edit_state(int(track_id))
            except Exception:
                continue
            if bool(getattr(state, "can_replace_directly", False)):
                allowed.append(int(track_id))
        return allowed

    @staticmethod
    def _normalize_media_attach_match_text(value: str | None) -> str:
        return re.sub(r"[^a-z0-9]+", " ", str(value or "").casefold()).strip()

    @staticmethod
    def _is_supported_media_attach_path(path: str, media_key: str) -> bool:
        suffix = Path(str(path or "")).suffix.lower()
        guessed_mime = str(mimetypes.guess_type(str(path or ""))[0] or "").strip().lower()
        if media_key == "audio_file":
            return suffix in BLOB_AUDIO_EXTS or guessed_mime.startswith("audio/")
        return suffix in BLOB_IMAGE_EXTS or guessed_mime.startswith("image/")

    def _prepare_media_attach_paths(
        self,
        media_key: str,
        raw_paths,
        *,
        title: str,
        allow_multiple: bool,
        ignored_message: str | None = None,
    ) -> list[str]:
        normalized_paths: list[str] = []
        seen: set[str] = set()
        for raw_path in raw_paths or []:
            clean = str(raw_path or "").strip()
            if not clean:
                continue
            path = str(Path(clean))
            if path in seen:
                continue
            seen.add(path)
            normalized_paths.append(path)
        supported_paths = [
            path
            for path in normalized_paths
            if Path(path).exists() and self._is_supported_media_attach_path(path, media_key)
        ]
        ignored_paths = [path for path in normalized_paths if path not in supported_paths]
        if ignored_paths and ignored_message:
            QMessageBox.information(
                self,
                title,
                ignored_message
                + "\n\nIgnored:\n- "
                + "\n- ".join(Path(path).name for path in ignored_paths[:12]),
            )
        if not supported_paths:
            QMessageBox.information(
                self,
                title,
                "No supported files were selected.",
            )
            return []
        if not allow_multiple and len(supported_paths) > 1:
            QMessageBox.information(
                self,
                title,
                "Only a single image file can be attached at a time.",
            )
            return []
        return supported_paths

    def _open_add_track_with_media_source(
        self,
        media_key: str,
        source_path: str,
    ) -> None:
        self.open_add_track_entry()
        if media_key == "audio_file":
            self.audio_file_field.setText(str(source_path or ""))
            self._refresh_line_edit_lossy_audio_warning(self.audio_file_field)
            self._apply_audio_duration_to_widgets(
                source_path,
                hours_widget=self.track_len_h,
                minutes_widget=self.track_len_m,
                seconds_widget=self.track_len_s,
            )
        else:
            self.album_art_field.setText(str(source_path or ""))
        self.track_title_field.setFocus()

    def _build_album_art_attach_plan(
        self,
        *,
        file_paths: list[str],
        tracks: list[BulkAudioAttachTrackCandidate],
        progress_callback=None,
    ) -> tuple[list[dict[str, object]], list[str]]:
        items: list[dict[str, object]] = []
        warnings: list[str] = []
        total = len(file_paths)
        for index, raw_path in enumerate(file_paths, start=1):
            path = Path(raw_path)
            if progress_callback is not None:
                progress_callback(
                    index - 1,
                    total,
                    f"Matching artwork file {index} of {total}: {path.name}",
                )
            item, warning = self._build_album_art_attach_item(path, tracks)
            items.append(item)
            if warning:
                warnings.append(warning)
        if progress_callback is not None:
            progress_callback(total, total, "Album art matching finished.")
        return items, warnings

    def _build_album_art_attach_item(
        self,
        path: Path,
        tracks: list[BulkAudioAttachTrackCandidate],
    ) -> tuple[dict[str, object], str | None]:
        title_candidates, stem_artist = BulkAudioAttachService._filename_candidates(path.stem)
        normalized_stem_artist = self._normalize_media_attach_match_text(stem_artist)
        best_tracks: list[BulkAudioAttachTrackCandidate] = []
        best_score = 0
        best_basis = ""
        for track in tracks:
            normalized_track_title = self._normalize_media_attach_match_text(track.title)
            normalized_album_title = self._normalize_media_attach_match_text(track.album)
            normalized_track_artist = self._normalize_media_attach_match_text(track.artist)
            for candidate, basis_label in title_candidates:
                normalized_candidate = self._normalize_media_attach_match_text(candidate)
                if not normalized_candidate:
                    continue
                score = 0
                basis = ""
                if normalized_album_title and normalized_candidate == normalized_album_title:
                    score = 260
                    basis = f"{basis_label} album title"
                elif normalized_track_title and normalized_candidate == normalized_track_title:
                    score = 220
                    basis = f"{basis_label} track title"
                if (
                    score > 0
                    and normalized_stem_artist
                    and normalized_track_artist
                    and normalized_stem_artist == normalized_track_artist
                ):
                    score += 25
                    basis = f"{basis} + artist"
                if score > best_score:
                    best_tracks = [track]
                    best_score = score
                    best_basis = basis
                elif score > 0 and score == best_score:
                    best_tracks.append(track)
        detected_album = title_candidates[0][0] if title_candidates else None
        if len(best_tracks) > 1 and best_score > 0:
            return (
                {
                    "source_path": str(path),
                    "source_name": path.name,
                    "detected_title": None,
                    "detected_artist": stem_artist,
                    "detected_album": detected_album,
                    "matched_track_id": None,
                    "match_basis": "Ambiguous artwork filename match",
                    "status": "ambiguous",
                    "warning": "",
                    "candidate_track_ids": [int(track.track_id) for track in best_tracks],
                },
                None,
            )
        if not best_tracks:
            return (
                {
                    "source_path": str(path),
                    "source_name": path.name,
                    "detected_title": None,
                    "detected_artist": stem_artist,
                    "detected_album": detected_album,
                    "matched_track_id": None,
                    "match_basis": "No confident catalog match",
                    "status": "unmatched",
                    "warning": "",
                    "candidate_track_ids": [],
                },
                None,
            )
        best_track = best_tracks[0]
        return (
            {
                "source_path": str(path),
                "source_name": path.name,
                "detected_title": None,
                "detected_artist": stem_artist,
                "detected_album": detected_album,
                "matched_track_id": int(best_track.track_id),
                "matched_track_artist": best_track.artist,
                "match_basis": best_basis,
                "status": "matched",
                "warning": "",
                "candidate_track_ids": [],
            },
            None,
        )

    def _select_track_ids_in_table(self, track_ids, *, replace: bool = True) -> None:
        normalized_ids = set(self._normalize_track_ids(track_ids))
        selection_model = self.table.selectionModel()
        if selection_model is None:
            return
        if replace:
            self.table.clearSelection()
        controller = self._catalog_table_controller()
        current_index = None
        for track_id in normalized_ids:
            index = controller.view_index_for_track_id(track_id, column=0)
            if not index.isValid():
                continue
            selection_model.select(
                index,
                QItemSelectionModel.Select | QItemSelectionModel.Rows,
            )
            if current_index is None:
                current_index = index
        if current_index is not None:
            selection_model.setCurrentIndex(current_index, QItemSelectionModel.NoUpdate)

    def _refresh_workspace_selection_scopes(self) -> None:
        panels = [
            getattr(self, "release_browser_dialog", None),
            getattr(self, "work_browser_dialog", None),
        ]
        for panel in panels:
            refresh_scope = getattr(panel, "refresh_selection_scope", None)
            if callable(refresh_scope):
                refresh_scope()

    def _on_catalog_selection_changed(self) -> None:
        self._refresh_workspace_selection_scopes()

    def _set_explicit_track_filter(
        self, track_ids: list[int] | None, *, source_label: str | None = None
    ) -> None:
        normalized_ids = self._normalize_track_ids(track_ids)
        self._explicit_row_filter_track_ids = set(normalized_ids) if normalized_ids else None
        self._apply_catalog_search_filter()
        if source_label:
            count = len(normalized_ids)
            message = (
                f"Filtered catalog to {count} track{'s' if count != 1 else ''} from {source_label}."
                if normalized_ids
                else f"Cleared explicit filter from {source_label}."
            )
            if self.statusBar() is not None:
                self.statusBar().showMessage(message, 5000)

    def _replace_catalog_track_filter(
        self, track_ids: list[int] | None, *, source_label: str | None = None
    ) -> None:
        normalized_ids = self._normalize_track_ids(track_ids)
        self.search_field.blockSignals(True)
        self.search_field.clear()
        self.search_field.blockSignals(False)
        self.search_column_combo.blockSignals(True)
        all_columns_index = self.search_column_combo.findData(-1)
        self.search_column_combo.setCurrentIndex(
            all_columns_index if all_columns_index != -1 else 0
        )
        self.search_column_combo.blockSignals(False)
        self._explicit_row_filter_track_ids = set(normalized_ids) if normalized_ids else None
        self._apply_catalog_search_filter()
        if normalized_ids:
            self._select_track_ids_in_table(normalized_ids)
        elif self.table.model() is not None and self.table.model().rowCount() > 0:
            self.table.clearSelection()
        if source_label and self.statusBar() is not None:
            count = len(normalized_ids)
            message = (
                f"Filtered catalog to {count} track{'s' if count != 1 else ''} from {source_label}."
                if normalized_ids
                else f"Cleared explicit filter from {source_label}."
            )
            self.statusBar().showMessage(message, 5000)
        self._refresh_workspace_selection_scopes()

    def _release_choices(self) -> list[tuple[int, str]]:
        if self.release_service is None:
            return []
        choices: list[tuple[int, str]] = []
        for release in self.release_service.list_releases():
            label = release.title
            if release.primary_artist:
                label = f"{label} — {release.primary_artist}"
            choices.append((release.id, label))
        return choices

    def _release_context_for_track(
        self,
        track_id: int,
        *,
        release_service: ReleaseService | None = None,
    ) -> tuple[ReleaseRecord | None, ReleaseTrackPlacement | None]:
        active_release_service = release_service or self.release_service
        if active_release_service is None:
            return None, None
        release = active_release_service.find_primary_release_for_track(track_id)
        if release is None:
            return None, None
        summary = active_release_service.fetch_release_summary(release.id)
        if summary is None:
            return release, None
        for placement in summary.tracks:
            if placement.track_id == int(track_id):
                return summary.release, placement
        return summary.release, None

    def _effective_artwork_payload_for_track(
        self,
        track_id: int,
        *,
        snapshot: TrackSnapshot | None = None,
        track_service: TrackService | None = None,
        load_bytes: bool = True,
    ) -> ArtworkPayload | None:
        try:
            active_track_service = track_service or self.track_service
            if active_track_service is None:
                return None
            source_snapshot = snapshot or active_track_service.fetch_track_snapshot(track_id)
            if source_snapshot is None:
                return None
            has_album_art = bool(
                source_snapshot.album_art_path
                or source_snapshot.album_art_blob_b64
                or source_snapshot.album_art_filename
                or int(source_snapshot.album_art_size_bytes or 0) > 0
            )
            if not has_album_art:
                return None
            fallback_mime_type = (
                str(source_snapshot.album_art_mime_type or "").strip() or "image/jpeg"
            )
            if not load_bytes:
                return ArtworkPayload(data=b"", mime_type=fallback_mime_type)
            data, mime_type = active_track_service.fetch_media_bytes(track_id, "album_art")
            return ArtworkPayload(data=data, mime_type=mime_type or fallback_mime_type)
        except Exception:
            return None

    @staticmethod
    def _display_tag_value(value) -> str:
        if isinstance(value, ArtworkPayload):
            return f"<Artwork {value.mime_type or 'image'}>"
        if value is None:
            return ""
        if isinstance(value, bytes):
            return f"<{len(value)} bytes>"
        return str(value)

    def _catalog_tag_data_for_track(
        self,
        track_id: int,
        *,
        snapshot: TrackSnapshot | None = None,
        track_service: TrackService | None = None,
        release_service: ReleaseService | None = None,
        include_artwork_bytes: bool = True,
    ):
        active_track_service = track_service or self.track_service
        if active_track_service is None:
            raise ValueError("Track service is not available")
        return build_catalog_export_tag_data(
            track_id,
            track_service=active_track_service,
            release_service=release_service or self.release_service,
            include_artwork_bytes=include_artwork_bytes,
        )

    def _attempt_catalog_audio_export_metadata(
        self,
        destination_path: str | Path,
        *,
        track_id: int,
    ) -> str | None:
        if self.track_service is None or self.audio_tag_service is None:
            return "catalog metadata services were unavailable"
        _metadata_embedded, metadata_warning = write_catalog_export_tags(
            destination_path,
            track_id=track_id,
            track_service=self.track_service,
            release_service=self.release_service,
            tag_service=self.audio_tag_service,
            include_artwork_bytes=True,
        )
        return metadata_warning

    def _release_payload_for_track_ids(
        self,
        track_ids: list[int],
        *,
        existing_release: ReleaseRecord | None = None,
        existing_summary=None,
        artwork_source_path: str | None = None,
        clear_artwork: bool = False,
        track_service: TrackService | None = None,
        release_service: ReleaseService | None = None,
        profile_name: str | None = None,
    ) -> ReleasePayload:
        active_track_service = track_service or self.track_service
        if active_track_service is None:
            raise ValueError("Track service is not available.")
        normalized_ids = self._normalize_track_ids(track_ids)
        snapshots = [
            snapshot
            for track_id in normalized_ids
            if (snapshot := active_track_service.fetch_track_snapshot(track_id)) is not None
        ]
        if not snapshots:
            raise ValueError("No valid tracks were available to build release metadata.")

        title = self._first_non_blank(
            *[snapshot.album_title for snapshot in snapshots],
            existing_release.title if existing_release is not None else None,
            snapshots[0].track_title,
        )
        clean_title = str(title or "").strip()
        placements: list[ReleaseTrackPlacement] = []
        existing_placements = {
            placement.track_id: placement
            for placement in (
                (existing_summary.tracks if existing_summary is not None else []) or []
            )
        }
        ordered_snapshots = sorted(
            enumerate(snapshots, start=1),
            key=lambda item: (
                self._normalize_track_number_value(item[1].track_number) or int(item[0]),
                int(item[0]),
            ),
        )
        for sequence_number, (_original_position, snapshot) in enumerate(
            ordered_snapshots,
            start=1,
        ):
            existing = existing_placements.get(snapshot.track_id)
            placements.append(
                ReleaseTrackPlacement(
                    track_id=snapshot.track_id,
                    disc_number=int(existing.disc_number if existing is not None else 1),
                    track_number=int(
                        existing.track_number
                        if existing is not None
                        else (
                            self._normalize_track_number_value(snapshot.track_number)
                            or sequence_number
                        )
                    ),
                    sequence_number=sequence_number,
                )
            )

        derived_artwork_source = artwork_source_path
        if (
            not clear_artwork
            and not derived_artwork_source
            and (existing_release is None or not existing_release.artwork_path)
        ):
            for snapshot in snapshots:
                resolved = active_track_service.resolve_media_path(snapshot.album_art_path)
                if resolved is not None and resolved.exists():
                    derived_artwork_source = str(resolved)
                    break

        return ReleasePayload(
            title=clean_title or f"Release {snapshots[0].track_id}",
            version_subtitle=(
                existing_release.version_subtitle if existing_release is not None else None
            ),
            primary_artist=self._first_non_blank(
                existing_release.primary_artist if existing_release is not None else None,
                *[snapshot.artist_name for snapshot in snapshots],
            ),
            album_artist=self._first_non_blank(
                existing_release.album_artist if existing_release is not None else None,
                *[snapshot.artist_name for snapshot in snapshots],
            ),
            release_type=(
                existing_release.release_type
                if existing_release is not None and existing_release.release_type
                else ReleaseService.infer_release_type(
                    title=clean_title,
                    track_count=len(snapshots),
                )
            ),
            release_date=self._first_non_blank(
                existing_release.release_date if existing_release is not None else None,
                *[snapshot.release_date for snapshot in snapshots],
            ),
            original_release_date=(
                existing_release.original_release_date if existing_release is not None else None
            ),
            label=self._first_non_blank(
                existing_release.label if existing_release is not None else None,
                *[snapshot.publisher for snapshot in snapshots],
            ),
            sublabel=existing_release.sublabel if existing_release is not None else None,
            catalog_number=self._first_non_blank(
                existing_release.catalog_number if existing_release is not None else None,
                *[snapshot.catalog_number for snapshot in snapshots],
            ),
            upc=self._first_non_blank(
                existing_release.upc if existing_release is not None else None,
                *[snapshot.upc for snapshot in snapshots],
            ),
            territory=existing_release.territory if existing_release is not None else None,
            explicit_flag=existing_release.explicit_flag if existing_release is not None else False,
            repertoire_status=(
                existing_release.repertoire_status if existing_release is not None else None
            ),
            metadata_complete=(
                existing_release.metadata_complete if existing_release is not None else False
            ),
            contract_signed=(
                existing_release.contract_signed if existing_release is not None else False
            ),
            rights_verified=(
                existing_release.rights_verified if existing_release is not None else False
            ),
            notes=existing_release.notes if existing_release is not None else None,
            artwork_source_path=derived_artwork_source,
            clear_artwork=bool(clear_artwork),
            profile_name=profile_name or self._current_profile_name(),
            placements=placements,
        )

    def _sync_releases_for_tracks(
        self,
        track_ids,
        *,
        cursor: sqlite3.Cursor | None = None,
        track_service: TrackService | None = None,
        release_service: ReleaseService | None = None,
        profile_name: str | None = None,
    ) -> list[int]:
        active_track_service = track_service or self.track_service
        active_release_service = release_service or self.release_service
        if active_track_service is None or active_release_service is None:
            return []
        if cursor is None:
            with self.conn:
                cur = self.conn.cursor()
                return self._sync_releases_for_tracks(
                    track_ids,
                    cursor=cur,
                    track_service=active_track_service,
                    release_service=active_release_service,
                    profile_name=profile_name,
                )

        cur = cursor
        created_or_updated: list[int] = []
        processed_group_keys: set[tuple[int, ...]] = set()

        for track_id in self._normalize_track_ids(track_ids):
            group_track_ids = active_track_service.list_album_group_track_ids(track_id, cursor=cur)
            if not group_track_ids:
                group_track_ids = [track_id]
            group_key = tuple(self._normalize_track_ids(group_track_ids))
            if not group_key or group_key in processed_group_keys:
                continue
            processed_group_keys.add(group_key)

            existing_release = active_release_service.find_primary_release_for_track(track_id)
            existing_summary = (
                active_release_service.fetch_release_summary(existing_release.id)
                if existing_release is not None
                else None
            )
            existing_track_ids = {
                placement.track_id
                for placement in (existing_summary.tracks if existing_summary is not None else [])
            }
            if (
                existing_summary is not None
                and len(existing_track_ids) > 1
                and existing_track_ids != set(group_key)
            ):
                existing_release = None
                existing_summary = None

            payload = self._release_payload_for_track_ids(
                list(group_key),
                existing_release=existing_release,
                existing_summary=existing_summary,
                track_service=active_track_service,
                release_service=active_release_service,
                profile_name=profile_name,
            )
            if existing_release is None:
                release_id = active_release_service.create_release(payload, cursor=cur)
            else:
                release_id = active_release_service.update_release(
                    existing_release.id, payload, cursor=cur
                )
            created_or_updated.append(int(release_id))

        return self._normalize_track_ids(created_or_updated)

    def open_add_track_workspace(self):
        self._apply_add_data_panel_state(True)
        self._ensure_add_track_panel_initialized()
        self._show_add_track_details_tab()
        field = getattr(self, "track_title_field", None)
        if field is not None:
            try:
                field.setFocus()
            except Exception:
                pass
        return getattr(self, "add_data_dock", None)

    def _show_add_track_details_tab(self) -> None:
        tabs = getattr(self, "add_data_tabs", None)
        if tabs is None:
            return
        try:
            track_index = int(getattr(self, "add_data_track_tab_index", 1))
            if 0 <= track_index < tabs.count():
                tabs.setCurrentIndex(track_index)
        except Exception:
            pass

